# CRITICAL FIX #1: Import secure_filename with fallback
try:
    from werkzeug.utils import secure_filename
except ImportError:
    # Fallback sanitizer if werkzeug doesn't have secure_filename
    def secure_filename(filename):
        """Minimal filename sanitizer - replace non-alphanumeric with underscore"""
        if not filename:
            return "unnamed"
        # Keep extension, sanitize base name
        import re
        name, ext = os.path.splitext(filename)
        name = re.sub(r'[^a-zA-Z0-9_.-]', '_', name)[:100]  # Max 100 chars
        ext = re.sub(r'[^a-zA-Z0-9.]', '', ext)[:10]  # Max 10 chars for extension
        return (name + ext) if name else "unnamed" + ext

from apscheduler.schedulers.background import BackgroundScheduler

# Global list to track all scheduler instances for proper shutdown
_active_schedulers = []

def _shutdown_all_schedulers():
    """Gracefully shutdown all active schedulers to prevent job submission errors during worker exit."""
    for scheduler in _active_schedulers:
        try:
            if scheduler and scheduler.running:
                scheduler.shutdown(wait=False)
                print(f"[SCHEDULER] Scheduler shut down gracefully")
        except Exception as e:
            print(f"[SCHEDULER] Error shutting down scheduler: {e}")
    _active_schedulers.clear()

# Register cleanup on normal Python exit (but not on signals - Gunicorn handles those)
# This prevents "RuntimeError: cannot schedule new futures after shutdown" during graceful exits
atexit.register(_shutdown_all_schedulers)

