@app.context_processor
def inject_build_id():
    """PR-5a: Inject build_id for cache-busting static assets"""
    # Compute build_id from git commit + file mtime
    git_commit = "unknown"
    try:
        result = subprocess.run(
            ["git", "rev-parse", "--short", "HEAD"],
            capture_output=True,
            text=True,
            timeout=2,
            cwd=os.path.dirname(os.path.abspath(__file__))
        )
        if result.returncode == 0:
            git_commit = result.stdout.strip()
    except Exception:
        pass

    build_time = os.path.getmtime(__file__) if os.path.exists(__file__) else None
    build_id = f"{git_commit}"
    if build_time:
        build_id += f"-{int(build_time)}"

    default_origin = request.host_url.rstrip("/") if request else ""
    node1_rpc_url = os.getenv("NODE1_RPC_URL", default_origin)
    node2_rpc_url = os.getenv("NODE2_RPC_URL", node1_rpc_url)

    return dict(
        build_id=build_id,
        node1_rpc_url=node1_rpc_url,
        node2_rpc_url=node2_rpc_url,
        node_role=NODE_ROLE,
        master_public_url=MASTER_PUBLIC_URL,
        read_node_url=READ_NODE_URL,
        public_url=PUBLIC_URL,
        media_url=MEDIA_URL,
        asset_cdn_base=ASSET_CDN_BASE,
        music_modal_enabled=MUSIC_MODAL_ENABLED,
    )


