def _usage_from_dict(raw: dict | None) -> dict:
    if not isinstance(raw, dict):
        return {"input_tokens": 0, "output_tokens": 0, "total_tokens": 0}

    def _num(val):
        try:
            return int(val or 0)
        except Exception:
            return 0

    usage = {
        "input_tokens": _num(raw.get("input_tokens")),
        "output_tokens": _num(raw.get("output_tokens")),
    }
    usage["total_tokens"] = usage["input_tokens"] + usage["output_tokens"]
    return usage


def _split_system_and_messages(messages: list[dict]) -> tuple[str | None, list[dict]]:
    system_prompt = None
    chat_messages: list[dict] = []
    for m in messages:
        if not isinstance(m, dict):
            continue
        role = (m.get("role") or "").lower()
        content = (m.get("content") or "").strip()
        if not content:
            continue
        if role == "system":
            system_prompt = (system_prompt + "\n" + content) if system_prompt else content
        else:
            chat_messages.append({"role": role if role in ("user", "assistant") else "user", "content": content})
    return system_prompt, chat_messages


def call_claude(model: str, messages: list[dict], max_tokens: int = 2048, temperature: float = 0.6) -> dict:
    api_key = (os.getenv("ANTHROPIC_API_KEY") or "").strip()
    if not api_key:
        app.logger.error("Claude call blocked: missing ANTHROPIC_API_KEY")
        raise RuntimeError("Claude provider unavailable")

    system_prompt, chat_messages = _split_system_and_messages(messages)
    if not chat_messages:
        raise RuntimeError("No chat messages provided")

    headers = {
        "x-api-key": api_key,
        "anthropic-version": "2023-06-01",
        "content-type": "application/json",
    }
    payload = {
        "model": model or "claude-sonnet-4-5-20250929",
        "max_tokens": max_tokens,
        "temperature": temperature,
        "messages": chat_messages,
    }
    if system_prompt:
        payload["system"] = system_prompt

    try:
        resp = requests.post(
            "https://api.anthropic.com/v1/messages",
            headers=headers,
            json=payload,
            timeout=2,
        )
    except requests.Timeout:
        app.logger.error("Claude timeout", extra={"model": model})
        raise
    except Exception as exc:  # pragma: no cover - defensive
        app.logger.error("Claude call failed", extra={"model": model, "error": str(exc)})
        raise

    if resp.status_code in (401, 403):
        app.logger.error("Claude auth failure", extra={"model": model, "status": resp.status_code})
    if resp.status_code >= 400:
        raise RuntimeError(f"HTTP {resp.status_code}: {resp.text}")

    data = resp.json()
    text = "".join(
        [part.get("text", "") for part in data.get("content", []) if isinstance(part, dict)]
    )
    return {
        "content": text.strip(),
        "usage": _usage_from_dict(data.get("usage")),
    }


def call_openai_chat(model: str, messages: list[dict], max_tokens: int = 2048, temperature: float = 0.6) -> dict:
    api_key = (os.getenv("OPENAI_API_KEY") or "").strip()
    if not api_key:
        app.logger.error("OpenAI call blocked: missing OPENAI_API_KEY")
        raise RuntimeError("OpenAI provider unavailable")

    headers = {
        "Authorization": f"Bearer {api_key}",
        "Content-Type": "application/json",
    }
    payload = {
        "model": model or "gpt-4.1",
        "messages": messages,
        "max_tokens": max_tokens,
        "temperature": temperature,
    }
    try:
        resp = requests.post(
            "https://api.openai.com/v1/chat/completions",
            headers=headers,
            json=payload,
            timeout=2,
        )
    except requests.Timeout:
        app.logger.error("OpenAI timeout", extra={"model": model})
        raise

    if resp.status_code in (401, 403):
        app.logger.error("OpenAI auth failure", extra={"model": model, "status": resp.status_code})
    if resp.status_code >= 400:
        raise RuntimeError(f"HTTP {resp.status_code}: {resp.text}")

    data = resp.json()
    message = ""
    try:
        message = data.get("choices", [{}])[0].get("message", {}).get("content", "") or ""
    except Exception:
        message = data.get("content", "") or ""
    usage = _usage_from_dict(data.get("usage"))
    return {"content": message.strip(), "usage": usage}


def call_gemini_chat(model: str, messages: list[dict], max_tokens: int = 1024, temperature: float = 0.6) -> dict:
    api_key = (os.getenv("GEMINI_API_KEY") or os.getenv("GOOGLE_API_KEY") or "").strip()
    if not api_key:
        app.logger.error("Gemini call blocked: missing GEMINI_API_KEY/GOOGLE_API_KEY")
        raise RuntimeError("Gemini provider unavailable")

    contents = [m.get("content", "") for m in messages if isinstance(m, dict)]
    prompt = "\n\n".join(contents).strip()
    if not prompt:
        raise RuntimeError("No chat messages provided")

    url = f"https://generativelanguage.googleapis.com/v1beta/models/{model}:generateContent"
    params = {"key": api_key}
    body = {
        "contents": [{"parts": [{"text": prompt}]}],
        "generationConfig": {"maxOutputTokens": max_tokens, "temperature": temperature},
    }
    try:
        resp = requests.post(url, params=params, json=body, timeout=2)
    except requests.Timeout:
        app.logger.error("Gemini timeout", extra={"model": model})
        raise

    if resp.status_code in (401, 403):
        app.logger.error("Gemini auth failure", extra={"model": model, "status": resp.status_code})
    if resp.status_code >= 400:
        raise RuntimeError(f"HTTP {resp.status_code}: {resp.text}")

    data = resp.json()
    candidates = data.get("candidates", []) or []
    text = ""
    if candidates:
        parts = candidates[0].get("content", {}).get("parts", [])
        text = "".join([p.get("text", "") for p in parts if isinstance(p, dict)])
    return {"content": text.strip(), "usage": _usage_from_dict(data.get("usage"))}


def _infer_provider(model: str | None, explicit: str | None = None) -> str:
    if explicit:
        return explicit.lower()
    if not model:
        return "anthropic"
    ml = model.lower()
    if ml.startswith("gpt") or ml.startswith("o1") or ml.startswith("o3"):
        return "openai"
    if ml.startswith("gemini"):
        return "google"
    if ml.startswith("claude"):
        return "anthropic"
    return "anthropic"


def refresh_model_catalog(force: bool = False) -> dict:
    global MODEL_CATALOG, MODEL_CATALOG_LAST_REFRESH

    # PR-XXX: Only sync AI models on master nodes (skip on replica/ai-core)
    if not is_master():
        app.logger.info(f"[AI] Skipping model catalog refresh on {NODE_ROLE} node")
        return MODEL_CATALOG or base_model_config()

    now = time.time()
    if MODEL_CATALOG and not force and now - MODEL_CATALOG_LAST_REFRESH < MODEL_REFRESH_INTERVAL_SECONDS:
        return MODEL_CATALOG

    openai_api_key = (os.getenv("OPENAI_API_KEY") or "").strip()
    catalog = base_model_config()
    provider_keys = {
        "openai": bool((openai_api_key or os.getenv("OPENAI_KEY") or "").strip()),
        "anthropic": bool((os.getenv("ANTHROPIC_API_KEY") or "").strip()),
        "google": bool((os.getenv("GEMINI_API_KEY") or os.getenv("GOOGLE_API_KEY") or "").strip()),
    }

    if openai_api_key:
        try:
            res = requests.get(
                "https://api.openai.com/v1/models",
                headers={"Authorization": f"Bearer {openai_api_key}"},
                timeout=2,
            )
            if res.status_code == 200:
                data = res.json().get("data", [])
                ids = set()
                for item in data:
                    mid = item.get("id", "")
                    if any(mid.startswith(pfx) for pfx in OPENAI_MODEL_FILTER):
                        ids.add(mid)
                models = catalog.get("openai", {}).get("models", [])
                existing_ids = {m["id"] for m in models}
                for mid in sorted(ids):
                    if mid not in existing_ids:
                        models.append({"id": mid, "label": mid})
        except Exception as exc:
            app.logger.warning("OpenAI model sync failed", extra={"error": str(exc)})

    for provider, data in catalog.items():
        data["enabled"] = provider_keys.get(provider, False)

    MODEL_CATALOG = {"providers": catalog, "refreshed_at": datetime.utcnow().isoformat(timespec="seconds") + "Z"}
    MODEL_CATALOG_LAST_REFRESH = now
    return MODEL_CATALOG


def _health_cache_ok(provider: str):
    cached = PROVIDER_HEALTH_CACHE.get(provider)
    if not cached:
        return None
    if time.time() - cached.get("ts", 0) <= PROVIDER_HEALTH_TTL:
        return cached.get("status")
    return None


def _check_provider_health(provider: str) -> str:
    cached = _health_cache_ok(provider)
    if cached:
        return cached

    status = "ok"
    try:
        if provider == "anthropic":
            call_claude("claude-sonnet-4-5-20250929", [{"role": "user", "content": "ping"}], max_tokens=1, temperature=0)
        elif provider == "openai":
            call_openai_chat("gpt-4.1-mini", [{"role": "user", "content": "ping"}], max_tokens=1, temperature=0)
        elif provider == "google":
            call_gemini_chat("gemini-1.5-flash-latest", [{"role": "user", "content": "ping"}], max_tokens=1, temperature=0)
        else:
            status = "error"
    except Exception as exc:
        status = "error"
        app.logger.warning("Provider health check failed", extra={"provider": provider, "error": str(exc)})

    PROVIDER_HEALTH_CACHE[provider] = {"status": status, "ts": time.time()}
    return status


def _start_model_scheduler():
    # PR-XXX: Only run model scheduler on master or AI core nodes
    if not should_sync_ai_models():
        app.logger.info(f"[AI] Skipping model scheduler on {NODE_ROLE} node")
        return

    enabled = (_strip_env_quotes(os.getenv("SCHEDULER_ENABLED", "true")).lower() not in ("0", "false", "no"))
    if not enabled:
        app.logger.info("Model refresh scheduler disabled via SCHEDULER_ENABLED")
        return

    def _job():
        try:
            refresh_model_catalog(force=True)
        except Exception as exc:  # pragma: no cover - background job safety
            app.logger.warning("Model refresh job failed", extra={"error": str(exc)})

    scheduler = BackgroundScheduler()
    scheduler.add_job(_job, "interval", seconds=MODEL_REFRESH_INTERVAL_SECONDS, id="model_refresh", replace_existing=True)
    scheduler.start()
    _active_schedulers.append(scheduler)
    app.logger.info("[AI] Background scheduler started for model catalog refresh")


# ─── HELPERS ───────────────────────────────────────
def _load_json_file(path, default):
    try:
        with open(path, "r", encoding="utf-8") as f:
            return json.load(f)
    except (FileNotFoundError, json.JSONDecodeError):
        return default


def _get_ledger_db_connection():
    conn = sqlite3.connect(LEDGER_DB_FILE, timeout=30)  # Wait up to 30s if locked
    conn.row_factory = sqlite3.Row
    # Enable WAL mode for better concurrent read/write performance
    conn.execute("PRAGMA journal_mode=WAL")
    conn.execute("PRAGMA busy_timeout=30000")  # 30 second busy timeout
    return conn


def _ledger_type_for_path(path: str) -> str | None:
    if path == LEDGER_FILE:
        return "thr"
    if path == WBTC_LEDGER_FILE:
        return "wbtc"
    if path == L2E_LEDGER_FILE:
        return "l2e"
    return None


def _load_ledger_from_sqlite(ledger_type: str) -> dict:
    if not USE_SQLITE_LEDGER:
        return {}
    with _get_ledger_db_connection() as conn:
        rows = conn.execute(
            "SELECT address, balance FROM balances WHERE ledger_type = ?",
            (ledger_type,),
        ).fetchall()
    return {row["address"]: row["balance"] for row in rows}


def _write_ledger_to_sqlite(ledger_type: str, ledger: dict) -> None:
    if not USE_SQLITE_LEDGER:
        return
    now_ts = int(time.time())
    entries = [
        (ledger_type, address, float(balance), now_ts)
        for address, balance in ledger.items()
        if address
    ]
    if not entries:
        return
    with _get_ledger_db_connection() as conn:
        conn.executemany(
            """
            INSERT INTO balances (ledger_type, address, balance, updated_at)
            VALUES (?, ?, ?, ?)
            ON CONFLICT(ledger_type, address)
            DO UPDATE SET balance = excluded.balance, updated_at = excluded.updated_at
            """,
            entries,
        )


def _init_ledger_db():
    """
    Initialize SQLite database (idempotent).
    Creates tables for:
    - balances: wallet balances (existing)
    - event_index: block/transaction events for fast querying
    - telemetry_cache: cached network stats (hashrate, difficulty, tx count)
    """
    if not USE_SQLITE_LEDGER:
        return
    os.makedirs(DATA_DIR, exist_ok=True)
    with _get_ledger_db_connection() as conn:
        # Balances table (existing)
        conn.execute(
            """
            CREATE TABLE IF NOT EXISTS balances (
                ledger_type TEXT NOT NULL,
                address TEXT NOT NULL,
                balance REAL NOT NULL DEFAULT 0,
                updated_at INTEGER NOT NULL,
                PRIMARY KEY (ledger_type, address)
            )
            """
        )
        conn.execute("CREATE INDEX IF NOT EXISTS idx_balances_address ON balances(address)")
        conn.execute("CREATE INDEX IF NOT EXISTS idx_balances_ledger_type ON balances(ledger_type)")
        conn.execute("CREATE INDEX IF NOT EXISTS idx_balances_updated_at ON balances(updated_at)")

        # Event index table (NEW - for fast block/tx queries)
        conn.execute(
            """
            CREATE TABLE IF NOT EXISTS event_index (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                event_type TEXT NOT NULL,
                event_id TEXT NOT NULL,
                height INTEGER,
                timestamp TEXT NOT NULL,
                from_address TEXT,
                to_address TEXT,
                amount REAL,
                asset_symbol TEXT,
                metadata TEXT,
                indexed_at INTEGER NOT NULL,
                UNIQUE(event_type, event_id)
            )
            """
        )
        conn.execute("CREATE INDEX IF NOT EXISTS idx_event_type ON event_index(event_type)")
        conn.execute("CREATE INDEX IF NOT EXISTS idx_event_height ON event_index(height DESC)")
        conn.execute("CREATE INDEX IF NOT EXISTS idx_event_timestamp ON event_index(timestamp DESC)")
        conn.execute("CREATE INDEX IF NOT EXISTS idx_event_from_addr ON event_index(from_address)")
        conn.execute("CREATE INDEX IF NOT EXISTS idx_event_to_addr ON event_index(to_address)")

        # Telemetry cache table (NEW - for dashboard stats)
        conn.execute(
            """
            CREATE TABLE IF NOT EXISTS telemetry_cache (
                metric_key TEXT PRIMARY KEY,
                metric_value TEXT NOT NULL,
                updated_at INTEGER NOT NULL
            )
            """
        )
        conn.execute("CREATE INDEX IF NOT EXISTS idx_telemetry_updated ON telemetry_cache(updated_at DESC)")

        # Music plays table (NEW - for GPS/Music telemetry integration)
        conn.execute(
            """
            CREATE TABLE IF NOT EXISTS music_plays (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                track_id TEXT NOT NULL,
                wallet_address TEXT NOT NULL,
                artist_address TEXT,
                play_timestamp INTEGER NOT NULL,
                duration_seconds INTEGER,
                gps_lat REAL,
                gps_lng REAL,
                tip_amount REAL DEFAULT 0.0,
                indexed_at INTEGER NOT NULL
            )
            """
        )
        conn.execute("CREATE INDEX IF NOT EXISTS idx_music_wallet ON music_plays(wallet_address)")
        conn.execute("CREATE INDEX IF NOT EXISTS idx_music_artist ON music_plays(artist_address)")
        conn.execute("CREATE INDEX IF NOT EXISTS idx_music_timestamp ON music_plays(play_timestamp DESC)")
        conn.execute("CREATE INDEX IF NOT EXISTS idx_music_track ON music_plays(track_id)")

        # Music playlists tables (NEW - playlist persistence)
        conn.execute(
            """
            CREATE TABLE IF NOT EXISTS music_playlists (
                id TEXT PRIMARY KEY,
                owner_address TEXT NOT NULL,
                title TEXT NOT NULL,
                created_at TEXT NOT NULL,
                updated_at TEXT NOT NULL
            )
            """
        )
        conn.execute("CREATE INDEX IF NOT EXISTS idx_music_playlists_owner ON music_playlists(owner_address)")
        conn.execute("CREATE INDEX IF NOT EXISTS idx_music_playlists_updated ON music_playlists(updated_at DESC)")

        conn.execute(
            """
            CREATE TABLE IF NOT EXISTS music_playlist_items (
                playlist_id TEXT NOT NULL,
                track_id TEXT NOT NULL,
                position INTEGER NOT NULL DEFAULT 0,
                added_at TEXT NOT NULL,
                PRIMARY KEY (playlist_id, track_id),
                FOREIGN KEY (playlist_id) REFERENCES music_playlists(id) ON DELETE CASCADE
            )
            """
        )
        conn.execute("CREATE INDEX IF NOT EXISTS idx_music_playlist_items_playlist ON music_playlist_items(playlist_id)")
        conn.execute("CREATE INDEX IF NOT EXISTS idx_music_playlist_items_position ON music_playlist_items(position)")

        conn.execute(
            """
            CREATE TABLE IF NOT EXISTS iot_devices (
                device_id TEXT PRIMARY KEY,
                label TEXT,
                owner_wallet TEXT,
                sensor_type TEXT,
                location TEXT,
                api_key TEXT,
                created_at INTEGER NOT NULL,
                updated_at INTEGER NOT NULL
            )
            """
        )
        conn.execute("CREATE INDEX IF NOT EXISTS idx_iot_devices_owner ON iot_devices(owner_wallet)")
        conn.execute("CREATE INDEX IF NOT EXISTS idx_iot_devices_sensor_type ON iot_devices(sensor_type)")

        conn.execute(
            """
            CREATE TABLE IF NOT EXISTS iot_readings (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                device_id TEXT NOT NULL,
                sensor_type TEXT NOT NULL,
                value_text TEXT,
                value_num REAL,
                unit TEXT,
                ts INTEGER NOT NULL,
                metadata_json TEXT,
                created_at INTEGER NOT NULL,
                FOREIGN KEY (device_id) REFERENCES iot_devices(device_id) ON DELETE CASCADE
            )
            """
        )
        conn.execute("CREATE INDEX IF NOT EXISTS idx_iot_readings_device_ts ON iot_readings(device_id, ts DESC)")
        conn.execute("CREATE INDEX IF NOT EXISTS idx_iot_readings_sensor_ts ON iot_readings(sensor_type, ts DESC)")

    with _get_ledger_db_connection() as conn:
        row = conn.execute("SELECT COUNT(1) AS count FROM balances").fetchone()
        count = row["count"] if row else 0

    if count == 0:
        seeds = {
            "thr": _load_json_file(LEDGER_FILE, {}),
            "wbtc": _load_json_file(WBTC_LEDGER_FILE, {}),
            "l2e": _load_json_file(L2E_LEDGER_FILE, {}),
        }
        for ledger_type, ledger in seeds.items():
            if ledger:
                _write_ledger_to_sqlite(ledger_type, ledger)


# ========================================
# EVENT INDEXER (NEW - Performance)
# ========================================

def _index_block_event(block: dict) -> None:
    """Index a block event for fast querying. Prevents O(n) chain scans."""
    if not USE_SQLITE_LEDGER:
        return
    try:
        now_ts = int(time.time())
        with _get_ledger_db_connection() as conn:
            conn.execute(
                """
                INSERT OR REPLACE INTO event_index
                (event_type, event_id, height, timestamp, metadata, indexed_at)
                VALUES (?, ?, ?, ?, ?, ?)
                """,
                (
                    "block",
                    block.get("block_hash", ""),
                    block.get("height"),
                    block.get("timestamp", ""),
                    json.dumps({
                        "miner": block.get("thr_address"),
                        "reward": block.get("reward"),
                        "nonce": block.get("nonce"),
                    }),
                    now_ts,
                ),
            )
    except Exception as e:
        logger.error(f"Failed to index block event: {e}")


def _index_transaction_event(tx: dict) -> None:
    """Index a transaction event for fast querying. Enables O(1) wallet history."""
    if not USE_SQLITE_LEDGER:
        return
    try:
        now_ts = int(time.time())
        with _get_ledger_db_connection() as conn:
            conn.execute(
                """
                INSERT OR REPLACE INTO event_index
                (event_type, event_id, height, timestamp, from_address, to_address,
                 amount, asset_symbol, metadata, indexed_at)
                VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
                """,
                (
                    tx.get("type", "transaction"),
                    tx.get("tx_id", tx.get("hash", "")),
                    tx.get("height"),
                    tx.get("timestamp", ""),
                    tx.get("from"),
                    tx.get("to"),
                    tx.get("amount"),
                    tx.get("symbol", "THR"),
                    json.dumps({k: v for k, v in tx.items()
                               if k not in ["from", "to", "amount", "symbol", "timestamp", "height"]}),
                    now_ts,
                ),
            )
    except Exception as e:
        logger.error(f"Failed to index transaction event: {e}")


def _get_recent_events(event_type: str = None, limit: int = 100, address: str = None) -> list:
    """
    Get recent events from index (fast).
    - event_type: 'block', 'transaction', 'transfer', etc. (None = all)
    - limit: max results (default 100)
    - address: filter by from/to address (None = all)

    Returns: List of events sorted by timestamp DESC
    """
    if not USE_SQLITE_LEDGER:
        return []

    try:
        with _get_ledger_db_connection() as conn:
            query = "SELECT * FROM event_index WHERE 1=1"
            params = []

            if event_type:
                query += " AND event_type = ?"
                params.append(event_type)

            if address:
                query += " AND (from_address = ? OR to_address = ?)"
                params.extend([address, address])

            query += " ORDER BY timestamp DESC LIMIT ?"
            params.append(limit)

            rows = conn.execute(query, params).fetchall()

            return [
                {
                    "id": row["id"],
                    "event_type": row["event_type"],
                    "event_id": row["event_id"],
                    "height": row["height"],
                    "timestamp": row["timestamp"],
                    "from": row["from_address"],
                    "to": row["to_address"],
                    "amount": row["amount"],
                    "symbol": row["asset_symbol"],
                    "metadata": json.loads(row["metadata"]) if row["metadata"] else {},
                }
                for row in rows
            ]
    except Exception as e:
        logger.error(f"Failed to get recent events: {e}")
        return []


# ========================================
# TELEMETRY CACHE (NEW - Dashboard)
# ========================================

def _update_telemetry_cache(key: str, value: any) -> None:
    """Update cached telemetry metric. Prevents expensive recalculations."""
    if not USE_SQLITE_LEDGER:
        return
    try:
        now_ts = int(time.time())
        with _get_ledger_db_connection() as conn:
            conn.execute(
                """
                INSERT OR REPLACE INTO telemetry_cache (metric_key, metric_value, updated_at)
                VALUES (?, ?, ?)
                """,
                (key, json.dumps(value), now_ts),
            )
    except Exception as e:
        logger.error(f"Failed to update telemetry cache: {e}")


def _get_telemetry_cache(key: str, max_age_seconds: int = 60) -> any:
    """
    Get cached telemetry metric if fresh enough.
    - key: metric name (e.g., 'network_hashrate', 'difficulty', 'tx_count')
    - max_age_seconds: max cache age (default 60s)

    Returns: Cached value or None if stale/missing
    """
    if not USE_SQLITE_LEDGER:
        return None

    try:
        now_ts = int(time.time())
        with _get_ledger_db_connection() as conn:
            row = conn.execute(
                "SELECT metric_value, updated_at FROM telemetry_cache WHERE metric_key = ?",
                (key,),
            ).fetchone()

            if not row:
                return None

            age = now_ts - row["updated_at"]
            if age > max_age_seconds:
                return None  # Stale

            return json.loads(row["metric_value"])
    except Exception as e:
        logger.error(f"Failed to get telemetry cache: {e}")
        return None


