def _track_music_play(track_id: str, wallet_address: str, artist_address: str = None,
                     duration_seconds: int = None, gps_lat: float = None, gps_lng: float = None,
                     tip_amount: float = 0.0) -> None:
    """
    Track music play with optional GPS coordinates.
    Used for GPS/Music telemetry integration and autonomous driving data collection.
    """
    if not USE_SQLITE_LEDGER:
        return
    try:
        now_ts = int(time.time())
        with _get_ledger_db_connection() as conn:
            conn.execute(
                """
                INSERT INTO music_plays
                (track_id, wallet_address, artist_address, play_timestamp,
                 duration_seconds, gps_lat, gps_lng, tip_amount, indexed_at)
                VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)
                """,
                (track_id, wallet_address, artist_address, now_ts,
                 duration_seconds, gps_lat, gps_lng, tip_amount, now_ts),
            )
    except Exception as e:
        logger.error(f"Failed to track music play: {e}")


def _get_music_plays(wallet_address: str = None, track_id: str = None,
                    artist_address: str = None, limit: int = 100) -> list:
    """
    Get music play history with optional filters.
    - wallet_address: Filter by listener
    - track_id: Filter by track
    - artist_address: Filter by artist
    - limit: Max results (default 100)

    Returns: List of music plays with GPS data
    """
    if not USE_SQLITE_LEDGER:
        return []

    try:
        with _get_ledger_db_connection() as conn:
            query = "SELECT * FROM music_plays WHERE 1=1"
            params = []

            if wallet_address:
                query += " AND wallet_address = ?"
                params.append(wallet_address)

            if track_id:
                query += " AND track_id = ?"
                params.append(track_id)

            if artist_address:
                query += " AND artist_address = ?"
                params.append(artist_address)

            query += " ORDER BY play_timestamp DESC LIMIT ?"
            params.append(limit)

            rows = conn.execute(query, params).fetchall()

            return [
                {
                    "id": row["id"],
                    "track_id": row["track_id"],
                    "wallet_address": row["wallet_address"],
                    "artist_address": row["artist_address"],
                    "play_timestamp": row["play_timestamp"],
                    "duration_seconds": row["duration_seconds"],
                    "gps_lat": row["gps_lat"],
                    "gps_lng": row["gps_lng"],
                    "tip_amount": row["tip_amount"],
                }
                for row in rows
            ]
    except Exception as e:
        logger.error(f"Failed to get music plays: {e}")
        return []


def _update_music_play_tip(track_id: str, wallet_address: str, tip_amount: float, duration_seconds: int = None) -> bool:
    """
    Update music play record with tip amount and duration when session ends.
    Finds the most recent play matching track_id and wallet_address within last 24 hours.

    Returns: True if record was updated, False otherwise
    """
    if not USE_SQLITE_LEDGER:
        return False

    try:
        now_ts = int(time.time())
        time_window = 24 * 60 * 60  # 24 hours

        with _get_ledger_db_connection() as conn:
            # Find most recent matching play within time window
            row = conn.execute(
                """
                SELECT id FROM music_plays
                WHERE track_id = ? AND wallet_address = ?
                AND play_timestamp > ?
                ORDER BY play_timestamp DESC
                LIMIT 1
                """,
                (track_id, wallet_address, now_ts - time_window),
            ).fetchone()

            if not row:
                logger.warning(f"No recent music play found for track {track_id}, wallet {wallet_address}")
                return False

            # Update with tip and duration
            play_id = row["id"]
            update_fields = ["tip_amount = ?"]
            params = [tip_amount]

            if duration_seconds is not None:
                update_fields.append("duration_seconds = ?")
                params.append(duration_seconds)

            params.append(play_id)

            conn.execute(
                f"UPDATE music_plays SET {', '.join(update_fields)} WHERE id = ?",
                params,
            )

            logger.info(f"Updated music play {play_id} with tip {tip_amount} THR")
            return True

    except Exception as e:
        logger.error(f"Failed to update music play tip: {e}")
        return False


def load_json(path, default):
    ledger_type = _ledger_type_for_path(path)
    if ledger_type:
        ledger_data = _load_ledger_from_sqlite(ledger_type)
        if ledger_data or USE_SQLITE_LEDGER:
            return ledger_data
    return _load_json_file(path, default)


def _seed_chain_meta():
    try:
        snapshot = load_json(LAST_BLOCK_FILE, {})
    except Exception:
        snapshot = {}
    if isinstance(snapshot, dict) and snapshot:
        set_chain_meta(
            snapshot.get("height", 0),
            snapshot.get("block_hash") or snapshot.get("last_hash"),
            snapshot,
        )


_seed_chain_meta()


def save_json(path, data):
    ledger_type = _ledger_type_for_path(path)
    if ledger_type:
        _write_ledger_to_sqlite(ledger_type, data)
    os.makedirs(os.path.dirname(path), exist_ok=True)
    dir_name = os.path.dirname(path)
    base_name = os.path.basename(path)
    try:
        with tempfile.NamedTemporaryFile("w", delete=False, dir=dir_name, prefix=f".{base_name}.", suffix=".tmp", encoding="utf-8") as tmp:
            json.dump(data, tmp, ensure_ascii=False, indent=2)
            tmp_path = tmp.name
        os.replace(tmp_path, path)
    finally:
        try:
            if "tmp_path" in locals() and os.path.exists(tmp_path):
                os.remove(tmp_path)
        except Exception:
            pass


def atomic_write_json(path: str, data) -> None:
    os.makedirs(os.path.dirname(path), exist_ok=True)
    dir_name = os.path.dirname(path)
    base_name = os.path.basename(path)
    tmp_path = None
    try:
        with tempfile.NamedTemporaryFile("w", delete=False, dir=dir_name, prefix=f".{base_name}.", suffix=".tmp", encoding="utf-8") as tmp:
            json.dump(data, tmp, ensure_ascii=False, indent=2)
            tmp.flush()
            os.fsync(tmp.fileno())
            tmp_path = tmp.name
        os.replace(tmp_path, path)
    finally:
        if tmp_path and os.path.exists(tmp_path):
            try:
                os.remove(tmp_path)
            except Exception:
                pass


_init_ledger_db()


def _default_tokens_registry() -> dict:
    return {
        "tokens": {
            "THR": {"decimals": 6, "chain": "thronos", "rpc_env": "THR_RPC_URL", "treasury_address": AI_WALLET_ADDRESS},
            "WBTC": {"decimals": 8, "chain": "bitcoin", "rpc_env": "BTC_RPC_URL", "treasury_address": os.getenv("TREASURY_WBTC_ADDRESS", AI_WALLET_ADDRESS)},
            "L2E": {"decimals": 6, "chain": "thronos", "rpc_env": "THR_RPC_URL", "treasury_address": AI_WALLET_ADDRESS},
            "T2E": {"decimals": 6, "chain": "thronos", "rpc_env": "THR_RPC_URL", "treasury_address": AI_WALLET_ADDRESS},
        },
        "updated_at": datetime.utcnow().isoformat(timespec="seconds") + "Z",
    }


def load_tokens_registry() -> dict:
    data = load_json(TOKENS_REGISTRY_FILE, {})
    if not isinstance(data, dict) or not isinstance(data.get("tokens"), dict) or not data.get("tokens"):
        data = _default_tokens_registry()
        save_json(TOKENS_REGISTRY_FILE, data)
    return data


def _token_decimals(symbol: str) -> int:
    registry = load_tokens_registry()
    token_meta = (registry.get("tokens") or {}).get((symbol or "THR").upper(), {})
    try:
        return max(0, int(token_meta.get("decimals", 6)))
    except Exception:
        return 6


def _normalize_decimal_amount(raw_amount, symbol: str) -> Decimal:
    dec = _token_decimals(symbol)
    quant = Decimal("1").scaleb(-dec)
    amount = Decimal(str(raw_amount or "0")).quantize(quant, rounding=ROUND_DOWN)
    if amount <= Decimal("0"):
        raise ValueError("invalid_amount")
    return amount


def emit_crosschain_event(event_type: str, payload: dict, status: str = "PENDING") -> dict:
    event_bus = load_json(EVENT_BUS_FILE, {"events": []})
    if not isinstance(event_bus, dict):
        event_bus = {"events": []}
    events = event_bus.get("events")
    if not isinstance(events, list):
        events = []
    event = {
        "event_id": f"EVT-{int(time.time()*1000)}-{secrets.token_hex(4)}",
        "type": str(event_type or "UNKNOWN").upper(),
        "status": str(status or "PENDING").upper(),
        "created_at": datetime.utcnow().isoformat(timespec="seconds") + "Z",
        "payload": payload if isinstance(payload, dict) else {},
    }
    events.append(event)
    event_bus["events"] = events[-5000:]
    event_bus["updated_at"] = datetime.utcnow().isoformat(timespec="seconds") + "Z"
    save_json(EVENT_BUS_FILE, event_bus)
    return event


def settle_pending_crosschain_events(limit: int = 100) -> int:
    event_bus = load_json(EVENT_BUS_FILE, {"events": []})
    events = event_bus.get("events") if isinstance(event_bus, dict) else []
    if not isinstance(events, list):
        return 0
    settled = 0
    for ev in events:
        if settled >= limit:
            break
        if not isinstance(ev, dict):
            continue
        if str(ev.get("status") or "").upper() != "PENDING":
            continue
        ev["status"] = "SETTLED"
        ev["settled_at"] = datetime.utcnow().isoformat(timespec="seconds") + "Z"
        settled += 1
    if settled:
        event_bus["events"] = events
        event_bus["updated_at"] = datetime.utcnow().isoformat(timespec="seconds") + "Z"
        save_json(EVENT_BUS_FILE, event_bus)
    return settled


def _x9_nonce_seen(nonce: str) -> bool:
    nonce = str(nonce or "").strip()
    if not nonce:
        return True
    bucket = load_json(X9_NONCE_CACHE_FILE, {"nonces": {}})
    nonces = bucket.get("nonces") if isinstance(bucket, dict) else {}
    if not isinstance(nonces, dict):
        nonces = {}
    now = int(time.time())
    # prune old entries (5 min)
    nonces = {k: int(v) for k, v in nonces.items() if int(v) >= now - 300}
    if nonce in nonces:
        return True
    nonces[nonce] = now
    save_json(X9_NONCE_CACHE_FILE, {"nonces": nonces})
    return False


# ─── Whitelist Wallet System ───────────────────────────────────────────────────
def load_whitelist_wallets() -> list:
    """
    Load whitelist wallets from file or env variable.
    Returns list of THR addresses.
    """
    env_whitelist = os.getenv("THRONOS_WHITELIST_WALLETS", "")
    if env_whitelist:
        addresses = [addr.strip() for addr in env_whitelist.split(",") if addr.strip()]
        return addresses

    entries = load_json(WHITELIST_WALLETS_FILE, [])
    if not isinstance(entries, list):
        return []

    addresses = []
    for entry in entries:
        if isinstance(entry, str):
            addresses.append(entry)
            continue
        if isinstance(entry, dict):
            address = entry.get("address") or entry.get("thr_address")
            if not address:
                continue
            if entry.get("active", True) and not entry.get("banned", False):
                addresses.append(address)
    return addresses


def is_wallet_whitelisted(thr_address: str) -> bool:
    """Check if a THR address is in the whitelist."""
    if not thr_address:
        return False
    whitelist = load_whitelist_wallets()
    return thr_address in whitelist


def get_wallet_pledge_mode(thr_address: str) -> str:
    """
    Get pledge mode for a THR address.
    Returns: "btc_pledge" | "whitelist" | "none"
    """
    if not thr_address:
        return "none"

    # Check if wallet is whitelisted
    if is_wallet_whitelisted(thr_address):
        return "whitelist"

    # Check if wallet has BTC pledge
    pledges = load_json(PLEDGE_CHAIN, [])
    pledge = next((p for p in pledges if p.get("thr_address") == thr_address), None)

    if pledge and pledge.get("send_auth_hash"):
        return "btc_pledge"

    return "none"


def has_pledge_access(thr_address: str) -> bool:
    """
    Check if wallet has pledge access (either whitelist or BTC pledge).
    Returns True if pledge_mode != "none"
    """
    return get_effective_pledge_state(thr_address)["effective_pledge_ok"]


def has_btc_pledge(thr_address: str) -> bool:
    if not thr_address:
        return False
    pledges = load_json(PLEDGE_CHAIN, [])
    pledge = next((p for p in pledges if p.get("thr_address") == thr_address), None)
    return bool(pledge and pledge.get("send_auth_hash"))


def get_mining_whitelist_entry(thr_address: str) -> dict | None:
    """Return mining whitelist entry, supporting legacy string lists."""
    if not thr_address:
        return None

    env_whitelist = os.getenv("THRONOS_WHITELIST_WALLETS", "")
    if env_whitelist:
        addresses = [addr.strip() for addr in env_whitelist.split(",") if addr.strip()]
        if thr_address in addresses:
            return {
                "address": thr_address,
                "active": True,
                "pledge_ok": has_btc_pledge(thr_address),
                "whitelist_legacy": True,
            }

    entries = load_json(WHITELIST_WALLETS_FILE, [])
    if isinstance(entries, list):
        for entry in entries:
            if isinstance(entry, str):
                if entry == thr_address:
                    return {
                        "address": entry,
                        "active": True,
                        "pledge_ok": has_btc_pledge(thr_address),
                        "whitelist_legacy": True,
                    }
                continue
            if isinstance(entry, dict):
                address = entry.get("address") or entry.get("thr_address")
                if address == thr_address:
                    active = entry.get("active", True)
                    pledge_ok = entry.get("pledge_ok", has_btc_pledge(thr_address))
                    role = (entry.get("role") or "").lower()
                    whitelist_legacy = entry.get("whitelist_legacy")
                    if whitelist_legacy is None:
                        whitelist_legacy = True
                    return {
                        "address": address,
                        "active": active,
                        "pledge_ok": pledge_ok,
                        "whitelist_legacy": whitelist_legacy,
                        "banned": entry.get("banned", False),
                    }

    return None


def _whitelist_allows_no_pledge(entry: dict | None) -> bool:
    if not entry:
        return False
    if not entry.get("active", True) or entry.get("banned", False):
        return False
    return bool(entry.get("whitelist_legacy") or entry.get("grandfathered"))


def get_effective_pledge_state(thr_address: str) -> dict:
    entry = get_mining_whitelist_entry(thr_address)
    pledge_ok = has_btc_pledge(thr_address)
    whitelist_active = bool(entry and entry.get("active", True) and not entry.get("banned", False))
    whitelist_legacy = bool(whitelist_active and _whitelist_allows_no_pledge(entry))
    effective_pledge_ok = pledge_ok or whitelist_legacy
    if whitelist_active:
        pledge_mode = "whitelist"
    elif pledge_ok:
        pledge_mode = "btc_pledge"
    else:
        pledge_mode = "none"
    return {
        "pledge_ok": pledge_ok,
        "whitelist_active": whitelist_active,
        "whitelist_legacy": whitelist_legacy,
        "effective_pledge_ok": effective_pledge_ok,
        "pledge_mode": pledge_mode,
    }


def validate_effective_auth(thr_address: str, auth_secret: str, passphrase: str) -> tuple[bool, dict, str | None]:
    """
    Validate wallet auth for transactions.

    Handles multiple hash formats due to historical code paths:
    - server.py pledge_submit: SHA256(f"{send_seed}:auth")
    - pledge_submit.py:        SHA256(send_seed)
    - legacy pledges:          no send_auth_hash at all

    For legacy pledges without send_auth_hash, auto-registers the
    auth_secret on first use (one-time migration).
    """
    state = get_effective_pledge_state(thr_address)
    if not state["effective_pledge_ok"]:
        return False, state, "no_effective_pledge"
    if state["pledge_mode"] == "whitelist":
        return True, state, None
    if not auth_secret:
        return False, state, "missing_auth_secret"
    pledge = get_pledge_for_auth(thr_address)
    if not pledge:
        return False, state, "missing_pledge"
    stored_auth_hash = pledge.get("send_auth_hash")
    stored_seed_hash = pledge.get("send_seed_hash")

    # --- Legacy pledge: no send_auth_hash → auto-register on first auth ---
    if not stored_auth_hash:
        new_auth_hash = hashlib.sha256(f"{auth_secret}:auth".encode()).hexdigest()
        new_seed_hash = hashlib.sha256(auth_secret.encode()).hexdigest()
        pledges = load_json(PLEDGE_CHAIN, [])
        for p in pledges:
            if p.get("thr_address") == thr_address:
                p["send_auth_hash"] = new_auth_hash
                p["send_seed_hash"] = new_seed_hash
                p["has_passphrase"] = False
                p["auth_migrated_at"] = time.strftime("%Y-%m-%d %H:%M:%S UTC", time.gmtime())
                break
        save_json(PLEDGE_CHAIN, pledges)
        logger.info(f"[AUTH] Auto-migrated send_auth_hash for {thr_address}")
        return True, state, None

    # --- Passphrase handling ---
    if pledge.get("has_passphrase"):
        if not passphrase:
            return False, state, "passphrase_required"
        auth_candidates = [
            f"{auth_secret}:{passphrase}:auth",   # server.py format
            f"{auth_secret}|{passphrase}",         # pledge_submit.py format with phrase
        ]
    else:
        auth_candidates = [
            f"{auth_secret}:auth",                 # server.py format
            auth_secret,                           # pledge_submit.py format (raw seed)
        ]

    # --- Check all hash formats against stored_auth_hash ---
    for candidate in auth_candidates:
        if hashlib.sha256(candidate.encode()).hexdigest() == stored_auth_hash:
            return True, state, None

    # --- Fallback: check against send_seed_hash ---
    if stored_seed_hash:
        if hashlib.sha256(auth_secret.encode()).hexdigest() == stored_seed_hash:
            return True, state, None

    return False, state, "invalid_auth"


def get_pledge_for_auth(thr_address: str) -> dict | None:
    """
    Get pledge object for authentication purposes.
    Returns pledge object only if wallet has BTC pledge.
    Returns None if wallet is whitelisted or has no access.
    """
    if not thr_address:
        return None

    pledges = load_json(PLEDGE_CHAIN, [])
    return next((p for p in pledges if p.get("thr_address") == thr_address), None)


# ─── PR-182: Write Protection for Replica Nodes ────────────────────────────────
def _is_chain_file(path: str) -> bool:
    """Check if a file is a critical chain/ledger file that replicas shouldn't write."""
    critical_files = [
        LEDGER_FILE,
        WBTC_LEDGER_FILE,
        CHAIN_FILE,
        PLEDGE_CHAIN,
        MEMPOOL_FILE,
        LAST_BLOCK_FILE,
        TX_LOG_FILE,
        VOTING_FILE,  # Voting state is part of chain governance
        AI_CREDS_FILE,  # AI wallet credentials
        AI_POOL_FILE,  # Phase 4: AI rewards pool state
    ]
    return any(path == f for f in critical_files)


def _enforce_write_protection(path: str):
    """Raise an error if a replica node tries to write to chain files."""
    if READ_ONLY and _is_chain_file(path):
        raise PermissionError(
            f"[REPLICA] Node is in READ_ONLY mode. Cannot write to {path}. "
            f"Use MASTER_NODE_URL API instead."
        )


# Wrap save_json and atomic_write_json with write protection
_original_save_json = save_json
_original_atomic_write_json = atomic_write_json

def save_json(path, data):
    _enforce_write_protection(path)
    return _original_save_json(path, data)

def atomic_write_json(path: str, data) -> None:
    _enforce_write_protection(path)
    return _original_atomic_write_json(path, data)


def _authorized_logging_request(req) -> bool:
    key = req.headers.get("X-API-Key") or req.args.get("api_key") or ""
    return str(key) == str(AI_LOG_API_KEY)


def _load_jsonl(path: str) -> list:
    try:
        with open(path, "r", encoding="utf-8") as f:
            lines = [line.strip() for line in f if line.strip()]
        return [json.loads(line) for line in lines]
    except FileNotFoundError:
        return []
    except Exception:
        try:
            return load_json(path, [])
        except Exception:
            return []


def _save_jsonl(path: str, entries: list[dict]) -> None:
    os.makedirs(os.path.dirname(path), exist_ok=True)
    with open(path, "w", encoding="utf-8") as f:
        for entry in entries:
            f.write(json.dumps(entry, ensure_ascii=False) + "\n")


def _status_is_success(status: str) -> bool:
    status_l = (status or "").lower()
    if not status_l:
        return False
    return not any(token in status_l for token in ("error", "quota", "no_credits", "provider_error", "blocked"))


def load_ai_interactions() -> list[dict]:
    return _load_jsonl(AI_INTERACTIONS_FILE)


def save_ai_interactions(entries: list[dict]) -> None:
    _save_jsonl(AI_INTERACTIONS_FILE, entries)


def append_ai_interaction(entry: dict) -> None:
    os.makedirs(os.path.dirname(AI_INTERACTIONS_FILE), exist_ok=True)
    with open(AI_INTERACTIONS_FILE, "a", encoding="utf-8") as f:
        f.write(json.dumps(entry, ensure_ascii=False) + "\n")


# ─── Phase 4: AI Pool Management ───────────────────────────────────────────────
def get_ai_pool_state() -> dict:
    """Get current AI pool state."""
    return load_json(AI_POOL_FILE, {
        "ai_pool_balance": 0.0,
        "total_music_tips": 0.0,
        "total_ai_distributed": 0.0,
        "last_distribution_time": None,
        "total_music_tips_count": 0,
        "total_ai_rewards_count": 0
    })


def save_ai_pool_state(pool_state: dict):
    """Save AI pool state (master only)."""
    save_json(AI_POOL_FILE, pool_state)


def credit_ai_pool(amount: float, music_tip_amount: float = 0):
    """Add THR to the AI pool (called when music tips are received)."""
    if READ_ONLY or NODE_ROLE != "master":
        logger.warning(f"[AI_POOL] Skipping credit on {NODE_ROLE} node")
        return

    pool = get_ai_pool_state()
    pool["ai_pool_balance"] = round(float(pool.get("ai_pool_balance", 0)) + amount, 6)
    if music_tip_amount > 0:
        pool["total_music_tips"] = round(float(pool.get("total_music_tips", 0)) + music_tip_amount, 6)
        pool["total_music_tips_count"] = int(pool.get("total_music_tips_count", 0)) + 1

    save_json(AI_POOL_FILE, pool)
    logger.info(f"[AI_POOL] Added {amount} THR from music tip (total pool: {pool['ai_pool_balance']} THR)")


def _debit_ai_pool(amount: float) -> bool:
    """Deduct from AI pool balance. Returns True if successful."""
    if READ_ONLY or NODE_ROLE != "master":
        return False

    pool = get_ai_pool_state()
    balance = float(pool.get("ai_pool_balance", 0))
    if balance < amount:
        return False

    pool["ai_pool_balance"] = round(balance - amount, 6)
    pool["total_ai_distributed"] = round(float(pool.get("total_ai_distributed", 0)) + amount, 6)
    pool["last_distribution_time"] = time.strftime("%Y-%m-%d %H:%M:%S UTC", time.gmtime())
    pool["total_ai_rewards_count"] = int(pool.get("total_ai_rewards_count", 0)) + 1
    save_json(AI_POOL_FILE, pool)
    return True


def _distribute_ai_pool_to_address(address: str, amount: float, category: str, details: dict = None) -> str:
    """
    Credit an address from the AI pool and create an ai_reward transaction.
    Returns the tx_id.
    """
    if amount <= 0:
        return None

    # Debit from pool first
    if not _debit_ai_pool(amount):
        logger.warning(f"[AI_POOL] Insufficient balance to distribute {amount} THR")
        return None

    # Credit wallet
    ledger = load_json(LEDGER_FILE, {})
    ledger[address] = round(float(ledger.get(address, 0)) + amount, 6)
    save_json(LEDGER_FILE, ledger)

    # Create ai_reward transaction
    chain = load_json(CHAIN_FILE, [])
    tx_id = f"AI-REWARD-{int(time.time())}-{secrets.token_hex(4)}"
    tx = {
        "type": "ai_reward",
        "to": address,
        "amount": amount,
        "category": category,  # "mining" or "iot_telemetry"
        "timestamp": time.strftime("%Y-%m-%d %H:%M:%S UTC", time.gmtime()),
        "tx_id": tx_id,
        "status": "confirmed"
    }
    if details:
        tx["details"] = details
    chain.append(tx)
    save_json(CHAIN_FILE, chain)

    logger.info(f"[AI_POOL] Distributed {amount} THR to {address} (category: {category})")
    return tx_id


# ─── Phase 5: Network Pool Management (Music Telemetry 10%) ─────────────────────
def get_network_pool_state() -> dict:
    """Get current network pool state."""
    return load_json(NETWORK_POOL_FILE, {
        "network_pool_balance": 0.0,
        "total_music_contributions": 0.0,
        "total_distributed_to_nodes": 0.0,
        "last_distribution_time": None,
        "distribution_count": 0,
        "active_validators": []
    })


def save_network_pool_state(pool_state: dict):
    """Save network pool state (master only)."""
    save_json(NETWORK_POOL_FILE, pool_state)


def credit_network_pool(amount: float, source: str = "music_telemetry"):
    """Add THR to the network pool (from music plays/tips)."""
    if READ_ONLY or NODE_ROLE != "master":
        logger.warning(f"[NETWORK_POOL] Skipping credit on {NODE_ROLE} node")
        return

    pool = get_network_pool_state()
    pool["network_pool_balance"] = round(float(pool.get("network_pool_balance", 0)) + amount, 6)
    pool["total_music_contributions"] = round(float(pool.get("total_music_contributions", 0)) + amount, 6)
    save_network_pool_state(pool)
    logger.info(f"[NETWORK_POOL] Added {amount} THR from {source} (total pool: {pool['network_pool_balance']} THR)")


def _distribute_network_reward(validator_address: str, amount: float, reason: str = "network_validation") -> str:
    """Distribute network pool rewards to validators/nodes."""
    if READ_ONLY or NODE_ROLE != "master":
        return None
    if amount <= 0:
        return None

    pool = get_network_pool_state()
    balance = float(pool.get("network_pool_balance", 0))
    if balance < amount:
        logger.warning(f"[NETWORK_POOL] Insufficient balance ({balance}) for {amount} THR distribution")
        return None

    # Debit pool
    pool["network_pool_balance"] = round(balance - amount, 6)
    pool["total_distributed_to_nodes"] = round(float(pool.get("total_distributed_to_nodes", 0)) + amount, 6)
    pool["last_distribution_time"] = time.strftime("%Y-%m-%d %H:%M:%S UTC", time.gmtime())
    pool["distribution_count"] = int(pool.get("distribution_count", 0)) + 1
    save_network_pool_state(pool)

    # Credit validator wallet
    ledger = load_json(LEDGER_FILE, {})
    ledger[validator_address] = round(float(ledger.get(validator_address, 0)) + amount, 6)
    save_json(LEDGER_FILE, ledger)

    # Record transaction
    chain = load_json(CHAIN_FILE, [])
    tx_id = f"NET-REWARD-{int(time.time())}-{secrets.token_hex(4)}"
    tx = {
        "type": "network_reward",
        "to": validator_address,
        "amount": amount,
        "reason": reason,
        "timestamp": time.strftime("%Y-%m-%d %H:%M:%S UTC", time.gmtime()),
        "tx_id": tx_id,
        "status": "confirmed"
    }
    chain.append(tx)
    save_json(CHAIN_FILE, chain)

    logger.info(f"[NETWORK_POOL] Distributed {amount} THR to {validator_address} (reason: {reason})")
    return tx_id


