def canonical_media_url(url: str | None) -> str:
    if not url:
        return ""

    u = url.strip()

    if u.startswith("http://") or u.startswith("https://"):
        try:
            parsed = urlparse(u)
            u = parsed.path
        except Exception:
            return u

    if u.startswith("/static/nft_images/"):
        fname = u.split("/")[-1]
        return f"/media/nft_images/{fname}"

    if u.startswith("/static/token_logos/"):
        fname = u.split("/")[-1]
        return f"/media/token_logos/{fname}"

    if u.startswith("/media/"):
        return u

    if u.startswith("media/"):
        return "/" + u

    if u.startswith(("token_logos/", "nft_images/", "tracks/", "covers/")):
        return "/media/" + u

    return u


def normalize_media_url(url: str | None) -> str:
    if not url:
        return ""

    value = url.strip()

    value = re.sub(r"^https?://(localhost|127\.0\.0\.1|0\.0\.0\.0)(:\d+)?", "", value, flags=re.IGNORECASE)
    for origin in ("https://thrchain.vercel.app", "https://thrchain.up.railway.app"):
        if value.lower().startswith(origin):
            value = value[len(origin):]

    if value.startswith("http://") or value.startswith("https://"):
        try:
            parsed = urlparse(value)
            value = parsed.path or ""
        except Exception:
            return value

    value = re.sub(r"/{2,}", "/", value)

    if value.startswith("/static/nft_images/"):
        return value.replace("/static/nft_images/", "/media/nft_images/")

    if value.startswith("/static/token_logos/"):
        return value.replace("/static/token_logos/", "/media/token_logos/")

    if value.startswith("/media/static/"):
        return value.replace("/media/static/", "/static/")

    if value.startswith("/media/") or value.startswith("/static/"):
        return value

    if value.startswith("media/") or value.startswith("static/"):
        return f"/{value}"

    for marker in ("/media/", "/static/"):
        idx = value.find(marker)
        if idx != -1:
            return value[idx:]

    return value


def normalize_image_url(url: str | None) -> str | None:
    if not url:
        return None
    # Strip localhost URLs for production safety
    value = re.sub(r"^https?://localhost:\d+", "", url, flags=re.IGNORECASE)
    if value.startswith("http"):
        return value
    if value.startswith("/media/"):
        return f"{MEDIA_URL.rstrip('/')}{value}"
    return f"{ASSET_CDN_BASE}/{value.lstrip('/')}"


def get_all_tokens():
    """Centralized catalog that returns base + custom tokens."""
    catalog_map: dict[str, dict] = {}

    def _merge_token(entry: dict, source: str):
        if not isinstance(entry, dict):
            return
        sym = (entry.get("symbol") or "").upper()
        if not sym:
            return
        merged = catalog_map.get(sym, {})
        merged.update(entry)
        merged["symbol"] = sym
        merged.setdefault("type", source)
        catalog_map[sym] = merged

    for base in _base_token_catalog():
        _merge_token(base, base.get("type", "base"))

    for t in load_tokens():
        logo_path = t.get("logo_path") or t.get("logo")
        if logo_path:
            t["logo_url"] = url_for("media", filename=logo_path, _external=False)
        _merge_token(t, t.get("type", "custom"))

    for symbol, meta in load_custom_tokens().items():
        logo_path = meta.get("logo_path") or meta.get("logo")
        _merge_token(
            {
                "symbol": symbol,
                "name": meta.get("name", symbol),
                "decimals": meta.get("decimals", 6),
                "logo_url": url_for("media", filename=logo_path, _external=False) if logo_path else None,
                "total_supply": meta.get("total_supply") or meta.get("initial_supply"),
                "type": meta.get("type", "experimental"),
                "token_id": meta.get("id"),
                "creator": meta.get("creator") or meta.get("owner"),
                "created_at": meta.get("created_at"),
            },
            meta.get("source", "experimental"),
        )

    catalog: list[dict] = []
    for sym, meta in catalog_map.items():
        tok = meta.copy()
        try:
            tok["decimals"] = int(tok.get("decimals", 6))
        except Exception:
            tok["decimals"] = 6
        logo_url = tok.get("logo_url") or tok.get("logo")
        tok["logo_url"] = normalize_image_url(logo_url)
        catalog.append(tok)

    catalog.sort(key=lambda t: t.get("symbol"))
    return catalog


def get_balance_from_store(wallet: str, ledger_type: str, default: float = 0.0) -> float:
    if not wallet:
        return default
    if USE_SQLITE_LEDGER:
        with _get_ledger_db_connection() as conn:
            row = conn.execute(
                "SELECT balance FROM balances WHERE ledger_type = ? AND address = ?",
                (ledger_type, wallet),
            ).fetchone()
        if row:
            return float(row["balance"])
        return default
    ledger_path = {
        "thr": LEDGER_FILE,
        "wbtc": WBTC_LEDGER_FILE,
        "l2e": L2E_LEDGER_FILE,
    }.get(ledger_type)
    if not ledger_path:
        return default
    ledger = load_json(ledger_path, {})
    return float(ledger.get(wallet, default))


