def calculate_dynamic_fee(amount: float) -> float:
    """
    Calculates dynamic burn fee based on transaction amount.
    Higher amounts = Lower fee percentage (incentivizes larger transactions)

    Fee Tiers:
    - 0-10 THR:     0.5% (0.005)
    - 10-100 THR:   0.3% (0.003)
    - 100-1000 THR: 0.15% (0.0015)
    - 1000+ THR:    0.05% (0.0005)
    """
    if amount >= 1000:
        fee_rate = 0.0005  # 0.05%
    elif amount >= 100:
        fee_rate = 0.0015  # 0.15%
    elif amount >= 10:
        fee_rate = 0.003   # 0.3%
    else:
        fee_rate = 0.005   # 0.5%

    fee = amount * fee_rate
    return round(max(MIN_FEE, fee), 6)

def calculate_fixed_burn_fee(amount: float, speed: str = "fast") -> float:
    """Calculate the fixed burn fee for THR sends."""
    if speed == "slow":
        fee_rate = 0.0009  # 0.09%
    else:
        fee_rate = FEE_RATE  # fixed 0.5%
    fee = amount * fee_rate
    return round(max(MIN_FEE, fee), 6)


def split_and_credit_fee(fee: float, source: str = "transfer") -> dict:
    """
    Split a network fee: 50% burned (deflation), 50% credited to AI Agent wallet.
    The AI Agent wallet uses its balance to fund IoT miner rewards in blocks.
    Returns dict with amounts for logging.
    """
    agent_share = round(fee * FEE_AGENT_SHARE, 6)
    burn_share = round(fee - agent_share, 6)  # remainder to avoid rounding loss

    if agent_share > 0:
        ledger = load_json(LEDGER_FILE, {})
        ledger[AI_WALLET_ADDRESS] = round(float(ledger.get(AI_WALLET_ADDRESS, 0)) + agent_share, 6)
        save_json(LEDGER_FILE, ledger)
        logger.info(f"[FEE_SPLIT] {fee} THR fee from {source}: {agent_share} → AI Agent, {burn_share} → burned")

    return {"fee_total": fee, "agent_share": agent_share, "burn_share": burn_share, "source": source}

# ─── Input Validation Helpers ───────────────────────────────────────────

def generate_thr_address(btc_address: str, timestamp: str = None) -> str:
    """
    Generate a deterministic THR address from BTC address.
    Format: THR + 40 hex characters
    """
    if timestamp is None:
        timestamp = str(int(time.time() * 1000))

    # Combine BTC address with timestamp for deterministic generation
    seed = f"{btc_address}:{timestamp}:thronos"
    # Double SHA256 for security
    hash1 = hashlib.sha256(seed.encode()).digest()
    hash2 = hashlib.sha256(hash1).hexdigest()

    # Take first 40 characters of the hex hash
    return f"THR{hash2[:40]}"

def validate_thr_address(address: str) -> bool:
    """
    Validate THR address format.
    Expected format: Starts with 'THR' followed by 40 hex characters.
    Example: THR1234567890abcdef1234567890abcdef12345678
    """
    if not address or not isinstance(address, str):
        return False

    # Remove whitespace
    address = address.strip()

    # Check format: THR + 40 hex chars
    if not address.startswith("THR"):
        return False

    hex_part = address[3:]
    if len(hex_part) != 40:
        return False

    # Check if hex_part contains only valid hex characters
    try:
        int(hex_part, 16)
        return True
    except ValueError:
        return False

def validate_amount(amount, min_amount=0.000001, max_amount=21000001) -> tuple[bool, str]:
    """
    Validate transaction amount.
    Returns: (is_valid, error_message)
    """
    try:
        amt = float(amount)
    except (ValueError, TypeError):
        return False, "Invalid amount format"

    if amt <= 0:
        return False, "Amount must be positive"

    if amt < min_amount:
        return False, f"Amount must be at least {min_amount} THR"

    if amt > max_amount:
        return False, f"Amount exceeds maximum ({max_amount} THR)"

    return True, ""

def validate_btc_address(address: str) -> bool:
    """
    Basic BTC address validation.
    Checks common formats: Legacy (1...), P2SH (3...), Bech32 (bc1...)
    """
    if not address or not isinstance(address, str):
        return False

    address = address.strip()

    # Legacy P2PKH (starts with 1)
    if address.startswith("1") and 26 <= len(address) <= 35:
        return True

    # --- Wallet required for Architect (THR payment) ---
    if not wallet:
        return jsonify(
            error="Wallet required. Architect charges in THR based on data volume.",
            status="no_wallet"
        ), 400

    # Load blueprint
    bp_path = os.path.join(DATA_DIR, "ai_blueprints", blueprint)
    if not os.path.exists(bp_path):
        # Fallback: try to find it in the list if passed as name only
        bp_dir = os.path.join(DATA_DIR, "ai_blueprints")
        found = False
        if os.path.exists(bp_dir):
            for f in os.listdir(bp_dir):
                if f == blueprint:
                    bp_path = os.path.join(bp_dir, f)
                    found = True
                    break
        if not found:
             return jsonify(error="Blueprint not found"), 404

    # Bech32 (starts with bc1)
    if address.startswith("bc1") and 42 <= len(address) <= 62:
        return True

    return False

# -------------------------------------------------------------------------
# Course registry helpers for Learn‑to‑Earn
#
# Courses are persisted in a simple JSON file under ``COURSES_FILE``.
# Each course is represented as a dictionary with the following keys:
#   id: unique identifier (UUID string)
#   title: human‑readable name
#   teacher: THR address of the instructor
#   price_thr: cost in THR tokens to enroll (float)
#   reward_l2e: L2E token reward for completion (float)
#   students: list of THR addresses currently enrolled
#   completed: list of THR addresses who have completed the course
#
# These helpers load and save the course list.

def load_courses():
    return load_json(COURSES_FILE, [])

def save_courses(courses):
    save_json(COURSES_FILE, courses)


    # --- Calculate THR cost based on data volume ---
    # Price: 0.001 THR per KB of generated code
    total_bytes = sum(f.get("size", 0) for f in (files or []))
    total_kb = total_bytes / 1024.0

    # Minimum charge: 0.1 THR, then 0.001 THR/KB
    thr_cost = max(0.1, round(total_kb * 0.001, 6))

    # --- Check THR balance ---
    ledger = load_json(LEDGER_FILE, {})
    user_balance = float(ledger.get(wallet, 0.0))

    if user_balance < thr_cost:
        return jsonify(
            error=f"Insufficient THR balance. Cost: {thr_cost} THR, Balance: {user_balance} THR",
            status="insufficient_funds",
            cost=thr_cost,
            balance=user_balance
        ), 402

    # --- Deduct THR and credit AI_WALLET_ADDRESS ---
    AI_WALLET = os.getenv("AI_WALLET_ADDRESS", "THR_AI_SERVICES_WALLET_00001")
    ledger[wallet] = round(user_balance - thr_cost, 6)
    ai_wallet_balance = float(ledger.get(AI_WALLET, 0.0))
    ledger[AI_WALLET] = round(ai_wallet_balance + thr_cost, 6)
    save_json(LEDGER_FILE, ledger)

    # --- Award T2E credits (inverse of THR payment!) ---
    # Philosophy: User pays THR, gets T2E credits in exchange
    # T2E credits increase with wallet's project count (multiplier)

    # Load wallet's project history
    t2e_history_file = os.path.join(DATA_DIR, "architect_t2e_history.json")
    t2e_history = load_json(t2e_history_file, {})

    wallet_history = t2e_history.get(wallet, {
        "projects_completed": 0,
        "total_t2e_earned": 0.0,
        "total_thr_spent": 0.0
    })

    # Calculate T2E multiplier based on projects completed
    projects_completed = wallet_history.get("projects_completed", 0)
    if projects_completed == 0:
        multiplier = 1.0
    elif projects_completed < 5:
        multiplier = 1.0 + (projects_completed * 0.2)  # 1.2, 1.4, 1.6, 1.8
    elif projects_completed < 10:
        multiplier = 2.0 + ((projects_completed - 5) * 0.2)  # 2.0-2.8
    else:
        multiplier = 3.0  # Cap at 3x for experienced users

    # Calculate T2E reward: base on data volume + multiplier
    base_t2e = round(total_kb * 0.01, 2)  # 0.01 T2E per KB
    total_t2e = round(base_t2e * multiplier, 2)

    # Award T2E to wallet (separate T2E balance tracking)
    t2e_balances_file = os.path.join(DATA_DIR, "t2e_balances.json")
    t2e_balances = load_json(t2e_balances_file, {})
    current_t2e = float(t2e_balances.get(wallet, 0.0))
    t2e_balances[wallet] = round(current_t2e + total_t2e, 6)
    save_json(t2e_balances_file, t2e_balances)

    # Update wallet history
    wallet_history["projects_completed"] = projects_completed + 1
    wallet_history["total_t2e_earned"] = round(wallet_history.get("total_t2e_earned", 0.0) + total_t2e, 6)
    wallet_history["total_thr_spent"] = round(wallet_history.get("total_thr_spent", 0.0) + thr_cost, 6)
    t2e_history[wallet] = wallet_history
    save_json(t2e_history_file, t2e_history)

    # --- Create blockchain transaction ---
    chain = load_json(CHAIN_FILE, [])
    tx = {
        "type": "architect_service",
        "from": wallet,
        "to": AI_WALLET,
        "amount": thr_cost,
        "fee": 0.0,
        "timestamp": datetime.datetime.utcnow().isoformat() + "Z",
        "blueprint": blueprint,
        "files_count": len(files or []),
        "total_bytes": total_bytes,
        "session_id": session_id or "none"
    }
    chain.append(tx)
    save_json(CHAIN_FILE, chain)
    update_last_block(tx, is_block=False)

    print(f"🏗️  Architect: {wallet} → {thr_cost} THR | +{total_t2e} T2E ({multiplier:.1f}x, {projects_completed + 1} projects)")

    return jsonify({
        "status": status,
        "quantum_key": quantum_key,
        "blueprint": blueprint,
        "response": cleaned,
        "files": [
            {
                "filename": f.get("filename"),
                "size": f.get("size")
            } for f in (files or [])
        ],
        "session_id": session_id,
        "cost_thr": thr_cost,
        "earned_t2e": total_t2e,
        "t2e_multiplier": round(multiplier, 2),
        "projects_completed": projects_completed + 1,
        "total_kb": round(total_kb, 2),
        "files_count": len(files or []),
        "redirect_to_chat": True  # Signal to redirect to chat.html for further development
    }), 200


