def load_ai_packs():
    """Διαβάζει τα διαθέσιμα packs από αρχείο, αλλιώς επιστρέφει τα default."""
    data = load_json(AI_PACKS_FILE, None)
    if isinstance(data, list) and data:
        return data
    return AI_DEFAULT_PACKS


def save_ai_packs(packs):
    """Αν θες κάποια στιγμή να αλλάζεις δυναμικά τα packs."""
    save_json(AI_PACKS_FILE, packs)


def load_ai_credits_ledger():
    return load_json(AI_CREDITS_LEDGER_FILE, [])


def save_ai_credits_ledger(entries):
    save_json(AI_CREDITS_LEDGER_FILE, entries)


def append_ai_credits_ledger(wallet: str, delta: int, reason: str, before: int, after: int, metadata: dict | None = None):
    try:
        ledger = load_ai_credits_ledger()
        if not isinstance(ledger, list):
            ledger = []
        entry = {
            "id": f"acl-{int(time.time()*1000)}-{secrets.token_hex(4)}",
            "wallet": wallet,
            "delta": int(delta or 0),
            "reason": (reason or "adjust").strip().lower(),
            "balance_before": int(before or 0),
            "balance_after": int(after or 0),
            "unit": "credits",
            "timestamp": time.strftime("%Y-%m-%d %H:%M:%S UTC", time.gmtime()),
            "metadata": metadata or {},
        }
        ledger.append(entry)
        save_ai_credits_ledger(ledger[-5000:])
    except Exception:
        logger.exception("[AI_CREDITS] failed to append ledger entry")


def load_ai_credits():
    """wallet -> σύνολο credits"""
    return load_json(AI_CREDITS_FILE, {})


def save_ai_credits(credits):
    save_json(AI_CREDITS_FILE, credits)


def get_ai_credits(wallet: str) -> int:
    wallet = (wallet or "").strip()
    if not wallet:
        return 0
    ledger_balance = get_ai_credits_from_ledger(wallet)
    if ledger_balance is not None:
        return max(0, int(ledger_balance))

    credits_map = load_ai_credits()
    try:
        val = int(credits_map.get(wallet, 0) or 0)
    except (TypeError, ValueError):
        val = 0
    return max(0, val)


def get_ai_credits_from_ledger(wallet: str) -> int | None:
    wallet = (wallet or "").strip()
    if not wallet:
        return None
    try:
        ledger = load_ai_credits_ledger()
    except Exception:
        return None
    if not isinstance(ledger, list):
        return None
    for entry in reversed(ledger):
        if not isinstance(entry, dict):
            continue
        if (entry.get("wallet") or "").strip() != wallet:
            continue
        if entry.get("balance_after") is not None:
            try:
                return max(0, int(entry.get("balance_after") or 0))
            except Exception:
                return 0
    return None


def _wallet_history_credits_fallback(wallet: str) -> int | None:
    """Best-effort fallback from wallet history summary fields."""
    try:
        history = _build_wallet_history(wallet, "", limit=1, cursor=0)
        summary = history.get("summary") if isinstance(history, dict) else {}
        if not isinstance(summary, dict):
            return None
        for key in ("ai_credits", "credits"):
            value = summary.get(key)
            if value is None:
                continue
            try:
                return max(0, int(value))
            except Exception:
                continue
    except Exception:
        return None
    return None


def get_available_ai_credits(wallet: str) -> int:
    """Master-side AI credits: ledger-first with summary/map fallback."""
    wallet = (wallet or "").strip()
    if not wallet:
        return 0
    if is_ai_core():
        return 0
    try:
        ledger_balance = get_ai_credits_from_ledger(wallet)
        if ledger_balance is not None:
            return max(0, int(ledger_balance))
    except Exception:
        logger.exception("[AI_CREDITS] failed ledger-based balance lookup")

    summary_balance = _wallet_history_credits_fallback(wallet)
    if summary_balance is not None:
        return summary_balance
    return max(0, get_ai_credits(wallet))


def add_ai_credits(wallet: str, delta: int, reason: str = "", metadata: dict | None = None) -> int:
    wallet = (wallet or "").strip()
    if not wallet:
        return 0
    with _AI_CREDITS_LOCK:
        credits_map = load_ai_credits()
        before = get_ai_credits(wallet)
        after = max(0, before + int(delta or 0))
        credits_map[wallet] = after
        save_ai_credits(credits_map)
    normalized_reason = (reason or "adjust").strip().lower()
    if normalized_reason == "chat_message":
        normalized_reason = "chat_usage"
    logger.info("[AI_CREDITS] wallet=%s op=%s cost=%s before=%s after=%s", wallet, normalized_reason, abs(int(delta or 0)), before, after)
    append_ai_credits_ledger(wallet, int(delta or 0), normalized_reason, before, after, metadata=metadata)
    return after


def require_ai_credits(wallet: str, cost: int) -> bool:
    wallet = (wallet or "").strip()
    if not wallet:
        return False
    return get_ai_credits(wallet) >= max(0, int(cost or 0))


def debit_ai_credits(
    wallet: str,
    cost: int | None = None,
    reason: str = "chat_message",
    *,
    delta: int | None = None,
    meta: dict | None = None,
    require: bool = False,
):
    """Debit/adjust AI credits with backward-compatible return style.

    Legacy callers (`cost`) receive `(ok, balance_after)`.
    New callers (`delta`) receive `balance_after` or `None` (when require=True and insufficient).
    """
    wallet = (wallet or "").strip()
    if not wallet:
        return (False, 0) if delta is None else None

    legacy_mode = delta is None
    if delta is None:
        amount = max(0, int(cost or 0))
        delta = -amount
    try:
        delta_i = int(delta or 0)
    except Exception:
        delta_i = 0

    before = get_available_ai_credits(wallet) if not is_ai_core() else get_ai_credits(wallet)
    after = max(0, before + delta_i)

    if require and (before + delta_i) < 0:
        logger.info("[AI_CREDITS] wallet=%s op=%s delta=%s before=%s after=%s", wallet, reason, delta_i, before, before)
        return (False, before) if legacy_mode else None

    with _AI_CREDITS_LOCK:
        credits_map = load_ai_credits()
        credits_map[wallet] = after
        save_ai_credits(credits_map)

    normalized_reason = (reason or "adjust").strip().lower()
    if normalized_reason == "chat_message":
        normalized_reason = "chat_usage"

    logger.info("[AI_CREDITS] wallet=%s op=%s delta=%s before=%s after=%s", wallet, normalized_reason, delta_i, before, after)
    append_ai_credits_ledger(wallet, delta_i, normalized_reason, before, after, metadata=meta)

    return (True, after) if legacy_mode else after


def _default_model_id():
    """Return the preferred default model id from the registry (or 'auto')."""

    try:
        default_model = get_default_model()
        return default_model.id if default_model else "auto"
    except Exception:
        return "auto"


def _normalized_ai_mode() -> str:
    raw_mode = (os.getenv("THRONOS_AI_MODE") or "all").lower()
    if raw_mode in ("", "router", "auto", "hybrid", "all", "proxy", "core"):
        return "all"
    if raw_mode == "openai_only":
        return "openai"
    return raw_mode


def _allowed_providers() -> set[str]:
    raw = os.getenv("THR_ALLOWED_PROVIDERS", "")
    if not raw.strip():
        return {"openai", "offline"}
    return {p.strip().lower() for p in raw.split(",") if p.strip()}


def _is_provider_allowed(provider: str) -> bool:
    providers = _allowed_providers()
    key = (provider or "").strip().lower()
    mapping = {
        "openai": "openai",
        "anthropic": "anthropic",
        "gemini": "gemini",
        "google": "gemini",
        "local": "offline",
        "offline_corpus": "offline",
        "thrai": "thrai",
        "thronos": "thrai",
    }
    normalized = mapping.get(key, key)
    return normalized in providers


def _select_callable_model(model_id: str | None, session_type: str | None = None):
    """Return a callable model id (or error response) respecting mode/provider availability."""

    provider_status = get_provider_status()
    normalized_mode = _normalized_ai_mode()
    catalog = _build_ai_model_catalog()
    callable_ids = [m.get("id") for m in catalog if m.get("enabled") and m.get("id") not in {"auto"}]

    default_model_id = _default_model_id()
    if default_model_id not in callable_ids and callable_ids:
        default_model_id = callable_ids[0]

    requested_raw = (model_id or "").strip()
    requested = requested_raw or default_model_id or "auto"
    requested_aliases = {
        "claude-opus": "claude-opus-4-6",
        "claude-4-opus": "claude-opus-4-6",
        "claude-4.6-opus": "claude-opus-4-6",
        "claude-3.5-sonnet": "claude-sonnet-4-5-20250929",
        "claude-3.5-haiku": "claude-haiku-4-5-20251001",
        "claude-3-5-sonnet": "claude-3-5-sonnet-latest",
        "claude-3-5-haiku": "claude-3-5-haiku-latest",
        "claude-4.5-sonnet": "claude-sonnet-4-5-20250929",
        "claude-4.5-haiku": "claude-haiku-4-5-20251001",
    }
    requested = requested_aliases.get(requested, requested)
    catalog_by_id = {m.get("id"): m for m in catalog if isinstance(m, dict) and m.get("id")}

    if requested == "auto" and callable_ids:
        heuristic_order = [
            "gpt-4.1-mini",
            "o3-mini",
            "claude-sonnet-4-5-20250929",
            "claude-3-5-sonnet-latest",
            "gemini-2.0-flash",
            "gemini-2.5-pro",
            "offline_corpus",
            "thrai",
        ]
        for candidate in heuristic_order:
            cinfo = catalog_by_id.get(candidate) or {}
            if candidate in callable_ids and _is_provider_allowed(cinfo.get("provider") or ""):
                requested = candidate
                break

    fallback_notice = None

    hard_unavailable = {"o3", "gpt-o3", "o3-pro", "gpt-o3-preview"}
    if requested in hard_unavailable:
        error_payload = {
            "ok": False,
            "error": "model_unavailable",
            "status": "model_unavailable",
            "requested_model": requested,
            "reason": "model_not_available_or_preview",
            "models": catalog,
        }
        return None, fallback_notice, (jsonify(error_payload), 200)

    requested_info = catalog_by_id.get(requested) if requested and requested != "auto" else None
    if requested_info and not _is_provider_allowed(requested_info.get("provider") or ""):
        blocked_provider = requested_info.get("provider") or "unknown"
        error_payload = {
            "ok": False,
            "error": "provider_blocked_by_mode",
            "provider": blocked_provider,
            "model_id": requested,
            "reason": "THRONOS_AI_MODE policy",
            "allowed_providers": sorted(list(_allowed_providers())),
        }
        return None, fallback_notice, (jsonify(error_payload), 200)

    if requested not in callable_ids and requested != "auto":
        error_payload = {
            "ok": False,
            "error": "model_unavailable",
            "status": "model_unavailable",
            "requested_model": requested,
            "reason": "model_not_available_or_preview",
            "models": catalog,
        }
        return None, fallback_notice, (jsonify(error_payload), 200)

    if requested in {"offline_corpus", "thrai"} and requested in callable_ids:
        return requested, fallback_notice, None

    resolved = _resolve_model(requested, normalized_mode=normalized_mode, provider_status=provider_status) if requested else None
    if resolved:
        return resolved.id, fallback_notice, None

    for mid in callable_ids:
        info = catalog_by_id.get(mid) or {}
        if not _is_provider_allowed(info.get("provider") or ""):
            continue
        resolved = _resolve_model(mid, normalized_mode=normalized_mode, provider_status=provider_status)
        if resolved:
            notice = fallback_notice or f"Model '{requested or 'auto'}' not available; using {resolved.id}"
            return resolved.id, notice, None

    # Nothing callable: return JSON error without charging
    disabled_models = []
    provider_diagnostics = {}
    for provider, models in AI_MODEL_REGISTRY.items():
        pinfo = provider_status.get(provider, {}) if isinstance(provider_status, dict) else {}
        provider_diagnostics[provider] = {
            "configured": pinfo.get("configured"),
            "library_loaded": pinfo.get("library_loaded", True),
            "has_key": pinfo.get("has_key", pinfo.get("configured")),
            "key_sources_checked": pinfo.get("key_sources_checked") or pinfo.get("checked_env"),
        }
        if not pinfo.get("configured") or pinfo.get("library_loaded") is False:
            disabled_models.extend([m.id for m in models])

    missing_keys = [p for p, info in provider_status.items() if not info.get("configured")]
    error_payload = {
        "ok": False,
        "status": "model_not_available",
        "error": "no_available_model",
        "enabled_models": callable_ids,
        "node_role": "ai_core",
        "thronos_ai_mode": "core",
        "suggested_model": default_model_id,
        "providers": provider_status,
        "provider_diagnostics": provider_diagnostics,
        "requested_model": requested,
        "mode": normalized_mode,
        "missing_keys": missing_keys,
        "disabled_models": disabled_models,
        "resolved_model": None,
        "call_attempted": False,
        "session_type": (session_type or "unknown"),
    }
    return None, fallback_notice, (jsonify(error_payload), 200)


def _log_ai_call(meta: dict):
    """Structured AI call logging without secrets."""
    try:
        app.logger.info("ai_call_meta", extra={"ai_call": meta})
    except Exception:
        try:
            app.logger.info(f"ai_call_meta: {meta}")
        except Exception:
            pass

# ---------------------------------------------------------------------------
# Free usage counters
# ---------------------------------------------------------------------------
def load_ai_free_usage():
    """
    Load the free usage counters from disk.  The returned value is a
    dictionary mapping session identifiers to the number of demo messages
    already consumed.  If the file does not exist, an empty dictionary is
    returned.
    """
    return load_json(AI_FREE_USAGE_FILE, {})


def save_ai_free_usage(counters):
    """
    Persist the free usage counters back to disk.  Accepts a dict mapping
    session_id strings to integers.  The file is stored in JSON format.
    """
    save_json(AI_FREE_USAGE_FILE, counters)

def load_ai_sessions():

    """Load AI sessions list (robust to legacy formats)."""
    def _now():
        return datetime.utcnow().isoformat(timespec="seconds") + "Z"

    data = load_json(AI_SESSIONS_FILE, default=[])
    if isinstance(data, dict):
        if isinstance(data.get("sessions"), list):
            data = data["sessions"]
        else:
            merged = []
            for w, lst in data.items():
                if isinstance(lst, list):
                    for s in lst:
                        if isinstance(s, dict) and "wallet" not in s:
                            s = {**s, "wallet": w}
                        merged.append(s)
            data = merged

    if not isinstance(data, list):
        data = []

    out = []
    for s in data:
        if not isinstance(s, dict):
            continue
        sid = s.get("id") or s.get("session_id") or str(uuid.uuid4())
        wallet = (s.get("wallet") or s.get("thr_wallet") or "").strip()
        created = s.get("created_at") or s.get("created") or _now()
        updated = s.get("updated_at") or s.get("updated") or created
        meta = s.get("meta") if isinstance(s.get("meta"), dict) else {}
        selected_model_id = meta.get("selected_model_id") or s.get("selected_model_id") or _default_model_id()
        session_type = (meta.get("session_type") or s.get("session_type") or "chat").lower()
        if session_type not in {"chat", "architect", "codex", "train", "admin"}:
            session_type = "chat"
        billing_mode_locked = (meta.get("billing_mode_locked") or s.get("billing_mode_locked") or _session_billing_mode(session_type)).lower()
        meta["session_type"] = session_type
        meta["billing_mode_locked"] = billing_mode_locked
        out.append({
            "id": sid,
            "wallet": wallet,
            "title": s.get("title") or s.get("name") or "New Chat",
            "created_at": created,
            "updated_at": updated,
            "archived": bool(s.get("archived", False)),
            "model": s.get("model") or s.get("ai_model") or None,
            "message_count": int(s.get("message_count") or s.get("messages_count") or 0),
            "meta": meta,
            "selected_model_id": selected_model_id,
            "session_type": session_type,
            "billing_mode_locked": billing_mode_locked,
        })
    return out

def save_ai_sessions(sessions):

    # persist as a plain list for simplicity
    if not isinstance(sessions, list):
        sessions = []
    save_json(AI_SESSIONS_FILE, sessions)


def _session_billing_mode(session_type: str) -> str:
    chat_billing = (os.getenv("CHAT_BILLING_MODE") or "credits").strip().lower() or "credits"
    architect_billing = (os.getenv("ARCHITECT_BILLING_MODE") or "thr").strip().lower() or "thr"
    st = (session_type or "chat").strip().lower()
    if st == "admin":
        return "free"
    if st == "architect":
        return architect_billing
    if st == "train":
        return "none"
    if st == "codex":
        return chat_billing
    return chat_billing


def _load_billing_idempotency() -> dict:
    data = load_json(AI_SESSION_BILLING_FILE, {})
    return data if isinstance(data, dict) else {}


def _save_billing_idempotency(data: dict):
    save_json(AI_SESSION_BILLING_FILE, data if isinstance(data, dict) else {})


def _session_by_id(session_id: str) -> dict | None:
    if not session_id:
        return None
    for s in load_ai_sessions():
        if s.get("id") == session_id:
            return s
    return None


def _create_session_record(session_type: str, wallet: str = "", title: str | None = None, session_id: str | None = None) -> dict:
    st = (session_type or "chat").strip().lower()
    if st not in {"chat", "architect", "codex", "train", "admin"}:
        st = "chat"
    now = datetime.utcnow().isoformat(timespec="seconds") + "Z"
    sid = (session_id or "").strip() or uuid.uuid4().hex
    billing_mode = _session_billing_mode(st)
    existing = _session_by_id(sid)
    if existing:
        return existing

    session = {
        "id": sid,
        "wallet": (wallet or "").strip(),
        "title": title or ("Admin Operator Session" if st == "admin" else ("Architect Session" if st == "architect" else ("Training Session" if st == "train" else "New Chat"))),
        "created_at": now,
        "updated_at": now,
        "archived": False,
        "model": None,
        "message_count": 0,
        "meta": {
            "session_type": st,
            "billing_mode_locked": billing_mode,
            "selected_model_id": _default_model_id(),
            "origin": "d3lfoi_admin" if st == "admin" else "user",
        },
        "selected_model_id": _default_model_id(),
        "session_type": st,
        "billing_mode_locked": billing_mode,
    }
    sessions = load_ai_sessions()
    sessions.append(session)
    save_ai_sessions(sessions)
    ensure_session_messages_file(sid)
    return session


def _session_messages_path(session_id: str) -> str:
    safe_id = str(session_id or "").replace("/", "_")
    return os.path.join(AI_SESSIONS_DIR, f"{safe_id}.json")


def ensure_session_messages_file(session_id: str):
    if not session_id:
        return
    path = _session_messages_path(session_id)
    os.makedirs(AI_SESSIONS_DIR, exist_ok=True)
    if not os.path.exists(path):
        save_json(path, [])


def _save_session_selected_model(session_id: str, selected_model_id: str):
    sessions = load_ai_sessions()
    updated = False
    for s in sessions:
        if s.get("id") == session_id:
            meta = s.get("meta") if isinstance(s.get("meta"), dict) else {}
            meta["selected_model_id"] = selected_model_id
            s["meta"] = meta
            s["selected_model_id"] = selected_model_id
            s["updated_at"] = datetime.utcnow().isoformat(timespec="seconds") + "Z"
            updated = True
            break
    if updated:
        save_ai_sessions(sessions)
    return updated


def _ensure_session_type(session_id: str, session_type: str):
    """Ensure a session carries the expected session_type, upgrading if needed.

    Allows type upgrades (e.g. chat → architect) so architect/T2E sessions
    can continue from existing chat sessions and earn credits back.
    Returns True if session matches or was upgraded, False only on error.
    """
    if not session_id:
        return False
    sessions = load_ai_sessions()
    changed = False
    for s in sessions:
        if s.get("id") == session_id:
            meta = s.get("meta") if isinstance(s.get("meta"), dict) else {}
            current = (s.get("session_type") or meta.get("session_type") or "chat").lower()
            if current != session_type:
                # Upgrade the session type instead of rejecting
                logger.info(
                    "session_type_upgrade",
                    extra={"session_id": session_id, "from": current, "to": session_type},
                )
                meta["session_type"] = session_type
                meta["upgraded_from"] = current
                s["meta"] = meta
                s["session_type"] = session_type
                s["billing_mode_locked"] = _session_billing_mode(session_type)
                meta["billing_mode_locked"] = _session_billing_mode(session_type)
                s["updated_at"] = datetime.utcnow().isoformat(timespec="seconds") + "Z"
                changed = True
            elif meta.get("session_type") is None:
                meta["session_type"] = session_type
                s["meta"] = meta
                s["session_type"] = session_type
                s["updated_at"] = datetime.utcnow().isoformat(timespec="seconds") + "Z"
                changed = True
            break
    if changed:
        save_ai_sessions(sessions)
    return True


def _normalize_session_selected_model(session: dict):
    """Ensure a session carries a valid selected_model_id and persist if needed."""
    if not isinstance(session, dict):
        return _default_model_id(), False

    enabled_ids = set(list_enabled_model_ids())
    default_model_id = _default_model_id()
    meta = session.get("meta") if isinstance(session.get("meta"), dict) else {}
    selected = meta.get("selected_model_id") or session.get("selected_model_id") or default_model_id

    if selected not in enabled_ids:
        selected = default_model_id
        _save_session_selected_model(session.get("id"), selected)
        meta["selected_model_id"] = selected
        session["meta"] = meta
        session["selected_model_id"] = selected
        return selected, True

    session["selected_model_id"] = selected
    meta["selected_model_id"] = selected
    session["meta"] = meta
    return selected, False


def prune_empty_sessions():
    """
    Remove sessions whose message files are missing or empty.

    Returns a summary dict: {"deleted": N, "kept": M, "errors": [...]}
    """

    result = {"deleted": 0, "kept": 0, "errors": []}
    try:
        sessions = load_ai_sessions()
    except Exception as exc:  # pragma: no cover - defensive
        return {"deleted": 0, "kept": 0, "errors": [f"load failed: {exc}"]}

    pruned = []
    now = datetime.utcnow()
    stale_hours = 168
    for session in sessions:
        sid = session.get("id") or session.get("session_id")
        if not sid:
            result["errors"].append("session missing id; skipped")
            continue

        session_type = (session.get("session_type") or (session.get("meta") or {}).get("session_type") or "chat").lower()
        if session_type != "chat":
            pruned.append(session)
            continue

        path = _session_messages_path(sid)
        try:
            if not os.path.exists(path):
                updated_at = session.get("updated_at") or session.get("created_at")
                try:
                    ts = datetime.fromisoformat(updated_at.replace("Z", "+00:00")) if updated_at else None
                except Exception:
                    ts = None
                age_hours = (now - ts).total_seconds() / 3600 if ts else 0
                if age_hours > stale_hours:
                    result["deleted"] += 1
                    continue
                ensure_session_messages_file(sid)
                pruned.append(session)
                continue

            messages = load_json(path, [])
            if not messages:
                updated_at = session.get("updated_at") or session.get("created_at")
                try:
                    ts = datetime.fromisoformat(updated_at.replace("Z", "+00:00")) if updated_at else None
                except Exception:
                    ts = None
                age_hours = (now - ts).total_seconds() / 3600 if ts else 0
                if age_hours > stale_hours:
                    try:
                        os.remove(path)
                    except FileNotFoundError:
                        pass
                    result["deleted"] += 1
                    continue
                pruned.append(session)
                continue

            pruned.append(session)
        except Exception as exc:  # pragma: no cover - defensive
            result["errors"].append(f"{sid}: {exc}")
            pruned.append(session)

    result["kept"] = len(pruned)
    save_ai_sessions(pruned)
    return result


def load_session_messages(session_id: str) -> list:
    """
    Load messages for a session, sorted by timestamp.
    FIX 3: Migrates old messages without msg_id/timestamp.
    """
    if not session_id:
        return []
    path = _session_messages_path(session_id)
    messages = load_json(path, []) or []

    # FIX 3: Migration for old sessions without msg_id/ts
    needs_save = False
    for i, msg in enumerate(messages):
        # Add msg_id if missing
        if "msg_id" not in msg:
            msg["msg_id"] = f"msg_migrated_{i}_{secrets.token_hex(4)}"
            needs_save = True

        # Add timestamp if missing (use epoch for old messages)
        if "timestamp" not in msg or not msg["timestamp"]:
            msg["timestamp"] = "1970-01-01T00:00:00Z"
            needs_save = True

        # Ensure ts shorthand exists for compatibility
        if "ts" not in msg and "timestamp" in msg:
            msg["ts"] = msg["timestamp"]
            needs_save = True

    # Save if we migrated any messages
    if needs_save:
        save_session_messages(session_id, messages)

    messages.sort(key=lambda m: m.get("timestamp", ""))
    return messages


def session_messages_exists(session_id: str) -> bool:
    """Check if a transcript file exists for the given session id."""
    if not session_id:
        return False
    path = _session_messages_path(session_id)
    return os.path.exists(path)


def save_session_messages(session_id: str, messages: list):
    """Save messages for a session."""
    if not session_id:
        return
    ensure_session_messages_file(session_id)
    path = _session_messages_path(session_id)
    save_json(path, messages)


def remove_session_from_index(session_id: str, wallet: str | None = None):
    """Remove a session from the index, optionally scoped by wallet."""
    if not session_id:
        return
    sessions = load_ai_sessions()
    new_sessions = []
    for s in sessions:
        if s.get("id") != session_id:
            new_sessions.append(s)
            continue
        if wallet and s.get("wallet") != wallet:
            new_sessions.append(s)
    if len(new_sessions) != len(sessions):
        save_ai_sessions(new_sessions)


def append_session_transcript(session_id: str, prompt: str, response: str, files, timestamp: str):
    """Persist a conversation turn to the per-session transcript file."""
    if not session_id:
        return

    path = _session_messages_path(session_id)
    os.makedirs(AI_SESSIONS_DIR, exist_ok=True)
    transcript = load_json(path, [])

    if prompt:
        transcript.append({
            "role": "user",
            "content": prompt,
            "timestamp": timestamp,
            "session_id": session_id,
        })

    if response:
        entry = {
            "role": "assistant",
            "content": response,
            "timestamp": timestamp,
            "session_id": session_id,
        }
        if files:
            entry["files"] = files
        transcript.append(entry)

    transcript = transcript[-400:]
    save_json(path, transcript)


def ensure_session_exists(session_id: str, wallet: str | None, session_type: str | None = None) -> dict:
    """
    FIX 9: Return an existing session or recreate it on disk.
    Graceful degradation - returns empty dict on errors.
    """
    if not session_id:
        return {}

    try:
        sessions = load_ai_sessions()
        for s in sessions:
            if s.get("id") == session_id:
                existing_type = (s.get("session_type") or (s.get("meta") or {}).get("session_type") or "chat").lower()
                if session_type and existing_type != session_type:
                    # Upgrade session type (e.g. chat → architect, architect → t2e)
                    # instead of rejecting — this allows architect sessions to be
                    # properly tagged for T2E credit flow.
                    logger.info(
                        "session_type_upgrade",
                        extra={"session_id": session_id, "from": existing_type, "to": session_type},
                    )
                    s["session_type"] = session_type
                    meta = s.get("meta") if isinstance(s.get("meta"), dict) else {}
                    meta["session_type"] = session_type
                    meta["upgraded_from"] = existing_type
                    s["meta"] = meta
                    existing_type = session_type
                expected_billing = _session_billing_mode(existing_type)
                meta = s.get("meta") if isinstance(s.get("meta"), dict) else {}
                changed = False
                if (s.get("billing_mode_locked") or meta.get("billing_mode_locked")) != expected_billing:
                    s["billing_mode_locked"] = expected_billing
                    meta["billing_mode_locked"] = expected_billing
                    s["meta"] = meta
                    changed = True
                if changed:
                    s["updated_at"] = datetime.utcnow().isoformat(timespec="seconds") + "Z"
                    save_ai_sessions(sessions)
                ensure_session_messages_file(session_id)
                return s

        now = datetime.utcnow().isoformat(timespec="seconds") + "Z"
        stype = (session_type or "chat").lower()
        recovered = {
            "id": session_id,
            "wallet": (wallet or "").strip(),
            "title": "Recovered Session",
            "created_at": now,
            "updated_at": now,
            "archived": False,
            "model": None,
            "message_count": 0,
            "meta": {"recovered": True, "session_type": stype, "billing_mode_locked": _session_billing_mode(stype)},
            "session_type": stype,
            "billing_mode_locked": _session_billing_mode(stype),
        }
        sessions.append(recovered)
        save_ai_sessions(sessions)
        ensure_session_messages_file(session_id)
        logger.info(f"Session recovered: {session_id} (wallet: {wallet})")
        return recovered
    except Exception as e:
        logger.error(f"Failed to ensure session {session_id}: {e}")
        return {}  # Graceful degradation


def generate_stable_session_key(wallet: str | None = None) -> str:
    """
    FIX 9: Generate stable session key.

    - If wallet provided: deterministic key based on wallet + timestamp (day)
    - If no wallet (guest): random UUID

    This ensures sessions are stable across requests for same wallet on same day.
    """
    if wallet:
        # Deterministic key: wallet + date (changes daily for privacy)
        from datetime import date
        today = date.today().isoformat()
        seed = f"{wallet}:{today}"
        # Use first 16 chars of sha256 hash
        import hashlib
        hash_hex = hashlib.sha256(seed.encode()).hexdigest()[:16]
        return f"session_{hash_hex}"
    else:
        # Guest mode: random UUID
        return str(uuid.uuid4())


def register_session(session_data: dict) -> bool:
    """
    FIX 9: Register/update a session in the canonical store.
    Wrapper around ensure_session_exists with graceful degradation.

    Args:
        session_data: {"session_id": str, "user_wallet": str | None, ...}

    Returns:
        bool: True if successful, False otherwise
    """
    try:
        session_id = session_data.get("session_id")
        if not session_id:
            return False

        wallet = session_data.get("user_wallet") or session_data.get("wallet")
        stype = session_data.get("session_type") or session_data.get("type") or "chat"
        ensure_session_exists(session_id, wallet, stype)
        return True
    except Exception as e:
        logger.error(f"Failed to register session: {e}")
        return False  # Graceful degradation


def attach_uploaded_files_to_session(session_id: str, wallet: str, files: list):
    """
    Link uploaded file metadata to a session, so the agent can see them.
    This only stores references (ids + names), not content.
    """
    wallet = (request.args.get("wallet") or "").strip()
    if not wallet:
        # Guest mode - return remaining free messages
        gid = get_or_set_guest_id()
        remaining = guest_remaining_free_messages(gid)
        resp = jsonify({"mode": "guest", "credits": remaining, "ai_credits": remaining, "max_free_messages": GUEST_MAX_FREE_MESSAGES})
        resp.set_cookie(GUEST_COOKIE_NAME, gid, max_age=GUEST_TTL_SECONDS, httponly=True, samesite="Lax")
        return resp, 200

def sha256d(data: bytes) -> bytes:
    return hashlib.sha256(hashlib.sha256(data).digest()).digest()

def target_to_bits(target: int) -> int:
    if target == 0:
        return 0
    target_hex = hex(target)[2:]
    if len(target_hex) % 2 != 0:
        target_hex = "0" + target_hex
    target_bytes = bytes.fromhex(target_hex)
    if target_bytes[0] >= 0x80:
        target_bytes = b"\\x00" + target_bytes
    exponent = len(target_bytes)
    coefficient = target_bytes[:3]
    if len(coefficient) < 3:
        coefficient = coefficient + b"\\x00" * (3 - len(coefficient))
    return (exponent << 24) | int.from_bytes(coefficient, "big")

def calculate_reward(height: int) -> float:
    """Calculate mining reward for a given block height using current halving parameters."""
    try:
        from mining_ecosystem_tokenomics import HALVING_INTERVAL, INITIAL_BLOCK_REWARD, EpochInfo
        return EpochInfo.get_reward_for_block(height)
    except (ImportError, Exception):
        # Fallback to hardcoded values if import fails
        HALVING_INTERVAL = 1_312_500
        INITIAL_BLOCK_REWARD = 8.0
        halvings = height // HALVING_INTERVAL
        if halvings > 33:  # Max 33 halvings before reward becomes negligible
            return 0.0
        return round(INITIAL_BLOCK_REWARD / (2 ** halvings), 6)

def recompute_height_offset_from_ledger():
    """
    Διαβάζει ledger + chain και βρίσκει πόσα THR έχουν εκδοθεί
    ΠΡΙΝ αρχίσουν να γράφονται blocks στο phantom_tx_chain.json.

    Το μεταφράζει σε ισοδύναμο αριθμό blocks σύμφωνα με
    το halving schedule (1.0, 0.5, 0.25, …).
    """
    global HEIGHT_OFFSET

    ledger = load_json(LEDGER_FILE, {})
    chain  = load_json(CHAIN_FILE, [])

    # Όσα blocks υπάρχουν ΗΔΗ στο chain
    blocks = [b for b in chain if isinstance(b, dict) and b.get("reward") is not None]
    minted_from_blocks = sum(float(b.get("reward", 0.0)) for b in blocks)

    # Συνολικό supply από ledger (άθροισμα όλων των διευθύνσεων)
    total_ledger = sum(float(v) for v in ledger.values())

    # Ό,τι περισσεύει το θεωρούμε "παλιό supply χωρίς blocks"
    pre_mined = max(0.0, total_ledger - minted_from_blocks)

    if pre_mined <= 0:
        HEIGHT_OFFSET = 0
        logger.info("No pre-mined supply detected. HEIGHT_OFFSET = 0")
        return

    remaining = pre_mined
    h = 0
    # Μέχρι max ~13M blocks, δεν μας νοιάζει απόδοση, είναι startup-only
    while remaining > 0 and h < 13_000_000:  # Ceiling for 5-year halving intervals
        r = calculate_reward(h)
        if r <= 0:
            break
        remaining -= r
        h += 1

    HEIGHT_OFFSET = h
    logger.info(
        f"[SUPPLY] Pre-mined ≈ {pre_mined:.6f} THR -> HEIGHT_OFFSET = {HEIGHT_OFFSET}"
    )


def compute_thr_supply_metrics(chain: list | None = None, pools: list | None = None) -> dict:
    """Compute THR supply metrics from chain events and pools."""
    if chain is None:
        chain = load_json(CHAIN_FILE, [])
    if pools is None:
        pools = load_pools()

    minted_from_blocks = sum(
        float(block.get("reward", 0.0))
        for block in chain
        if isinstance(block, dict) and block.get("reward") is not None
    )
    minted_from_admin = 0.0
    burned_from_fees = 0.0
    burned_from_events = 0.0

    for tx in chain:
        if not isinstance(tx, dict) or tx.get("reward") is not None:
            continue
        tx_type = (tx.get("type") or "").lower()
        if tx_type in {"mint", "coinbase", "reward"}:
            minted_from_admin += float(tx.get("amount", 0.0) or 0.0)
        burned_from_fees += float(tx.get("fee_burned", 0.0) or tx.get("fee", 0.0) or 0.0)
        if tx_type in {"burn", "thr_burn"}:
            burned_from_events += float(tx.get("amount", 0.0) or 0.0)
        burned_from_events += float(tx.get("burn_amount", 0.0) or tx.get("burned_thr", 0.0) or 0.0)

    burned_from_blocks = sum(
        float((block.get("reward_split") or {}).get("burn", block.get("pool_fee", 0.0)) or 0.0)
        for block in chain
        if isinstance(block, dict) and block.get("reward") is not None
    )

    minted_total_thr = minted_from_blocks + minted_from_admin
    burned_total_thr = burned_from_blocks + burned_from_fees + burned_from_events
    total_supply_thr = max(round(minted_total_thr - burned_total_thr, 6), 0.0)

    locked_in_pools_thr = 0.0
    for pool in pools:
        if not isinstance(pool, dict):
            continue
        token_a = (pool.get("token_a") or "").upper()
        token_b = (pool.get("token_b") or "").upper()
        reserves_a = float(pool.get("reserves_a", 0.0) or 0.0)
        reserves_b = float(pool.get("reserves_b", 0.0) or 0.0)
        if token_a == "THR":
            locked_in_pools_thr += reserves_a
        if token_b == "THR":
            locked_in_pools_thr += reserves_b

    other_locked = 0.0
    circulating_supply_thr = round(total_supply_thr - locked_in_pools_thr - other_locked, 6)

    return {
        "minted_total_thr": round(minted_total_thr, 6),
        "burned_total_thr": round(burned_total_thr, 6),
        "total_supply_thr": total_supply_thr,
        "locked_in_pools_thr": round(locked_in_pools_thr, 6),
        "circulating_supply_thr": circulating_supply_thr,
    }


def update_last_block(entry, is_block=True):
    """
    Γράφει last_block.json αλλά πλέον κρατά και:
    - block_count (με offset)
    - total_supply (άθροισμα ledger)
    ώστε η αρχική σελίδα να ξέρει ΠΟΣΑ block και ΠΟΣΟ supply έχουμε.
    """
    chain  = load_json(CHAIN_FILE, [])
    blocks = [b for b in chain if isinstance(b, dict) and b.get("reward") is not None]
    block_count = HEIGHT_OFFSET + len(blocks)

    supply_metrics = compute_thr_supply_metrics(chain=chain)
    total_supply = supply_metrics["total_supply_thr"]

    # Build the summary for the last block or transaction.  When
    # ``is_block`` is False (e.g. for a transaction update), we want to
    # preserve the existing block height and hash in last_block.json.  This
    # prevents the viewer/home page from incorrectly showing the last
    # transaction as the latest block.  Only ``block_count`` and
    # ``total_supply`` should be updated in that case.
    summary = {
        "height":     entry.get("height"),
        "block_hash": entry.get("block_hash") or entry.get("tx_id"),
        "timestamp":  entry.get("timestamp"),
        "thr_address": entry.get("thr_address"),
        "type": "block" if is_block else entry.get("type", "transfer"),
        "block_count": block_count,
        "total_supply": total_supply,
    }
    if not is_block:
        # Preserve the latest block information when updating due to
        # transactions or other non-block events.
        existing = load_json(LAST_BLOCK_FILE, {})
        if existing:
            summary["height"] = existing.get("height")
            summary["block_hash"] = existing.get("block_hash")
            summary["timestamp"] = existing.get("timestamp")
            summary["thr_address"] = existing.get("thr_address")
    save_json(LAST_BLOCK_FILE, summary)
    LAST_BLOCK_SNAPSHOT.clear()
    LAST_BLOCK_SNAPSHOT.update(summary)
    set_chain_meta(
        summary.get("height"),
        summary.get("block_hash"),
        summary,
    )
    LAST_HASH_CACHE.update({
        "ts": time.time(),
        "data": {
            "last_hash": summary.get("block_hash") or "0" * 64,
            "height": summary.get("height") if summary.get("height") is not None else -1,
            "timestamp": summary.get("timestamp"),
        },
    })


def get_last_block_snapshot() -> dict:
    if LAST_BLOCK_SNAPSHOT:
        return LAST_BLOCK_SNAPSHOT
    snapshot = load_json(LAST_BLOCK_FILE, {})
    if not isinstance(snapshot, dict):
        snapshot = {}
    if not snapshot or (snapshot.get("block_hash") is None and snapshot.get("height") is None):
        try:
            snapshot = _rebuild_index_from_chain()
        except Exception as exc:
            logger.error("Failed to rebuild last block snapshot: %s", exc)
    if isinstance(snapshot, dict):
        LAST_BLOCK_SNAPSHOT.update(snapshot)
        set_chain_meta(
            snapshot.get("height"),
            snapshot.get("block_hash") or snapshot.get("last_hash"),
            snapshot,
        )
    return LAST_BLOCK_SNAPSHOT

def verify_btc_payment(btc_address, min_amount=MIN_AMOUNT, require_confirmation=False):
    """Verify if a BTC address has sent payment to the vault.

    Args:
        btc_address: Source BTC address
        min_amount: Minimum BTC amount required
        require_confirmation: If True, require at least 1 confirmation

    Returns:
        (paid: bool, txns: list of transactions)
    """
    max_retries = 3
    retry_delay = 1

    for attempt in range(max_retries):
        try:
            txns = get_btc_txns(btc_address, BTC_RECEIVER)
            valid_txns = []

            for tx in txns:
                if tx.get("to") == BTC_RECEIVER and tx.get("amount_btc", 0) >= min_amount:
                    # Check confirmation requirement
                    confirmations = tx.get("confirmations", 0)
                    if require_confirmation and confirmations < 1:
                        logger.debug(f"Tx {tx.get('txid')} has {confirmations} confirmations, skipping")
                        continue
                    valid_txns.append(tx)

            if valid_txns or attempt == max_retries - 1:
                # Return if we found valid transactions or this is the last attempt
                paid = len(valid_txns) > 0
                return paid, txns

            # Retry if no transactions found (might be indexing lag)
            if attempt < max_retries - 1:
                logger.debug(f"No payment found for {btc_address}, retrying in {retry_delay}s...")
                time.sleep(retry_delay)
                retry_delay *= 2

        except Exception as e:
            logger.warning(f"Error verifying payment (attempt {attempt + 1}/{max_retries}): {e}")
            if attempt < max_retries - 1:
                time.sleep(retry_delay)
                retry_delay *= 2
            elif attempt == max_retries - 1:
                logger.error(f"Failed to verify payment after {max_retries} attempts")

    return False, []

def get_mining_target():
    blocks = get_reward_blocks()
    if len(blocks) < RETARGET_INTERVAL:
        return INITIAL_TARGET
    last_block  = blocks[-1]
    last_target = int(last_block.get("target", INITIAL_TARGET))
    if len(blocks) % RETARGET_INTERVAL != 0:
        return last_target
    start_block = blocks[-RETARGET_INTERVAL]
    try:
        t_fmt = "%Y-%m-%d %H:%M:%S UTC"
        t_end = datetime.strptime(last_block["timestamp"], t_fmt).timestamp()
        t_sta = datetime.strptime(start_block["timestamp"], t_fmt).timestamp()
    except Exception as e:
        logger.error(f"Time parse error: {e}")
        return last_target
    actual = max(1, t_end - t_sta)
    expected = RETARGET_INTERVAL * TARGET_BLOCK_TIME
    ratio = actual / expected
    ratio = 0.25 if ratio < 0.25 else (4.0 if ratio > 4.0 else ratio)
    new_target = int(last_target * ratio)
    if new_target > INITIAL_TARGET:
        new_target = INITIAL_TARGET
    return new_target


# ─── AI FILE / CORPUS HELPERS ──────────────────────
def extract_ai_files_from_text(full_text: str):
    """
    Ψάχνει για blocks τύπου:
      [[FILE:filename.ext]]
      ...περιεχόμενο...
      [[/FILE]]
    Γράφει τα αρχεία στο AI_FILES_DIR και επιστρέφει:
      files: list[ {filename, path, size} ]
      cleaned_text: text χωρίς τα raw blocks.
    """
    files = []
    cleaned_parts = []
    i = 0
    while True:
        start = full_text.find("[[FILE:", i)
        if start == -1:
            cleaned_parts.append(full_text[i:])
            break

        # ό,τι υπάρχει πριν το block
        cleaned_parts.append(full_text[i:start])

        end_name = full_text.find("]]", start)
        if end_name == -1:
            # δεν κλείνει σωστά, κρατάμε όλο το υπόλοιπο
            cleaned_parts.append(full_text[start:])
            break

        filename = full_text[start + len("[[FILE:"):end_name].strip()
        end_block = full_text.find("[[/FILE]]", end_name)
        if end_block == -1:
            cleaned_parts.append(full_text[start:])
            break

        content = full_text[end_name + 2:end_block]

        # ασφαλές όνομα αρχείου
        safe_name = filename.replace("..", "_").replace("/", "_").replace("\\", "_")
        file_path = os.path.join(AI_FILES_DIR, safe_name)
        try:
            with open(file_path, "w", encoding="utf-8") as f:
                f.write(content.strip())
            size = len(content.encode("utf-8"))
            files.append({
                "filename": safe_name,
                "path": file_path,
                "size": size,
            })
            cleaned_parts.append(f"\\n[AI file generated: {safe_name}]\\n")
        except Exception as e:
            print("AI file write error:", e)
            cleaned_parts.append(f"\\n[AI file error: {safe_name}]\\n")

        i = end_block + len("[[/FILE]]")

    cleaned_text = "".join(cleaned_parts).strip()
    return files, cleaned_text


@app.route("/api/ai/generated/<filename>", methods=["GET"])
def api_ai_generated_file(filename):
    """
    Download ενός AI-generated αρχείου από το AI_FILES_DIR.
    Χρησιμοποιείται από /chat και /architect για τα [[FILE:...]].
    """
    safe_name = filename.replace("..", "_").replace("/", "_").replace("\\", "_")
    path = os.path.join(AI_FILES_DIR, safe_name)
    if not os.path.exists(path):
        return jsonify({"ok": False, "error": "file not found"}), 404

    mime, _ = mimetypes.guess_type(safe_name)
    return send_file(
        path,
        as_attachment=True,
        download_name=safe_name,
        mimetype=mime or "application/octet-stream",
    )




def _load_offline_corpus_entries() -> list:
    raw = load_json(AI_CORPUS_FILE, {"conversations": []})
    if isinstance(raw, dict):
        conv = raw.get("conversations")
        return conv if isinstance(conv, list) else []
    if isinstance(raw, list):
        return raw
    return []


def _save_offline_corpus_entries(entries: list) -> None:
    save_json(AI_CORPUS_FILE, {"conversations": entries if isinstance(entries, list) else []})

def enqueue_offline_corpus(wallet: str, prompt: str, response: str, files, session_id: str | None = None):
    """
    Ελαφρύ offline corpus για Whisper / training + sessions.
    Κρατάμε και session_id ώστε να χωρίζονται οι συνομιλίες τύπου ChatGPT.
    """
    sid = session_id or "default"

    ts = time.strftime("%Y-%m-%d %H:%M:%S UTC", time.gmtime())
    entry = {
        "timestamp": ts,
        "wallet": wallet or "",
        "prompt": prompt,
        "response": response,
        "files": [f.get("filename") for f in files] if files else [],
        "session_id": sid,
    }

    raw_corpus = load_json(AI_CORPUS_FILE, [])
    if isinstance(raw_corpus, dict):
        corpus = raw_corpus.get("conversations") if isinstance(raw_corpus.get("conversations"), list) else []
    elif isinstance(raw_corpus, list):
        corpus = raw_corpus
    else:
        corpus = []
    corpus.append(entry)
    corpus = corpus[-1000:]
    if isinstance(raw_corpus, dict):
        raw_corpus["conversations"] = corpus
        save_json(AI_CORPUS_FILE, raw_corpus)
    else:
        save_json(AI_CORPUS_FILE, corpus)
    append_session_transcript(sid, prompt, response, files, ts)

    # update / create session meta
    if wallet:
        sessions = load_ai_sessions()
        found = None
        for s in sessions:
            if s.get("wallet") == wallet and s.get("id") == sid:
                found = s
                break

        if not found:
            title_src = prompt.strip() or "Νέα συνομιλία"
            title = (title_src.replace("\\n", " ")[:80]).strip()
            found = {
                "id": sid,
                "wallet": wallet,
                "title": title or "Νέα συνομιλία",
                "created_at": ts,
                "updated_at": ts,
            }
            sessions.append(found)
        else:
            found["updated_at"] = ts

        save_ai_sessions(sessions)


# ─── VIEWER HELPERS ────────────────────────────────
def get_blocks_for_viewer():
    chain = load_json(CHAIN_FILE, [])

    # Pre-index transactions by height for O(1) lookup instead of O(n) per block
    _TX_TYPES = frozenset((
        "transfer",
        "coinbase",
        "service_payment",
        "ai_knowledge",
        "token_transfer",
        "token_create",
        "token_mint",
        "token_burn",
        "swap",
        "bridge",
        "ai_credits",
        "mail_attestation",
        "referral_earning",
        "l2e",
        "iot",
        "autopilot",
    ))
    txs_by_height = {}
    raw_blocks = []
    for entry in chain:
        if not isinstance(entry, dict):
            continue
        if entry.get("reward") is not None:
            raw_blocks.append(entry)
        elif entry.get("type") in _TX_TYPES and entry.get("height") is not None:
            h = entry["height"]
            txs_by_height.setdefault(h, []).append(entry)

    blocks = []
    for b in raw_blocks:
        height = b.get("height")
        if height is None:
            height = len(blocks)
        block_txs = txs_by_height.get(height, [])

        # Always use current schedule (calculate_reward + 80/10/5/5 split) for display.
        # Old blocks stored with pre-upgrade rewards (e.g. 1.0 THR / 90-10 split) are
        # rendered with the post-upgrade schedule so the explorer reflects current economics.
        try:
            scheduled_reward = calculate_reward(int(height))
        except Exception:
            scheduled_reward = 8.0  # Phase C5 initial reward

        stored_reward = float(b.get("reward", 0.0) or 0.0)
        rsplit = b.get("reward_split") or {}
        stored_split_total = (
            float(rsplit.get("miner", 0.0))
            + float(rsplit.get("ai", 0.0))
            + float(rsplit.get("burn", 0.0))
            + float(rsplit.get("full_nodes", 0.0))
            + float(rsplit.get("ecosystem", 0.0))
        ) if rsplit else 0.0

        # Trust stored values only if they match the current schedule (post-upgrade blocks).
        # Otherwise (pre-upgrade / corrupt data) regenerate from calculate_reward(height).
        if rsplit and abs(stored_split_total - scheduled_reward) < 0.001:
            total_reward = stored_split_total
            reward_to_miner = float(rsplit.get("miner", 0.0))
            reward_to_ai = float(rsplit.get("ai", 0.0))
            burn_from_split = (
                float(rsplit.get("burn", 0.0))
                + float(rsplit.get("full_nodes", 0.0))
                + float(rsplit.get("ecosystem", 0.0))
            )
        elif stored_reward > 0 and abs(stored_reward - scheduled_reward) < 0.001:
            # Stored total matches schedule but no split info — derive 80/10/5/5
            total_reward = stored_reward
            reward_to_miner = total_reward * 0.80
            reward_to_ai = total_reward * 0.10
            burn_from_split = total_reward * 0.10  # 5% full_nodes + 5% ecosystem
        else:
            # Pre-upgrade or corrupt block — render with current schedule
            total_reward = scheduled_reward
            reward_to_miner = total_reward * 0.80
            reward_to_ai = total_reward * 0.10
            burn_from_split = total_reward * 0.10

        fees_from_txs = sum(float(tx.get("fee_burned", 0.0) or tx.get("fee", 0.0)) for tx in block_txs)

        miner_address = b.get("thr_address") or b.get("miner_address") or ""
        if not miner_address and block_txs:
            for tx in block_txs:
                if tx.get("type") in ("coinbase", "mining_reward"):
                    miner_address = tx.get("to") or tx.get("thr_address") or ""
                    break

        blocks.append({
            "index": height,
            "hash": b.get("block_hash", ""),
            "thr_address": miner_address,
            "fee_burned": round(burn_from_split + fees_from_txs, 6),
            "reward_to_miner": round(reward_to_miner, 6),
            "reward_to_ai": round(reward_to_ai, 6),
            "reward": round(total_reward, 6),
            "is_stratum": bool(b.get("is_stratum")),
            "nonce": b.get("nonce", "-"),
            "transactions": block_txs,
            "timestamp": b.get("timestamp", "")
        })

    # PR-3: Dedupe blocks by hash before returning (keep last occurrence)
    seen_hashes = {}
    deduped = []
    for b in blocks:
        h = b.get("hash")
        if h:
            seen_hashes[h] = b  # Overwrites earlier duplicates
        else:
            deduped.append(b)  # Keep blocks without hash

    # Add deduplicated blocks back
    deduped.extend(seen_hashes.values())

    # PR-3: Also dedupe by index (optional, if hash-based dedupe isn't enough)
    seen_indexes = {}
    final_blocks = []
    for b in deduped:
        idx = b.get("index")
        if idx is not None:
            if idx not in seen_indexes:
                seen_indexes[idx] = b
                final_blocks.append(b)
        else:
            final_blocks.append(b)

    final_blocks.sort(key=lambda x: x["index"], reverse=True)

    # Filter orphan / phantom blocks: anything whose height is more than 1 above
    # the canonical tip (from last_block.json) is treated as an orphan and excluded
    # from the viewer. This prevents corrupted past mining state (e.g. ghost blocks
    # at heights 204773/204772 while real tip is 200285) from polluting the display.
    try:
        tip_snapshot = get_last_block_snapshot() or {}
        tip_height = int(tip_snapshot.get("height") or 0)
        if tip_height > 0:
            # Allow tip_height + 1 (block currently being mined) and tip_height itself.
            # Anything substantially above tip is an orphan.
            max_visible_height = tip_height + 1
            filtered = [b for b in final_blocks if int(b.get("index") or 0) <= max_visible_height]
            # If filtering would empty the list (e.g. fresh node), fall back to unfiltered.
            if filtered:
                final_blocks = filtered
    except Exception:
        pass  # On any error, return unfiltered list rather than empty.

    return final_blocks

def _tx_feed(include_pending: bool = True, include_bridge: bool = True) -> list[dict]:
    """Return normalized tx records from the shared ledger plus optional extras."""

    # Use load_tx_log directly - seeding happens at startup, not on every request
    records = list(load_tx_log())
    # Canonicalize kinds in case the ledger has legacy values
    for r in records:
        if isinstance(r, dict):
            r_kind = _canonical_kind(r.get("kind") or r.get("type") or "")
            r["kind"] = r_kind
            r.setdefault("type", r_kind)

    seen_ids = {r.get("tx_id") for r in records if r.get("tx_id")}

    if include_pending:
        for raw_tx in load_mempool():
            norm = _normalize_tx_for_display(raw_tx)
            if not norm:
                continue
            tx_id = norm.get("tx_id")
            if tx_id and tx_id in seen_ids:
                continue
            norm["status"] = "pending"
            records.append(norm)
            if tx_id:
                seen_ids.add(tx_id)

    if include_bridge:
        for bridge_tx in _load_bridge_txs():
            if not isinstance(bridge_tx, dict):
                continue
            bridge_tx.setdefault("type", "bridge")
            norm = _normalize_tx_for_display(bridge_tx)
            if not norm:
                continue
            tx_id = norm.get("tx_id")
            if tx_id and tx_id in seen_ids:
                continue
            records.append(norm)
            if tx_id:
                seen_ids.add(tx_id)

    records.sort(key=lambda x: x.get("timestamp", ""), reverse=True)
    return records


def get_transactions_for_viewer():
    out = []
    _TX_TYPES = frozenset((
        "transfer",
        "coinbase",
        "service_payment",
        "ai_knowledge",
        "token_transfer",
        "token_create",
        "token_mint",
        "token_burn",
        "swap",
        "bridge",
        "ai_credits",
        "mail_attestation",
        "referral_earning",
        "l2e",
        "iot",
        "autopilot",
    ))
    for norm in _tx_feed():
        kind = _canonical_kind(norm.get("kind") or norm.get("type") or "")
        norm["kind"] = kind or "transfer"
        norm.setdefault("type", norm["kind"])
        if norm["kind"] not in _TX_TYPES:
            continue

        raw_note = norm.get("note") or ""
        details_payload = norm.get("details")
        details = details_payload if isinstance(details_payload, dict) else None

        if norm.get("kind") == "ai_credits" and not raw_note:
            payload = norm.get("ai_payload") or ""
            payload_obj: dict[str, Any] = {}
            if isinstance(payload, str):
                try:
                    payload_obj = json.loads(payload)
                except Exception:
                    payload_obj = {}

            raw_note = "Legacy AI TX (prompt_tail truncated)"
            if details is None:
                details = {
                    "kind": "ai_knowledge_legacy",
                    "provider": payload_obj.get("provider"),
                    "model": payload_obj.get("model"),
                    "has_prompt_tail": bool(payload_obj.get("prompt_tail")),
                    "has_response_tail": bool(payload_obj.get("response_tail")),
                }

        if details and details.get("kind") == "ai_interaction" and not raw_note:
            raw_note = "AI interaction transfer"

        norm.update({
            "details": details,
            "note": raw_note,
            "height": norm.get("height"),
        })

        out.append(norm)

    out.sort(key=lambda x: x.get("timestamp", ""), reverse=True)
    return out


def ensure_ai_wallet():
    """
    Ensure the AI agent wallet exists on the main chain.
    This MUST ONLY run on the master node with write access.
    """
    # PR-182 FIX: Skip on replica/read-only nodes
    if READ_ONLY or NODE_ROLE != "master":
        print(f"[AI_WALLET] Skipping initialization on {NODE_ROLE} node (READ_ONLY={READ_ONLY})")
        return

    pledges = load_json(PLEDGE_CHAIN, [])
    ai_pledge = next((p for p in pledges if p.get("thr_address")==AI_WALLET_ADDRESS), None)
    if ai_pledge:
        print(f"🤖 AI Wallet {AI_WALLET_ADDRESS} ready.")
        return
    print(f"🤖 Initializing AI Agent Wallet: {AI_WALLET_ADDRESS}")
    send_seed      = secrets.token_hex(16)
    send_seed_hash = hashlib.sha256(send_seed.encode()).hexdigest()
    send_auth_hash = hashlib.sha256(f"{send_seed}:auth".encode()).hexdigest()
    new_pledge = {
        "btc_address":"SYSTEM_AI_RESERVE",
        "pledge_text":"Thronos AI Agent Genesis Allocation",
        "timestamp": time.strftime("%Y-%m-%d %H:%M:%S UTC", time.gmtime()),
        "pledge_hash":"AI_GENESIS_"+secrets.token_hex(8),
        "thr_address":AI_WALLET_ADDRESS,
        "send_seed_hash":send_seed_hash,
        "send_auth_hash":send_auth_hash,
        "has_passphrase":False,
        "is_system":True
    }
    pledges.append(new_pledge)
    save_json(PLEDGE_CHAIN, pledges)
    creds = {
        "thr_address":AI_WALLET_ADDRESS,
        "auth_secret":send_seed,
        "note":"Put these in ai_agent/agent_config.json"
    }
    save_json(AI_CREDS_FILE, creds)
    print(f"✅ AI Wallet Registered. Credentials saved to {AI_CREDS_FILE}")


def decode_iot_steganography(image_path):
    try:
        img = Image.open(image_path)
        width, height = img.size
        pixels = img.load()
        delimiter = "###END###"
        chars=[]
        cur=""
        for y in range(height):
            for x in range(width):
                r,g,b = pixels[x,y]
                for val in (r,g,b):
                    cur += str(val & 1)
                    if len(cur)==8:
                        chars.append(chr(int(cur,2)))
                        cur=""
                        if len(chars)>=len(delimiter) and "".join(chars[-len(delimiter):])==delimiter:
                            json_str = "".join(chars[:-len(delimiter)])
                            return json.loads(json_str)
        return None
    except Exception as e:
        print("Stego Decode Error:", e)
        return None


# ─── READ_ONLY ENFORCEMENT (reject all writes on replica) ─────────────────
PRIMARY_PROXY = os.getenv("PRIMARY_PROXY", _BOOTSTRAP_PRIMARY)

@app.before_request
def enforce_read_only():
    """
    When READ_ONLY=1 reject all POST/PUT/PATCH/DELETE requests except
    health-check and bootstrap paths. Returns 403 with helpful message.
    """
    if not READ_ONLY:
        return None
    if request.method not in ("POST", "PUT", "PATCH", "DELETE"):
        return None
    # Allow health/bootstrap even as POST (for monitoring tools)
    safe_paths = ("/health", "/bootstrap.json", "/api/whoami")
    admin_ai_safe_paths = ("/api/admin/login", "/api/admin/ai/chat", "/api/admin/ai/health", "/api/admin/models", "/api/admin/models/toggle", "/api/admin/agents", "/api/admin/pytheia/state", "/api/admin/pytheia/control", "/api/admin/ai/voice_hook", "/api/voice/x9_webhook")
    if request.path.startswith(safe_paths):
        return None
    if NODE_ROLE == "ai_core" and request.path.startswith(admin_ai_safe_paths):
        return None
    return jsonify({
        "ok": False,
        "error": "read_only_node",
        "message": "This node is read-only. Writes must go to the primary.",
        "primary": PRIMARY_PROXY,
        "node_role": NODE_ROLE,
    }), 403


# ─── LEADER-ONLY WRITES (REPLICA FORWARDING) ──────────────────────────────
@app.before_request
def forward_writes_to_leader():
    """
    Non-leader nodes must forward critical state-changing requests to the leader.
    """
    # AI core is an independent control-plane node and must not proxy writes
    # through chain leader forwarding middleware.
    if NODE_ROLE in ("master", "ai_core"):
        return None

    if request.method not in ["POST", "PUT", "DELETE", "PATCH"]:
        return None

    guarded_prefixes = (
        "/send",
        "/api/wallet/send",
        "/api/swap",
        "/api/bridge",
        "/submit_block",
        "/api/miner/submit",  # Miner block submissions must go to master
    )
    if not request.path.startswith(guarded_prefixes):
        return None

    target_url = f"{MASTER_INTERNAL_URL.rstrip('/')}{request.path}"
    headers = {k: v for k, v in request.headers if k.lower() not in {"host", "content-length"}}
    data = request.get_data()

    try:
        upstream = requests.request(
            method=request.method,
            url=target_url,
            params=request.args,
            data=data,
            headers=headers,
            timeout=15
        )
    except requests.RequestException as exc:
        return jsonify({
            "error": "leader_unavailable",
            "message": "Leader node unavailable for write operation",
            "detail": str(exc),
            "node_role": NODE_ROLE,
            "leader_url": MASTER_INTERNAL_URL
        }), 503

    excluded_headers = {"content-encoding", "content-length", "transfer-encoding", "connection"}
    response = Response(upstream.content, status=upstream.status_code)
    for key, value in upstream.headers.items():
        if key.lower() not in excluded_headers:
            response.headers[key] = value
    response.headers["X-Forwarded-To-Leader"] = "true"
    response.headers["X-Thronos-Leader"] = "1"
    return response


def _chain_ready() -> bool:
    """Return True if the local chain file has at least one block."""
    try:
        chain = load_json(CHAIN_FILE, [])
        return len(chain) > 0
    except Exception:
        return False


@app.before_request
def forward_reads_to_leader():
    """
    Non-leader nodes must proxy chain-dependent reads to the leader.
    Also proxies /api/* reads to PRIMARY_PROXY when local chain is empty.
    Never proxies /static, /health, /bootstrap.json.
    """
    # AI core must always serve local AI endpoints (models/providers/chat)
    # and should never depend on leader read-proxy behavior.
    if NODE_ROLE in ("master", "ai_core"):
        return None

    if request.method != "GET":
        return None

    # Never proxy static assets, health, bootstrap
    skip_prefixes = ("/static", "/health", "/bootstrap.json", "/favicon")
    if request.path.startswith(skip_prefixes):
        return None

    guarded_prefixes = (
        "/api/network_stats",
        "/api/network_live",
        "/api/blocks",
        "/api/tx_feed",
        "/api/history",
        "/api/dashboard",
        "/api/swap/quote",
        "/api/v1/status",
        "/api/v1/block",
        "/api/v1/blockhash",
        "/last_block",
        "/last_block_hash",
        "/token_chart",
        "/api/balances",      # Wallet balance queries
        "/api/miner/work",    # Miner work requests
        "/api/wallet",        # All wallet-related GET requests
    )

    # Always proxy guarded prefixes to leader
    should_proxy = request.path.startswith(guarded_prefixes)

    # Never proxy AI API reads; these should resolve locally (especially on ai_core)
    if request.path.startswith("/api/ai"):
        should_proxy = False

    # If chain is empty, proxy /api/* reads to primary, except AI APIs above.
    if not should_proxy and request.path.startswith("/api/") and not request.path.startswith("/api/ai") and not _chain_ready():
        should_proxy = True

    if not should_proxy:
        return None

    # Choose proxy target: LEADER_URL for replicas, PRIMARY_PROXY as fallback
    proxy_target = LEADER_URL or PRIMARY_PROXY
    target_url = f"{proxy_target.rstrip('/')}{request.path}"
    headers = {k: v for k, v in request.headers if k.lower() not in {"host", "content-length"}}

    try:
        upstream = requests.request(
            method="GET",
            url=target_url,
            params=request.args,
            headers=headers,
            timeout=15
        )
    except requests.RequestException as exc:
        return jsonify({
            "error": "leader_unavailable",
            "message": "Leader node unavailable for read operation",
            "detail": str(exc),
            "node_role": NODE_ROLE,
            "leader_url": proxy_target
        }), 503

    excluded_headers = {"content-encoding", "content-length", "transfer-encoding", "connection"}
    response = Response(upstream.content, status=upstream.status_code)
    for key, value in upstream.headers.items():
        if key.lower() not in excluded_headers:
            response.headers[key] = value
    response.headers["X-Forwarded-To-Leader"] = "true"
    response.headers["X-Thronos-Leader"] = "1"
    return response


@app.after_request
def add_node_headers(response):
    response.headers["X-Thronos-Node"] = NODE_ROLE
    response.headers["X-Thronos-Node-URL"] = request.host_url.rstrip("/")
    if "X-Thronos-Leader" not in response.headers:
        response.headers["X-Thronos-Leader"] = "1" if NODE_ROLE == "master" else "0"
    if request.path.startswith("/api/") and request.path != "/api/whoami":
        response.headers["Cache-Control"] = "no-store"
    return response


