@app.route("/api/blocks", methods=["GET"])
def api_blocks():
    """
    Get blocks with proper pagination (newest first).

    Query params:
    - offset: Starting index (default 0)
    - limit: Number of blocks to return (default 100, max 500)
    - from_height: Optional starting height
    - to_height: Optional ending height

    Returns blocks in descending order (newest first).
    """
    offset = request.args.get("offset", type=int, default=0)
    limit = min(request.args.get("limit", type=int, default=100), 500)
    from_height = request.args.get("from_height", type=int)
    to_height = request.args.get("to_height", type=int)

    # Get all blocks
    all_blocks = get_blocks_for_viewer()
    total = len(all_blocks)

    # Filter by height range if specified
    if from_height is not None or to_height is not None:
        filtered = []
        for b in all_blocks:
            h = b.get("index")
            if h is None:
                continue
            if from_height is not None and h < from_height:
                continue
            if to_height is not None and h > to_height:
                continue
            filtered.append(b)
        all_blocks = filtered
        total = len(all_blocks)

    # Apply pagination (blocks are already sorted newest first)
    blocks = all_blocks[offset:offset + limit]

    # Get min/max heights
    min_height = min((b.get("index", 0) for b in all_blocks), default=0)
    max_height = max((b.get("index", 0) for b in all_blocks), default=0)

    return jsonify({
        "ok": True,
        "blocks": blocks,
        "total": total,
        "offset": offset,
        "limit": limit,
        "has_more": offset + limit < total,
        "min_height": min_height,
        "max_height": max_height
    }), 200


def _categorize_transaction(tx: dict) -> str:
    """
    Categorize a transaction into a specific type for filtering and statistics.

    Categories (matching frontend wallet history tabs):
    - thr: THR transfers
    - mining: Block mining rewards
    - tokens: Token operations
    - l2e: Learn-to-Earn rewards
    - ai_credits: AI Chat credits (consume, earn, spend)
    - architect: Architect/AI Jobs (THR billing)
    - iot: IoT device data/GPS/telemetry
    - bridge: Bridge in/out transactions
    - swaps: Pool swap operations
    - liquidity: Pool add/remove liquidity
    - gateway: Gateway operations
    - music: Music tips/plays/royalties
    - other: Everything else
    """
    tx_type = tx.get("type") or tx.get("kind") or ""
    tx_type_lower = tx_type.lower()

    # IoT (GPS telemetry, autopilot, parking, vehicle data) - check BEFORE music
    # because music_gps_telemetry contains "music" but belongs in IoT
    if tx_type_lower in {"iot_telemetry", "music_gps_telemetry", "iot_reward", "iot_mining_reward",
                         "gps_mining", "route_contribution", "autopilot", "parking",
                         "iot_autopilot", "iot_parking", "iot_parking_reservation"}:
        return "iot"
    if tx.get("category") == "iot" or "telemetry" in tx_type_lower:
        return "iot"

    # Music tips / stream / royalties
    if tx.get("category") in {"music_stream", "music_royalty", "music_tip"}:
        return str(tx.get("category"))
    if "music" in tx_type_lower or tx_type_lower in {"music_tip", "music_play_reward", "music_stream", "music_royalty"}:
        return "music_tip"

    # AI Credits (Chat billing) - must check BEFORE generic "ai" match
    if tx_type in ["credits_consume", "ai_credits", "ai_credit", "ai_credits_earned",
                   "ai_credits_spent", "ai_credits_refund", "service_payment", "ai_knowledge"]:
        return "ai_credits"

    # Architect / AI Jobs (THR billing + ai_reward for training providers)
    if tx_type in ["architect_payment", "architect_service", "ai_job_created",
                   "ai_job_progress", "ai_job_completed", "ai_job_reward",
                   "ai_reward", "t2e_architect_reward"] or tx_type_lower.startswith("ai_job"):
        return "architect_job"

    # Train2Earn contributions
    if "t2e" in tx_type_lower and "architect" not in tx_type_lower:
        return "t2e"

    # Learn-to-earn rewards
    if "l2e" in tx_type_lower or tx_type in ["l2e_reward", "l2e"]:
        return "l2e"

    # IoT fallback (catch anything with "iot" or "gps" not caught earlier)
    if "iot" in tx_type_lower or "gps" in tx_type_lower:
        return "iot"

    # Bridge operations
    if "bridge" in tx_type_lower or tx_type in ["bridge", "bridge_in", "bridge_out", "bridge_deposit", "bridge_withdraw", "crosschain", "wbtc_burn"]:
        return "bridge"

    # Pledges
    if "pledge" in tx_type_lower or tx_type in ["pledge", "btc_pledge"]:
        return "pledge"

    # Mining rewards
    if tx_type in ["coinbase", "mint", "mining_reward"]:
        return "mining"

    # Swaps (category: "swaps" to match frontend filter)
    if "swap" in tx_type_lower:
        return "swaps"

    # Liquidity (category: "liquidity" to match frontend filter)
    if "liquidity" in tx_type_lower or "pool" in tx_type_lower:
        return "liquidity"

    # Token operations (explicit token_* types)
    if tx_type in ["token_transfer", "token_create", "token_mint", "token_burn"]:
        return "token_transfer"

    # NFT operations (mint, buy, transfer)
    if "nft" in tx_type_lower or tx_type in ["nft_mint", "nft_buy", "nft_transfer"]:
        return "nft"

    # VerifyID / verification rewards
    if "verifyid" in tx_type_lower or "verify_id" in tx_type_lower or tx_type in [
        "hash_verification", "verifyid_reward", "device_verification", "device_registration"
    ]:
        return "verifyid"

    # Sentinel subscription payments
    if "sentinel" in tx_type_lower or tx_type in ["sentinel_subscription", "sentinel_fee", "sentinel_gift"]:
        return "sentinel"

    # Fiat gateway operations (buy, sell, deposit, withdrawal)
    if tx_type in [
        "fiat_buy", "fiat_deposit", "fiat_onramp",
        "fiat_sell_request", "fiat_withdrawal", "fiat_offramp",
        "iot_purchase",
    ] or tx.get("fiat_amount") is not None or tx.get("stripe_id") is not None:
        return "gateway"

    # Native THR transfers vs non-THR token transfers
    if tx_type in ["transfer", "send", "thr_transfer"]:
        symbol = (tx.get("symbol") or tx.get("asset_symbol") or "").upper()
        if symbol and symbol != "THR":
            return "token_transfer"
        return "thr"

    return "other"


def normalize_history_item(tx: dict) -> dict:
    sym = (tx.get("symbol") or tx.get("token_symbol") or tx.get("token") or "").upper()
    kind = (tx.get("kind") or tx.get("type") or "").lower()

    if sym == "CREDITS" and kind in ("token_transfer", "transfer", ""):
        tx["kind"] = "ai_credit"
        tx["category"] = "ai"
        tx["unit"] = "credits"

    if tx.get("reward") is not None and (tx.get("thr_address") or tx.get("miner")):
        tx["kind"] = "mining_reward"
        tx["category"] = tx.get("category") or "mining"

    return tx


@app.route("/transfers", methods=["GET"])
@app.route("/api/transfers", methods=["GET"])
def api_transfers():
    """
    Get transfers with filtering and statistics.

    Query params:
    - offset: Starting index (default 0)
    - limit: Number of transfers (default 100, max 500)
    - type: Filter by category (optional)
    - address: Filter by from/to address (optional)
    - stats_only: If true, return only statistics (default false)

    Returns adaptive statistics:
    - If total transfers < 10,000: all-time stats
    - Else: last 24h stats with indicator
    """
    offset = request.args.get("offset", type=int, default=0)
    limit = min(request.args.get("limit", type=int, default=100), 500)
    tx_type = request.args.get("type", "").lower()
    address = request.args.get("address", "").strip()
    stats_only = request.args.get("stats_only", "false").lower() == "true"

    # Get all transactions
    all_txs = _tx_feed(include_pending=True, include_bridge=True)

    # Categorize transactions
    for tx in all_txs:
        if "category" not in tx:
            tx["category"] = _categorize_transaction(tx)

    # Remove block-like events from transfers feed
    all_txs = [tx for tx in all_txs if not _is_block_event(tx)]

    total_txs = len(all_txs)

    # Determine time window for statistics
    use_time_filter = total_txs >= 10000
    if use_time_filter:
        # Last 24 hours
        now = time.time()
        cutoff_time = now - (24 * 3600)
        stats_txs = [tx for tx in all_txs if _parse_timestamp(tx.get("timestamp", "")) >= cutoff_time]
        stats_period = "24h"
    else:
        # All time
        stats_txs = all_txs
        stats_period = "all_time"

    # Compute statistics by category
    category_counts = {}
    for tx in stats_txs:
        cat = tx.get("category", "other")
        category_counts[cat] = category_counts.get(cat, 0) + 1

    # Get unique addresses from stats period
    unique_addresses = set()
    for tx in stats_txs:
        from_addr = tx.get("from", "")
        to_addr = tx.get("to", "")
        if from_addr:
            unique_addresses.add(from_addr)
        if to_addr:
            unique_addresses.add(to_addr)

    stats = {
        "total_transfers": len(stats_txs),
        "unique_addresses": len(unique_addresses),
        "period": stats_period,
        "by_category": category_counts,
        "use_time_filter": use_time_filter
    }

    if stats_only:
        return jsonify({
            "ok": True,
            "stats": stats
        }), 200

    # Filter transactions
    filtered_txs = all_txs

    # Filter by type/category
    if tx_type:
        filtered_txs = [tx for tx in filtered_txs if tx.get("category", "").lower() == tx_type]

    # Filter by address
    if address:
        filtered_txs = [
            tx for tx in filtered_txs
            if address.lower() in (tx.get("from") or "").lower()
            or address.lower() in (tx.get("to") or "").lower()
        ]

    total_filtered = len(filtered_txs)

    # Apply pagination
    transfers = filtered_txs[offset:offset + limit]

    return jsonify({
        "ok": True,
        "transfers": transfers,
        "total": total_filtered,
        "offset": offset,
        "limit": limit,
        "has_more": offset + limit < total_filtered,
        "stats": stats
    }), 200


def _parse_timestamp(ts_str: str) -> float:
    """Parse a timestamp string to Unix timestamp."""
    if not ts_str:
        return 0.0
    try:
        # Try ISO format first
        if "T" in ts_str or "Z" in ts_str:
            dt = datetime.fromisoformat(ts_str.replace("Z", "+00:00"))
            return dt.timestamp()
        # Try "%Y-%m-%d %H:%M:%S UTC" format
        dt = datetime.strptime(ts_str, "%Y-%m-%d %H:%M:%S UTC")
        return dt.timestamp()
    except:
        return 0.0


def _is_block_event(tx: dict) -> bool:
    tx_type = (tx.get("type") or "").lower()
    category = (tx.get("category") or "").lower()
    event = (tx.get("event") or "").lower()
    kind = (tx.get("kind") or "").lower()
    return (
        tx_type == "block"
        or category == "block"
        or event == "mined_block"
        or kind == "block"
    )


@app.route("/api/wallet/mining_stats", methods=["GET"])
def api_wallet_mining_stats():
    """
    Get mining statistics for a specific wallet address.

    Query params:
    - address: THR address of the miner

    Returns:
    - blocks_mined: Total blocks mined
    - total_block_reward: Total THR from block rewards
    - total_pool_burn: Total THR burned from this miner's blocks
    - total_ai_share: Total AI share from these blocks
    - last_block_height: Height of last mined block
    - last_block_time: Timestamp of last mined block
    - recent_blocks: List of last 10 mined blocks
    """
    address = request.args.get("address", "").strip()

    if not address:
        return jsonify({"ok": False, "error": "Address required"}), 400

    # Get all blocks
    all_blocks = get_blocks_for_viewer()

    # Filter blocks mined by this address
    mined_blocks = []
    total_block_reward = 0.0
    total_pool_burn = 0.0
    total_ai_share = 0.0

    for block in all_blocks:
        # Check miner address (stored in transactions within the block)
        block_txs = block.get("transactions", [])
        miner_addr = None

        # Find coinbase/mining reward transaction
        for tx in block_txs:
            if tx.get("type") in ["coinbase", "mining_reward", "mint"]:
                miner_addr = tx.get("to") or tx.get("thr_address")
                break

        # If no miner found in txs, check block metadata
        if not miner_addr:
            # Some blocks might have miner_address field
            miner_addr = block.get("miner_address") or block.get("miner_thr_address")

        if miner_addr and miner_addr.lower() == address.lower():
            mined_blocks.append(block)
            total_block_reward += float(block.get("reward_to_miner", 0.0))
            total_pool_burn += float(block.get("fee_burned", 0.0))
            total_ai_share += float(block.get("reward_to_ai", 0.0))

    # Sort by height descending
    mined_blocks.sort(key=lambda b: b.get("index", 0), reverse=True)

    # Get last block info
    last_block = mined_blocks[0] if mined_blocks else {}
    last_block_height = last_block.get("index")
    last_block_time = last_block.get("timestamp")

    # Get recent 10 blocks
    recent_blocks = []
    for block in mined_blocks[:10]:
        recent_blocks.append({
            "height": block.get("index"),
            "hash": block.get("hash"),
            "reward": block.get("reward_to_miner", 0.0),
            "fee_burned": block.get("fee_burned", 0.0),
            "timestamp": block.get("timestamp"),
            "is_stratum": block.get("is_stratum", False)
        })

    return jsonify({
        "ok": True,
        "address": address,
        "blocks_mined": len(mined_blocks),
        "total_block_reward": round(total_block_reward, 6),
        "total_pool_burn": round(total_pool_burn, 6),
        "total_ai_share": round(total_ai_share, 6),
        "last_block_height": last_block_height,
        "last_block_time": last_block_time,
        "recent_blocks": recent_blocks
    }), 200


def _collect_wallet_history_transactions(address: str, category_filter: str):
    # Load chain + tx_log ONCE (avoid the O(n²) get_blocks_for_viewer call)
    chain = load_json(CHAIN_FILE, [])
    tx_log = load_tx_log()

    addr_lower = address.lower()

    # Category mapping used for all tx types
    category_map = {
        "thr": "thr",
        "token_transfer": "tokens",
        "music_tip": "music",
        "music_stream": "music",
        "music_royalty": "music",
        "ai_reward": "architect",
        "ai_credits": "ai_credits",
        "architect": "architect_job",
        "architect_job": "architect",
        "t2e": "t2e_reward_thr",
        "l2e": "l2e",
        "iot_telemetry": "iot",
        "iot": "iot",
        "bridge": "bridge",
        "pledge": "gateway",
        "mining": "mining",
        "swaps": "swaps",
        "swap": "swaps",
        "liquidity": "liquidity",
        "nft": "nft",
        "nft_mint": "nft",
        "nft_buy": "nft",
        "iot_reward": "iot",
        "iot_mining_reward": "iot",
        "music_gps_telemetry": "iot",
        "gps_mining": "iot",
        "verifyid": "verifyid",
        "other": "other",
        "gateway": "gateway",
        "fiat_buy": "gateway",
        "fiat_deposit": "gateway",
        "fiat_onramp": "gateway",
        "fiat_sell_request": "gateway",
        "fiat_withdrawal": "gateway",
        "fiat_offramp": "gateway",
        "iot_purchase": "gateway",
        "sentinel": "sentinel",
        "sentinel_subscription": "sentinel",
        "sentinel_fee": "sentinel",
        "sentinel_gift": "sentinel",
    }

    # Merge chain + tx_log, deduplicate by tx_id
    seen_tx_ids = set()
    all_txs = []
    for tx in chain:
        if not isinstance(tx, dict):
            continue
        tid = tx.get("tx_id") or tx.get("id")
        if tid and tid in seen_tx_ids:
            continue
        if tid:
            seen_tx_ids.add(tid)
        all_txs.append(tx)
    for tx in tx_log:
        if not isinstance(tx, dict):
            continue
        tid = tx.get("tx_id") or tx.get("id")
        if tid and tid in seen_tx_ids:
            continue
        if tid:
            seen_tx_ids.add(tid)
        all_txs.append(tx)

    wallet_txs = []
    mining_ids = set()

    # Single pass: collect regular txs AND mining rewards from chain entries
    for tx in all_txs:
        tx_type = (tx.get("type") or tx.get("kind") or "").lower()

        # --- Mining / coinbase entries → extract block reward ---
        if tx_type in ("coinbase", "mining_reward", "mint"):
            miner_addr = tx.get("to") or tx.get("thr_address")
            if not miner_addr or miner_addr.lower() != addr_lower:
                continue
            block_hash = tx.get("block_hash") or tx.get("hash") or ""
            reward_id = f"reward:{block_hash}:{miner_addr}"
            if reward_id in mining_ids:
                continue
            mining_ids.add(reward_id)
            rsplit = tx.get("reward_split") or {}
            reward_amt = float(
                rsplit.get("miner")
                or tx.get("reward_to_miner")
                or tx.get("reward")
                or tx.get("amount")
                or 0.0
            )
            wallet_txs.append(normalize_history_item({
                "kind": "mining_reward",
                "type": "mining_reward",
                "category": "mining",
                "direction": "received",
                "from": "COINBASE",
                "to": miner_addr,
                "asset_symbol": "THR",
                "symbol": "THR",
                "amount": reward_amt,
                "timestamp": tx.get("timestamp"),
                "block_height": tx.get("height") or tx.get("index"),
                "block_hash": block_hash,
                "thr_address": miner_addr,
                "id": reward_id,
                "meta": {
                    "block_height": tx.get("height") or tx.get("index"),
                    "block_hash": block_hash,
                    "fee_burned": tx.get("fee_burned"),
                    "reward_to_miner": tx.get("reward_to_miner", tx.get("reward")),
                    "reward_to_ai": tx.get("reward_to_ai"),
                    "source": "stratum" if tx.get("is_stratum") else "legacy",
                },
            }))
            continue

        # --- Block entries (have "reward" key, no "type") → extract miner reward ---
        if tx.get("reward") is not None and not tx_type:
            block_miner = tx.get("thr_address") or tx.get("miner_address") or tx.get("miner")
            if not block_miner or block_miner.lower() != addr_lower:
                continue
            block_hash = tx.get("block_hash") or ""
            reward_id = f"reward:{block_hash}:{block_miner}"
            if reward_id in mining_ids:
                continue
            mining_ids.add(reward_id)
            # Always render mining rewards with the CURRENT halving schedule (Phase C5: 8 THR + 80/10/5/5).
            # Pre-upgrade blocks have stale stored values (e.g. 1.0 THR / 90-10 split) — recompute for display.
            try:
                _height_for_reward = int(tx.get("height") or tx.get("index") or 0)
                scheduled_reward = calculate_reward(_height_for_reward)
            except Exception:
                scheduled_reward = 8.0

            stored_reward = float(tx.get("reward", 0.0) or 0.0)
            rsplit = tx.get("reward_split") or {}
            stored_split_total = (
                float(rsplit.get("miner", 0.0))
                + float(rsplit.get("ai", 0.0))
                + float(rsplit.get("burn", 0.0))
                + float(rsplit.get("full_nodes", 0.0))
                + float(rsplit.get("ecosystem", 0.0))
            ) if rsplit else 0.0

            if rsplit and abs(stored_split_total - scheduled_reward) < 0.001:
                total_reward = stored_split_total
                reward_to_miner = float(rsplit.get("miner", 0.0))
                reward_to_ai = float(rsplit.get("ai", 0.0))
            elif stored_reward > 0 and abs(stored_reward - scheduled_reward) < 0.001:
                total_reward = stored_reward
                reward_to_miner = total_reward * 0.80
                reward_to_ai = total_reward * 0.10
            else:
                total_reward = scheduled_reward
                reward_to_miner = total_reward * 0.80
                reward_to_ai = total_reward * 0.10
            wallet_txs.append(normalize_history_item({
                "kind": "mining_reward",
                "type": "mining_reward",
                "category": "mining",
                "direction": "received",
                "from": "COINBASE",
                "to": block_miner,
                "asset_symbol": "THR",
                "symbol": "THR",
                "amount": reward_to_miner,
                "timestamp": tx.get("timestamp"),
                "block_height": tx.get("height") or tx.get("index"),
                "block_hash": block_hash,
                "thr_address": block_miner,
                "id": reward_id,
                "meta": {
                    "block_height": tx.get("height") or tx.get("index"),
                    "block_hash": block_hash,
                    "fee_burned": tx.get("fee_burned"),
                    "reward_to_miner": reward_to_miner,
                    "reward_to_ai": reward_to_ai,
                    "source": "stratum" if tx.get("is_stratum") else "legacy",
                },
            }))
            continue

        # --- Regular transactions ---
        tx_from = tx.get("from") or tx.get("sender")
        tx_to = tx.get("to") or tx.get("recipient")
        tx_address = tx.get("address")  # IoT telemetry
        tx_meta = tx.get("meta") if isinstance(tx.get("meta"), dict) else {}

        parties = {
            tx_from,
            tx_to,
            tx_address,
            tx.get("thr_address"),
            tx.get("wallet"),
            tx.get("wallet_address"),
            tx.get("owner"),
            tx.get("user_wallet"),
            tx.get("sender_wallet"),
            tx.get("recipient_wallet"),
            # Fix: Include pool/swap participants so they appear in wallet history
            tx.get("trader"),
            tx.get("provider"),
            tx_meta.get("wallet"),
            tx_meta.get("wallet_address"),
            tx_meta.get("thr_address"),
            tx_meta.get("owner"),
            tx_meta.get("artist_wallet"),
            tx_meta.get("tipper_wallet"),
            tx_meta.get("trader"),
            tx_meta.get("provider"),
        }
        parties = {str(p).lower() for p in parties if p}
        if addr_lower not in parties:
            continue

        tx_copy = dict(tx)
        raw_category = _categorize_transaction(tx)
        tx_copy["category"] = category_map.get(raw_category, raw_category)

        # Normalize symbol: ensure 'symbol' is always set for frontend rendering
        if not tx_copy.get("symbol") and tx_copy.get("token_symbol"):
            tx_copy["symbol"] = tx_copy["token_symbol"]
        if not tx_copy.get("asset_symbol") and tx_copy.get("token_symbol"):
            tx_copy["asset_symbol"] = tx_copy["token_symbol"]

        if tx_to and str(tx_to).lower() == addr_lower:
            tx_copy["direction"] = "received"
        elif tx_from and str(tx_from).lower() == addr_lower:
            tx_copy["direction"] = "sent"
        else:
            tx_copy["direction"] = "related"

        wallet_txs.append(tx_copy)

    # Apply category filter
    if category_filter:
        wallet_txs = [tx for tx in wallet_txs if tx.get("category", "").lower() == category_filter]

    for tx in wallet_txs:
        for key in ("image_url", "logo_url", "audio_url", "cover_url"):
            if key in tx:
                tx[key] = normalize_media_url(str(tx.get(key) or ""))

    # Sort by timestamp descending
    wallet_txs.sort(key=lambda t: _parse_timestamp(t.get("timestamp", "")), reverse=True)

    # Calculate category summaries
    summary = {
        "total_mining": 0.0,
        "total_ai_rewards": 0.0,
        "total_music_tips_sent": 0.0,
        "total_music_tips_received": 0.0,
        "total_iot_rewards": 0.0,
        "total_sent": 0.0,
        "total_received": 0.0,
        "mining_count": 0,
        "ai_reward_count": 0,
        "music_tip_count": 0,
        "iot_count": 0
    }

    for tx in wallet_txs:
        category = tx.get("category", "other")
        direction = tx.get("direction", "related")
        try:
            amount = float(tx.get("amount", 0) or 0)
        except Exception:
            amount = 0.0

        if category == "mining":
            summary["total_mining"] += amount
            summary["mining_count"] += 1
        elif category == "ai_reward":
            summary["total_ai_rewards"] += amount
            summary["ai_reward_count"] += 1
        elif category == "music_tip":
            if direction == "sent":
                summary["total_music_tips_sent"] += amount
            elif direction == "received":
                summary["total_music_tips_received"] += amount
            summary["music_tip_count"] += 1
        elif category == "iot_telemetry":
            # IoT txs represent work done, rewards come via ai_reward
            summary["iot_count"] += 1
        elif category == "sentinel":
            summary["total_sentinel_spent"] += amount
            summary["sentinel_count"] += 1

        if direction == "received":
            summary["total_received"] += amount
        elif direction == "sent":
            summary["total_sent"] += amount

    # Round summary values
    for key in summary:
        if isinstance(summary[key], float):
            summary[key] = round(summary[key], 6)

    return wallet_txs, summary


def _build_wallet_history(address: str, category_filter: str, limit: int, cursor: int):
    wallet_txs, summary = _collect_wallet_history_transactions(address, category_filter)

    total = len(wallet_txs)
    paged = wallet_txs[cursor:cursor + limit]
    next_cursor = cursor + limit if cursor + limit < total else None

    return {
        "transactions": paged,
        "summary": summary,
        "total_transactions": total,
        "limit": limit,
        "cursor": cursor,
        "next_cursor": next_cursor,
    }


def _empty_wallet_history_summary() -> dict:
    return {
        "total_mining": 0.0,
        "total_ai_rewards": 0.0,
        "total_music_tips_sent": 0.0,
        "total_music_tips_received": 0.0,
        "total_iot_rewards": 0.0,
        "total_sentinel_spent": 0.0,
        "total_sent": 0.0,
        "total_received": 0.0,
        "mining_count": 0,
        "ai_reward_count": 0,
        "music_tip_count": 0,
        "iot_count": 0,
        "sentinel_count": 0,
    }


def _build_wallet_history_fallback(address: str, limit: int, cursor: int) -> dict:
    addr_lower = address.lower()
    entries: list[dict] = []
    feed = _tx_feed(include_pending=True, include_bridge=True)
    for tx in feed:
        if not isinstance(tx, dict):
            continue
        parties = set(tx.get("parties") or [])
        parties.update({tx.get("from"), tx.get("to"), tx.get("trader"), tx.get("thr_address")})
        parties = {str(p).lower() for p in parties if p}
        if addr_lower not in parties:
            continue
        tx_copy = dict(tx)
        tx_copy["category"] = tx_copy.get("category") or _categorize_transaction(tx_copy)
        tx_copy = normalize_history_item(tx_copy)
        tx_from = tx_copy.get("from")
        tx_to = tx_copy.get("to")
        if tx_to and str(tx_to).lower() == addr_lower:
            tx_copy["direction"] = "received"
        elif tx_from and str(tx_from).lower() == addr_lower:
            tx_copy["direction"] = "sent"
        else:
            tx_copy["direction"] = "related"
        for key in ("logo_url", "image_url", "cover_url", "audio_url", "token_logo"):
            if key in tx_copy:
                tx_copy[key] = normalize_media_url(str(tx_copy.get(key) or ""))
        entries.append(tx_copy)

    entries.sort(key=lambda x: x.get("timestamp", ""), reverse=True)
    total = len(entries)
    paged = entries[cursor:cursor + limit]
    next_cursor = cursor + limit if cursor + limit < total else None
    return {
        "transactions": paged,
        "summary": _empty_wallet_history_summary(),
        "total_transactions": total,
        "limit": limit,
        "cursor": cursor,
        "next_cursor": next_cursor,
    }


@app.route("/history", methods=["GET"])
@app.route("/api/wallet/history", methods=["GET"])
def api_wallet_history():
    """
    Get wallet transaction history with category grouping and summaries (Phase 4).

    Query params:
    - address: THR address
    - category: Optional filter (mining, ai_reward, music_tip, iot_telemetry, etc.)
    - limit: Max entries to return (default 200)
    - cursor: Offset cursor for pagination
    - exclude_source: Comma-separated sources to hide (default: none)
    - status: Filter by "pending" or "confirmed"
    """
    address = (request.args.get("address") or request.args.get("wallet") or "").strip()
    category_filter = request.args.get("category", "").strip().lower()
    exclude_source = request.args.get("exclude_source", "").strip().lower()
    status_filter = request.args.get("status", "").strip().lower()
    try:
        limit = min(int(request.args.get("limit", 200)), 500)
    except Exception:
        limit = 200
    try:
        cursor = max(int(request.args.get("cursor", 0)), 0)
    except Exception:
        cursor = 0

    if not address:
        return jsonify({"ok": False, "error": "Address required"}), 400

    try:
        payload = _build_wallet_history(address, category_filter, limit, cursor)
    except Exception as exc:
        logger.error("[wallet_history] failed: %s", exc)
        payload = _build_wallet_history_fallback(address, limit, cursor)

    # Enrich each tx with canonical type/status/source and apply filters
    exclude_set = {s.strip() for s in exclude_source.split(",") if s.strip()} if exclude_source else set()
    filtered = []
    for tx in payload.get("transactions", []):
        # Canonical fields
        if "type" not in tx:
            tx["type"] = tx.get("kind") or tx.get("tx_type") or tx.get("category") or "transfer"
        if "status" not in tx:
            tx["status"] = "pending" if tx.get("pending") else "confirmed"
        if "source" not in tx:
            tx["source"] = tx.get("category") or _categorize_transaction(tx)

        # Filter by status
        if status_filter and tx["status"] != status_filter:
            continue
        # Filter by excluded source
        if tx.get("source") in exclude_set:
            continue

        for key in ("logo_url", "image_url", "cover_url", "audio_url", "token_logo"):
            if key in tx:
                tx[key] = normalize_media_url(str(tx.get(key) or ""))
        filtered.append(tx)

    payload["transactions"] = filtered
    payload["total_transactions"] = len(filtered)
    summary = payload.get("summary") if isinstance(payload.get("summary"), dict) else {}
    credits_balance = int(get_available_ai_credits(address) if not is_ai_core() else get_ai_credits(address))
    summary["ai_credits"] = credits_balance
    summary["credits"] = credits_balance
    payload["summary"] = summary

    return jsonify({
        "ok": True,
        "address": address,
        **payload,
    }), 200


