@app.route("/api/wallet/dashboard", methods=["GET"])
def api_wallet_dashboard():
    """Wallet dashboard snapshot with stable AI credits aliases."""
    address = (request.args.get("address") or request.args.get("wallet") or "").strip()
    if not validate_thr_address(address):
        return jsonify({"ok": False, "error": "invalid_address", "status": 400}), 400

    try:
        history_payload = _build_wallet_history(address, "", limit=200, cursor=0)
    except Exception as exc:
        logger.warning("[wallet_dashboard] history build failed for %s: %s", address, exc)
        history_payload = _build_wallet_history_fallback(address, limit=200, cursor=0)

    summary = history_payload.get("summary") if isinstance(history_payload.get("summary"), dict) else {}
    if not isinstance(summary, dict):
        summary = {}

    ai_credits_balance = int(get_ai_credits_from_ledger(address) or 0)
    summary["ai_credits"] = ai_credits_balance
    summary["credits"] = ai_credits_balance

    # Best-effort THR balance snapshot.
    thr_balance = 0.0
    try:
        if USE_SQLITE_LEDGER:
            with _get_ledger_db_connection() as conn:
                row = conn.execute(
                    "SELECT balance FROM balances WHERE ledger_type = 'thr' AND address = ?",
                    (address,),
                ).fetchone()
                thr_balance = float(row["balance"] or 0.0) if row else 0.0
        else:
            ledger_map = load_json(LEDGER_FILE, {})
            thr_balance = float(ledger_map.get(address, 0.0) or 0.0)
    except Exception:
        thr_balance = 0.0

    return jsonify({
        "ok": True,
        "address": address,
        "status": 200,
        "summary": summary,
        "ai_credits": ai_credits_balance,
        "credits": ai_credits_balance,
        "thr_balance": round(thr_balance, 8),
        "transactions_count": int(history_payload.get("total_transactions") or 0),
    }), 200


@app.route("/api/v2/wallet/history", methods=["GET"])
def api_v2_wallet_history():
    """
    MICROSERVICE ENDPOINT FOR NODE 3

    Optimized wallet history API - lightweight, cacheable, fast.
    Designed to be deployed on Node 3 to offload main server.

    Query params:
    - address: THR address (required)
    - limit: Max transactions to return (default: 100)
    - offset: Skip first N transactions (default: 0)
    - category: Filter by category (optional)
    - from_date: ISO timestamp filter (optional)
    - to_date: ISO timestamp filter (optional)

    Response:
    {
        "ok": true,
        "address": "THR...",
        "transactions": [...],
        "total": 1234,
        "limit": 100,
        "offset": 0,
        "has_more": true
    }
    """
    address = request.args.get("address", "").strip()
    try:
        limit = min(int(request.args.get("limit", 100)), 500)  # Max 500
    except (TypeError, ValueError):
        limit = 100
    try:
        offset = int(request.args.get("offset", 0))
    except (TypeError, ValueError):
        offset = 0
    category_filter = request.args.get("category", "").strip().lower()
    from_date = request.args.get("from_date", "").strip()
    to_date = request.args.get("to_date", "").strip()

    if not address:
        return jsonify({"ok": False, "error": "Address required"}), 400

    wallet_txs, _summary = _collect_wallet_history_transactions(address, category_filter)

    if from_date:
        wallet_txs = [tx for tx in wallet_txs if tx.get("timestamp", "") >= from_date]

    if to_date:
        wallet_txs = [tx for tx in wallet_txs if tx.get("timestamp", "") <= to_date]

    # Pagination
    total = len(wallet_txs)
    paginated_txs = wallet_txs[offset:offset + limit]
    has_more = (offset + limit) < total

    return jsonify({
        "ok": True,
        "address": address,
        "transactions": paginated_txs,
        "total": total,
        "limit": limit,
        "offset": offset,
        "has_more": has_more,
        "endpoint": "v2",
        "node": "microservice-optimized"
    }), 200


@app.route("/api/wallet/qr/<thr_addr>")
def wallet_qr_code(thr_addr):
    """Generate QR code image for the given THR address."""
    img = qrcode.make(thr_addr)
    buf = io.BytesIO()
    img.save(buf, format='PNG')
    buf.seek(0)
    return send_file(buf, mimetype="image/png")


def _build_qr_payload(network: str | None, address: str) -> str:
    net = (network or "").strip().lower()
    if net in {"btc", "bitcoin"}:
        return f"bitcoin:{address}"
    if net in {"eth", "ethereum"}:
        return f"ethereum:{address}"
    if net in {"bnb", "bsc"}:
        return f"bnb:{address}"
    if net in {"xrp", "ripple"}:
        return f"xrp:{address}"
    return address


def _qr_response(payload: str, force_json: bool = False):
    img = qrcode.make(payload)
    buf = io.BytesIO()
    img.save(buf, format="PNG")
    buf.seek(0)
    if force_json:
        encoded = base64.b64encode(buf.getvalue()).decode("utf-8")
        return jsonify({"ok": True, "data_url": f"data:image/png;base64,{encoded}"}), 200
    return send_file(buf, mimetype="image/png")


@app.route("/api/qr")
@app.route("/api/bridge/qr")
def api_qr():
    address = (request.args.get("address") or request.args.get("thr_address") or "").strip()
    if not address:
        return jsonify({"ok": False, "error": "Missing address"}), 400
    network = request.args.get("network")
    payload = _build_qr_payload(network, address)
    wants_json = (request.args.get("format") or "").lower() == "json"
    wants_json = wants_json or (request.args.get("json") or "").lower() in {"1", "true", "yes"}
    if not wants_json:
        best = request.accept_mimetypes.best if request.accept_mimetypes else ""
        wants_json = best == "application/json"
    return _qr_response(payload, force_json=wants_json)


@app.route("/api/wallet/audio/<thr_addr>")
def wallet_audio(thr_addr):
    """Generate WAV audio encoding the THR address."""
    binary_data = ''.join(format(ord(c), '08b') for c in thr_addr) + '00000000'
    framerate = 44100
    tone_duration = 0.1
    pause_duration = 0.05
    t_bit = np.linspace(0, tone_duration, int(framerate * tone_duration), endpoint=False)
    waveform = np.array([], dtype=np.int16)
    for bit in binary_data:
        freq = 880 if bit == '1' else 440
        tone = (32767 * np.sin(2 * np.pi * freq * t_bit)).astype(np.int16)
        silence = np.zeros(int(framerate * pause_duration), dtype=np.int16)
        waveform = np.concatenate((waveform, tone, silence))
    buf = io.BytesIO()
    with wave.open(buf, 'wb') as wf:
        wf.setnchannels(1)
        wf.setsampwidth(2)
        wf.setframerate(framerate)
        wf.writeframes(waveform.tobytes())
    buf.seek(0)
    return send_file(buf, mimetype="audio/wav", download_name="ThronosAddress.wav")

