@app.route("/api/dashboard")
def api_dashboard():
    """
    Fast dashboard stats using cached telemetry (NEW - Performance).

    Returns network stats from telemetry_cache instead of expensive recalculations.
    Falls back to /api/network_stats if cache is unavailable.

    Metrics:
    - network_hashrate: Estimated hashrate
    - difficulty: Current mining difficulty
    - tx_count: Total transaction count
    - block_count: Total block count
    - tps: Transactions per second (last minute)
    - pledges: Pledge count (from file, not cached)
    - balances: Total supply, burned, AI balance (from ledger/DB)
    """
    try:
        # Try to get cached telemetry (60s max age)
        cached_stats = {}
        if USE_SQLITE_LEDGER:
            for key in ["network_hashrate", "difficulty", "tx_count", "block_count", "tps"]:
                value = _get_telemetry_cache(key, max_age_seconds=60)
                if value is not None:
                    cached_stats[key] = value

        # Get non-cached data (fast lookups)
        pledges = load_json(PLEDGE_CHAIN, [])
        pledge_count = len(pledges)

        # Get balances from DB or ledger
        if USE_SQLITE_LEDGER:
            with _get_ledger_db_connection() as conn:
                # Get total supply
                row = conn.execute(
                    "SELECT SUM(balance) as total FROM balances WHERE ledger_type = 'thr'"
                ).fetchone()
                total_supply = round(float(row["total"] or 0), 6)

                # Get burned amount
                row = conn.execute(
                    "SELECT balance FROM balances WHERE ledger_type = 'thr' AND address = ?",
                    (BURN_ADDRESS,)
                ).fetchone()
                burned = round(float(row["balance"] or 0) if row else 0, 6)

                # Get AI balance
                row = conn.execute(
                    "SELECT balance FROM balances WHERE ledger_type = 'thr' AND address = ?",
                    (AI_WALLET_ADDRESS,)
                ).fetchone()
                ai_balance = round(float(row["balance"] or 0) if row else 0, 6)
        else:
            # Fallback to ledger file
            ledger = load_json(LEDGER_FILE, {})
            burned = float(ledger.get(BURN_ADDRESS, 0))
            ai_balance = float(ledger.get(AI_WALLET_ADDRESS, 0))
            total_supply = round(sum(float(v) for v in ledger.values()), 6)

        # Get last block info (fast - uses LAST_BLOCK_SNAPSHOT)
        last_block = get_last_block_snapshot()
        chain_height = last_block.get("height", 0)

        # Combine cached + fresh data
        response = {
            "ok": True,
            "source": "telemetry_cache" if cached_stats else "fallback",
            "cache_age_seconds": 60,  # Max cache age
            # Cached metrics (fast!)
            "network_hashrate": cached_stats.get("network_hashrate", 0),
            "difficulty": cached_stats.get("difficulty", 0),
            "tx_count": cached_stats.get("tx_count", 0),
            "block_count": cached_stats.get("block_count", chain_height),
            "tps": cached_stats.get("tps", 0),
            # Fresh data (fast lookups)
            "pledge_count": pledge_count,
            "total_supply": total_supply,
            "burned": burned,
            "ai_balance": ai_balance,
            "chain_height": chain_height,
            "last_block_hash": last_block.get("block_hash", ""),
            # Token and pool counts for index page stats
            "token_count": len(load_json(CUSTOM_TOKENS_FILE, [])),
            "pool_count": len(load_pools()),
        }

        # Add Cache-Control headers to prevent browser caching
        resp = jsonify(response)
        resp.headers['Cache-Control'] = 'no-cache, no-store, must-revalidate'
        resp.headers['Pragma'] = 'no-cache'
        resp.headers['Expires'] = '0'
        return resp, 200

    except Exception as exc:
        logger.error("[dashboard] failed: %s", exc)
        # Fallback to network_stats (slower but works)
        return jsonify({
            "ok": False,
            "error": "cache_unavailable",
            "fallback": "use /api/network_stats",
        }), 500


def _rebuild_index_from_chain() -> dict:
    if READ_ONLY or _strip_env_quotes(os.getenv("DISABLE_SNAPSHOT_REBUILD", "0")) == "1":
        return {"height": -1}
    chain = load_json(CHAIN_FILE, [])
    supply_metrics = compute_thr_supply_metrics(chain=chain)

    tx_log = []
    for raw in chain:
        raw = _apply_legacy_ai_job_backfill(raw)
        raw = _apply_legacy_liquidity_backfill(raw)
        norm = _normalize_tx_for_display(raw)
        if norm:
            tx_log.append(norm)
    tx_log.sort(key=lambda x: x.get("timestamp", ""), reverse=True)
    atomic_write_json(TX_LOG_FILE, tx_log)

    # PR-3: Defensively dedupe blocks by hash before building indexes (keep last occurrence)
    raw_blocks = [b for b in chain if isinstance(b, dict) and b.get("reward") is not None]
    seen_hashes = {}
    for b in raw_blocks:
        h = b.get("block_hash")
        if h:
            seen_hashes[h] = b  # Overwrites duplicates, keeping last

    blocks = list(seen_hashes.values()) if seen_hashes else raw_blocks
    block_count = HEIGHT_OFFSET + len(blocks)
    total_supply = supply_metrics["total_supply_thr"]
    if blocks:
        last_block = blocks[-1]
        summary = {
            "height": HEIGHT_OFFSET + len(blocks) - 1,
            "block_hash": last_block.get("block_hash") or last_block.get("tx_id"),
            "timestamp": last_block.get("timestamp"),
            "thr_address": last_block.get("thr_address"),
            "type": "block",
            "block_count": block_count,
            "total_supply": total_supply,
        }
    else:
        summary = {
            "height": None,
            "block_hash": None,
            "timestamp": None,
            "thr_address": None,
            "type": "none",
            "block_count": block_count,
            "total_supply": total_supply,
        }
    atomic_write_json(LAST_BLOCK_FILE, summary)
    return summary


@app.route("/api/admin/reindex", methods=["POST"])
def api_admin_reindex():
    if NODE_ROLE != "master":
        return jsonify({"error": "leader_only", "leader_url": LEADER_URL}), 409

    auth_header = request.headers.get("Authorization", "")
    token = ""
    if auth_header.startswith("Bearer "):
        token = auth_header.removeprefix("Bearer ").strip()
    if not token:
        token = (request.headers.get("X-Admin-Secret") or "").strip()
    if not token:
        return jsonify({"error": "missing_auth"}), 401
    admin_candidates = {
        os.getenv("ADMIN_KEY", "").strip(),
        os.getenv("ADMIN_SECRET", "").strip(),
        ADMIN_SECRET,
    }
    admin_candidates.discard("")
    if token not in admin_candidates:
        return jsonify({"error": "unauthorized"}), 403

    os.makedirs(DATA_DIR, exist_ok=True)
    with open(INDEX_REBUILD_LOCK, "w") as lock_file:
        fcntl.flock(lock_file, fcntl.LOCK_EX)
        summary = _rebuild_index_from_chain()
        fcntl.flock(lock_file, fcntl.LOCK_UN)

    return jsonify({"ok": True, "new_index_tip_height": summary.get("height")}), 200

# ─── PEERS & HEARTBEAT ─────────────────────────────────────────────────────

def cleanup_expired_peers():
    """Remove peers that haven't sent heartbeat in PEER_TTL_SECONDS"""
    global PEERS
    now = _now_ts()
    expired = [peer_id for peer_id, data in PEERS.items()
               if now - data.get("last_seen", 0) > PEER_TTL_SECONDS]
    for peer_id in expired:
        del PEERS[peer_id]
    return len(expired)

@app.route("/api/peers/heartbeat", methods=["POST"], endpoint="api_peers_heartbeat")
def peers_heartbeat():
    data = request.get_json(silent=True) or {}
    url = data.get("url")
    if not url:
        return jsonify(ok=False, error="missing url"), 400

    PEERS[url] = {
        "url": url,
        "node_role": data.get("node_role", "replica"),
        "height": int(data.get("height", -1) or -1),
        "last_seen": int(time.time()),
    }
    peers = list(PEERS.values())
    return jsonify(ok=True, role=NODE_ROLE, active_peers=len(peers), peers=peers, ttl_seconds=PEER_TTL_SECONDS), 200

@app.route("/api/peers/active", methods=["GET"])
def peers_active():
    if NODE_ROLE != "master":
        return jsonify({"error": "Active peers only available on master node"}), 403

    cleanup_expired_peers()
    return jsonify({
        "ok": True,
        "active_peers": list(PEERS.values()),
        "ttl_seconds": PEER_TTL_SECONDS,
    }), 200


@app.route("/api/peers/list", methods=["GET"])
def peers_list():
    if NODE_ROLE != "master":
        return jsonify({"error": "Active peers only available on master node"}), 403
    cleanup_expired_peers()
    peers = []
    for peer_id, data in PEERS.items():
        peers.append({
            "peer_id": peer_id,
            "host": data.get("url"),
            "last_seen": data.get("last_seen"),
            "node_role": data.get("node_role"),
            "height": data.get("height"),
        })
    return jsonify({"ok": True, "peers": peers, "ttl_seconds": PEER_TTL_SECONDS}), 200

@app.route("/api/network_live")
def network_live():
    chain  = load_json(CHAIN_FILE, [])
    blocks = [b for b in chain if isinstance(b, dict) and b.get("reward") is not None]
    mempool_len = len(load_mempool())

    window = 20
    avg_time = None
    if len(blocks) >= 2:
        tail = blocks[-min(window, len(blocks)):]
        try:
            t_fmt = "%Y-%m-%d %H:%M:%S UTC"
            t0 = datetime.strptime(tail[0]["timestamp"], t_fmt).timestamp()
            t1 = datetime.strptime(tail[-1]["timestamp"], t_fmt).timestamp()
            avg_time = (t1 - t0) / max(1, (len(tail) - 1))
        except Exception:
            avg_time = None

    target     = get_mining_target()
    difficulty = int(INITIAL_TARGET // target)
    hashrate   = None
    if avg_time and avg_time > 0:
        hashrate = int(difficulty * (2**32) / avg_time)

    block_count = HEIGHT_OFFSET + len(blocks)

    # Calculate active miners (unique miners in last 100 blocks)
    active_miners_window = 100
    recent_blocks = blocks[-min(active_miners_window, len(blocks)):]
    unique_miners = set()
    for block in recent_blocks:
        miner_addr = block.get("thr_address") or block.get("miner_address")
        if miner_addr:
            unique_miners.add(miner_addr)
    active_miners = len(unique_miners)

    # Active peers - use real heartbeat tracking from replicas
    cleanup_expired_peers()  # Remove stale peers
    active_peers_count = len(PEERS)

    return jsonify({
        "difficulty":          difficulty,
        "avg_block_time_sec":  avg_time,
        "est_hashrate_hs":     hashrate,
        "block_count":         block_count,
        "tx_count":            len(chain),
        "mempool":             mempool_len,
        "active_miners":       active_miners,
        "active_peers":        active_peers_count,
    })


def _current_chain_height() -> int:
    """Return current chain height (including HEIGHT_OFFSET)."""
    chain = load_json(CHAIN_FILE, [])
    blocks = [b for b in chain if isinstance(b, dict) and b.get("reward") is not None]
    return HEIGHT_OFFSET + len(blocks)


def _list_api_routes():
    """Return list of API routes under the configured base prefix."""
    routes = []
    for rule in app.url_map.iter_rules():
        if not str(rule).startswith(API_BASE_PREFIX):
            continue
        methods = sorted(m for m in rule.methods if m not in {"HEAD", "OPTIONS"})
        routes.append({"rule": str(rule), "methods": methods})
    routes.sort(key=lambda r: r["rule"])
    return routes

