def _load_bridge_txs():
    txs = load_json(WATCHER_LEDGER_FILE, [])
    if isinstance(txs, dict):
        if "txs" in txs:
            txs = txs.get("txs", [])
        elif "transactions" in txs:
            txs = txs.get("transactions", [])
        else:
            txs = list(txs.values())
    return txs if isinstance(txs, list) else []


@app.route("/api/bridge/txs")
def api_bridge_txs():
    """Return recorded bridge transactions (alias for watcher ledger)."""
    return jsonify(txs=_load_bridge_txs()), 200


@app.route("/api/bridge/stats")
def api_bridge_stats():
    """Return basic bridge statistics for UI dashboards."""
    txs = _load_bridge_txs()
    total_btc = 0.0
    total_thr = 0.0
    pending = 0
    for tx in txs:
        try:
            total_btc += float(tx.get("btc_amount", tx.get("btc", 0.0)))
            total_thr += float(tx.get("thr_amount", tx.get("thr", 0.0)))
        except Exception:
            pass
        status = str(tx.get("status", "")).lower()
        if status in {"pending", "processing"}:
            pending += 1
    return jsonify({
        "txs": len(txs),
        "total_btc": round(total_btc, 8),
        "total_thr": round(total_thr, 6),
        "pending": pending,
        "last_updated": datetime.utcnow().isoformat(timespec="seconds") + "Z",
    }), 200


@app.route("/api/bridge/status")
def api_bridge_status():
    """
    PRIORITY 4: Return operational status of the bridge.

    Returns:
        - ok: boolean indicating if bridge is operational
        - mode: "disabled" | "manual" | "beta" | "live"
        - last_sync: timestamp of last sync
        - reserves: current bridge reserves (if applicable)
        - notes: human-readable status message
    """
    txs = _load_bridge_txs()

    # PRIORITY 4: Bridge is now in beta mode with burn/deposit support
    mode = os.getenv("BRIDGE_MODE", "beta")
    notes = "Bitcoin bridge is operational. Deposits receive wBTC after 3 confirmations. Withdrawals processed by operator within 24h."

    # Calculate basic stats
    last_tx_time = None
    if txs:
        try:
            # Try to get the most recent transaction timestamp
            for tx in reversed(txs):
                if "timestamp" in tx:
                    last_tx_time = tx["timestamp"]
                    break
        except Exception:
            pass

    # Calculate wBTC reserves
    wbtc_ledger = load_json(WBTC_LEDGER_FILE, {})
    total_wbtc = sum(float(v) for v in wbtc_ledger.values() if v)

    return jsonify({
        "ok": mode in {"beta", "live"},
        "mode": mode,
        "last_sync": last_tx_time or datetime.utcnow().isoformat(timespec="seconds") + "Z",
        "reserves": {
            "wbtc": round(total_wbtc, 8),
            "btc": 0.0  # Would be calculated from actual BTC reserve wallet
        },
        "notes": notes,
        "endpoints": {
            "stats": "/api/bridge/stats",
            "history": "/api/bridge/history/<address>",
            "deposit": "/api/bridge/deposit?wallet=<address>",
            "burn": "/api/bridge/burn"
        }
    }), 200


@app.route("/api/bridge/history/<address>")
def api_bridge_history(address):
    """
    Return bridge history for a given Thronos / BTC address.

    The frontend calls this to show the user's recent bridge activity.
    We keep this very lightweight and tolerant to older records.
    """
    txs = _load_bridge_txs()
    norm = (address or "").strip()
    history = []
    for tx in txs:
        try:
            # Accept a few alternate field names so old records still match
            candidates = [
                tx.get("from_address"),
                tx.get("to_address"),
                tx.get("wallet"),
                tx.get("from"),
                tx.get("to"),
            ]
            if norm and any(c and str(c).strip() == norm for c in candidates):
                history.append(tx)
        except Exception:
            continue

    # Newest first, if timestamps exist
    try:
        history.sort(key=lambda t: t.get("timestamp", 0), reverse=True)
    except Exception:
        pass

    return jsonify({"address": norm, "history": history}), 200

@app.route("/api/bridge/burn", methods=["POST"])
def api_bridge_burn():
    """
    PRIORITY 4: Bridge Withdrawal - Burn wBTC to get BTC.
    Creates BRIDGE_WITHDRAW_REQUEST transaction.
    """
    data = request.get_json() or {}
    wallet = (data.get("wallet") or "").strip()
    btc_address = (data.get("btc_address") or "").strip()
    wbtc_amount = float(data.get("amount", 0))

    if not wallet or not btc_address:
        return jsonify({"ok": False, "error": "Missing wallet or BTC address"}), 400

    if wbtc_amount <= 0:
        return jsonify({"ok": False, "error": "Invalid amount"}), 400

    # Check pledge access (whitelist or BTC pledge)
    if not has_pledge_access(wallet):
        return jsonify({"ok": False, "error": "No pledge access"}), 403

    # Load wBTC ledger
    wbtc_ledger = load_json(WBTC_LEDGER_FILE, {})
    current_balance = float(wbtc_ledger.get(wallet, 0))

    if current_balance < wbtc_amount:
        return jsonify({
            "ok": False,
            "error": f"Insufficient wBTC balance. You have {current_balance}, need {wbtc_amount}"
        }), 400

    # Validate BTC address (basic validation)
    valid_prefixes = ['1', '3', 'bc1']
    if not any(btc_address.startswith(p) for p in valid_prefixes) or len(btc_address) < 26:
        return jsonify({"ok": False, "error": "Invalid Bitcoin address"}), 400

    # Generate withdrawal request ID
    request_id = f"bridge_withdraw_{int(time.time())}_{secrets.token_hex(4)}"

    # Deduct wBTC from wallet
    wbtc_ledger[wallet] = round(current_balance - wbtc_amount, 8)
    save_json(WBTC_LEDGER_FILE, wbtc_ledger)

    # Create BRIDGE_WITHDRAW_REQUEST transaction
    chain = load_json(CHAIN_FILE, [])
    tx = {
        "type": "BRIDGE_WITHDRAW_REQUEST",
        "request_id": request_id,
        "from": wallet,
        "btc_address": btc_address,
        "wbtc_amount": wbtc_amount,
        "status": "pending_operator",
        "timestamp": time.strftime("%Y-%m-%d %H:%M:%S UTC", time.gmtime()),
        "tx_id": f"BRIDGE-{len(chain)}-{int(time.time())}"
    }
    chain.append(tx)
    save_json(CHAIN_FILE, chain)
    update_last_block(tx, is_block=False)

    # Log to watcher ledger for bridge history
    watcher_txs = load_json(WATCHER_LEDGER_FILE, [])
    watcher_txs.append({
        "request_id": request_id,
        "from_address": wallet,
        "to_address": btc_address,
        "wbtc_amount": wbtc_amount,
        "btc_amount": wbtc_amount,  # 1:1 mapping for wBTC
        "status": "pending_operator",
        "timestamp": tx["timestamp"],
        "direction": "withdraw"
    })
    save_json(WATCHER_LEDGER_FILE, watcher_txs)

    app.logger.info(f"🌉 Bridge Withdraw Request: {wallet} → {btc_address} | {wbtc_amount} wBTC | ID: {request_id}")

    return jsonify({
        "ok": True,
        "status": "success",
        "request_id": request_id,
        "message": f"Withdrawal request created. {wbtc_amount} wBTC will be sent to {btc_address}. Operator will process within 24h.",
        "wbtc_burned": wbtc_amount,
        "new_balance": wbtc_ledger[wallet]
    }), 200

# ─── Bridge TX Helpers ───────────────────────────────────────────────

def create_canonical_bridge_tx(
    kind: str,  # "bridge_deposit" or "bridge_withdraw"
    network: str,  # "bitcoin", "ethereum", "bnb", "xrp"
    wrapped_token: str,  # "WBTC", "WETH", "WBNB", "WXRP"
    amount: float,
    thr_address: str,
    external_address: str,
    external_txid: str | None = None,
    fee_burned: float = 0.0,
    status: str = "confirmed"
) -> dict:
    """
    Create a canonical bridge transaction in the normalized schema.

    This ensures all bridge transactions (deposit/withdraw) follow a consistent
    format and appear correctly in:
    - /api/wallet/history (Wallet History Modal)
    - /api/tx_feed (Viewer Transfers Tab)
    - /api/dashboard (Global Stats)

    Schema:
    {
        "tx_id": "BRIDGE-{NETWORK}-{TIMESTAMP}-{RANDOM}",
        "kind": "bridge_deposit" | "bridge_withdraw",
        "asset": "WBTC" | "WETH" | "WBNB" | "WXRP",
        "amount": float,
        "from_address": "THR..." | "external_placeholder",
        "to_address": "THR..." | "external_placeholder",
        "fee_burned": float,
        "network": "bitcoin" | "ethereum" | "bnb" | "xrp",
        "status": "confirmed" | "pending" | "failed",
        "meta": {
            "external_txid": "...",
            "external_address": "...",
            "direction": "in" | "out",
            "network_name": "Bitcoin" | "Ethereum" | ...
        },
        "timestamp": "YYYY-MM-DD HH:MM:SS UTC"
    }
    """
    tx_id = f"BRIDGE-{network.upper()}-{int(time.time())}-{secrets.token_hex(4)}"
    timestamp = time.strftime("%Y-%m-%d %H:%M:%S UTC", time.gmtime())

    # Determine direction and addresses
    if kind == "bridge_deposit":
        # External → Thronos (deposit)
        from_address = f"{network}_external"  # Placeholder for external network
        to_address = thr_address
        direction = "in"
    elif kind == "bridge_withdraw":
        # Thronos → External (withdraw)
        from_address = thr_address
        to_address = f"{network}_external"  # Placeholder for external network
        direction = "out"
    else:
        raise ValueError(f"Invalid bridge kind: {kind}")

    # Network display names
    network_names = {
        "bitcoin": "Bitcoin",
        "ethereum": "Ethereum",
        "bnb": "BNB Chain",
        "xrp": "XRP Ledger",
        "solana": "Solana"
    }

    tx = {
        "tx_id": tx_id,
        "kind": kind,
        "asset": wrapped_token,
        "amount": amount,
        "from_address": from_address,
        "to_address": to_address,
        "from": from_address,  # Alias for compatibility
        "to": to_address,      # Alias for compatibility
        "fee_burned": fee_burned,
        "fee": fee_burned,     # Alias for compatibility
        "network": network,
        "status": status,
        "meta": {
            "external_txid": external_txid or "",
            "external_address": external_address,
            "direction": direction,
            "network_name": network_names.get(network, network.upper()),
            "thr_address": thr_address
        },
        "timestamp": timestamp,
        # Compatibility aliases
        "type": kind,
        "symbol": wrapped_token,
        "asset_symbol": wrapped_token,
        "token_symbol": wrapped_token
    }

    return tx


def persist_bridge_tx(
    kind: str,
    network: str,
    wrapped_token: str,
    amount: float,
    thr_address: str,
    external_address: str,
    external_txid: str | None = None,
    fee_burned: float = 0.0,
    status: str = "confirmed"
):
    """
    Create and persist a canonical bridge transaction to all required logs.

    This function:
    1. Creates canonical bridge TX
    2. Persists to TX log (for /api/wallet/history)
    3. Adds to chain file (for blocks/viewer)
    4. Returns the TX for further processing
    """
    tx = create_canonical_bridge_tx(
        kind=kind,
        network=network,
        wrapped_token=wrapped_token,
        amount=amount,
        thr_address=thr_address,
        external_address=external_address,
        external_txid=external_txid,
        fee_burned=fee_burned,
        status=status
    )

    # Persist to normalized TX log
    persist_normalized_tx(tx)

    # Add to chain file for blocks/viewer
    chain = load_json(CHAIN_FILE, [])
    chain.append(tx)
    save_json(CHAIN_FILE, chain)

    # Update last block
    update_last_block(tx, is_block=False)

    app.logger.info(f"🌉 Bridge TX Persisted: {tx['tx_id']} | {kind} | {amount} {wrapped_token} | {network}")

    return tx


def process_bridge_deposit(
    network: str,
    thr_address: str,
    amount: float,
    external_txid: str,
    external_address: str
) -> dict:
    """
    Process a confirmed bridge deposit from external network.

    Called by watcher when it detects a confirmed deposit on:
    - Bitcoin (BTC_RPC_URL)
    - Ethereum (ETH_RPC_URL)
    - BNB Chain (BSC_RPC_URL)
    - XRP Ledger (XRP_RPC_URL)

    Flow:
    1. Mint wrapped tokens to user's THR address
    2. Create canonical bridge TX (deposit)
    3. Update deposit tracking
    4. Return TX for confirmation

    Example usage (from watcher):
        tx = process_bridge_deposit(
            network="bitcoin",
            thr_address="THR...",
            amount=0.001,
            external_txid="abc123...",
            external_address="bc1q..."
        )
    """
    # Map network to wrapped token and ledger
    network_config = {
        "bitcoin": {"wrapped_token": "WBTC", "ledger_file": WBTC_LEDGER_FILE},
        "ethereum": {"wrapped_token": "WETH", "ledger_file": os.path.join(DATA_DIR, "weth_ledger.json")},
        "bnb": {"wrapped_token": "WBNB", "ledger_file": os.path.join(DATA_DIR, "wbnb_ledger.json")},
        "xrp": {"wrapped_token": "WXRP", "ledger_file": os.path.join(DATA_DIR, "wxrp_ledger.json")}
    }

    if network not in network_config:
        raise ValueError(f"Unsupported network: {network}")

    config = network_config[network]
    wrapped_token = config["wrapped_token"]
    ledger_file = config["ledger_file"]

    # Mint wrapped tokens (1:1 mapping)
    wrapped_ledger = load_json(ledger_file, {})
    current_balance = float(wrapped_ledger.get(thr_address, 0))
    wrapped_ledger[thr_address] = round(current_balance + amount, 8)
    save_json(ledger_file, wrapped_ledger)

    # Create canonical bridge TX
    tx = persist_bridge_tx(
        kind="bridge_deposit",
        network=network,
        wrapped_token=wrapped_token,
        amount=amount,
        thr_address=thr_address,
        external_address=external_address,
        external_txid=external_txid,
        fee_burned=0.0,
        status="confirmed"
    )

    # Update deposit tracking
    deposits_file = os.path.join(DATA_DIR, "bridge_deposits.json")
    deposits = load_json(deposits_file, {})
    tracking_key = f"{thr_address}:{network}"

    if tracking_key in deposits:
        deposits[tracking_key]["total_deposited"] = round(
            deposits[tracking_key].get("total_deposited", 0) + amount, 8
        )
        deposits[tracking_key]["deposits"].append({
            "tx_id": tx["tx_id"],
            "external_txid": external_txid,
            "amount": amount,
            "timestamp": tx["timestamp"],
            "status": "confirmed"
        })
        save_json(deposits_file, deposits)

    app.logger.info(f"🌉 Bridge Deposit Processed: {external_txid[:16]}... → {thr_address} | {amount} {wrapped_token} | {network}")

    return tx


# ─── Bridge Endpoints ────────────────────────────────────────────────

@app.route("/api/bridge/deposit", methods=["GET"])
def api_bridge_deposit():
    """
    Multi-chain bridge: Generate deposit addresses for BTC, ETH, BNB, XRP.

    Supports two formats:
    1. Legacy: ?wallet=THR... (returns BTC address)
    2. New: ?network={bitcoin|ethereum|bnb|xrp}&thr_address=THR...

    Uses RPC endpoints:
    - BTC_RPC_URL (Bitcoin)
    - ETH_RPC_URL (Ethereum)
    - BSC_RPC_URL (BNB Chain)
    - XRP_RPC_URL (XRP Ledger)
    """
    # Check for new format first
    network = request.args.get("network", "").strip().lower()
    thr_address = request.args.get("thr_address", "").strip()

    # Legacy format fallback (wallet parameter = BTC)
    if not network and not thr_address:
        wallet = request.args.get("wallet", "").strip()
        if not wallet:
            return jsonify({"ok": False, "error": "Missing parameters"}), 400
        network = "bitcoin"
        thr_address = wallet

    if not thr_address:
        return jsonify({"ok": False, "error": "THR address required"}), 400

    # Validate network
    supported_networks = ["bitcoin", "ethereum", "bnb", "xrp"]
    if network not in supported_networks:
        return jsonify({
            "ok": False,
            "error": f"Unsupported network. Supported: {', '.join(supported_networks)}"
        }), 400

    # Generate deterministic deposit address based on network
    deposit_seed = f"{thr_address}:{network}_bridge:thronos"
    deposit_hash = hashlib.sha256(deposit_seed.encode()).hexdigest()

    # Generate network-specific addresses
    # TODO: Use actual RPC clients (BTC_RPC_URL, ETH_RPC_URL, BSC_RPC_URL, XRP_RPC_URL)
    if network == "bitcoin":
        # BTC: bc1 (bech32) format
        deposit_address = f"bc1q{deposit_hash[:40]}"
        wrapped_token = "WBTC"
        min_deposit = 0.001
        confirmations = 3
    elif network == "ethereum":
        # ETH: 0x format (40 hex chars)
        deposit_address = f"0x{deposit_hash[:40]}"
        wrapped_token = "WETH"
        min_deposit = 0.01
        confirmations = 12
    elif network == "bnb":
        # BNB: 0x format (same as ETH, BEP-20)
        deposit_address = f"0x{deposit_hash[:40]}"
        wrapped_token = "WBNB"
        min_deposit = 0.01
        confirmations = 15
    elif network == "xrp":
        # XRP: r-address format
        # XRP addresses start with 'r' and use base58
        deposit_address = f"r{deposit_hash[:33]}"
        wrapped_token = "WXRP"
        min_deposit = 10.0
        confirmations = 1
    else:
        return jsonify({"ok": False, "error": "Network not implemented"}), 501

    # Load or create deposit tracking
    deposits_file = os.path.join(DATA_DIR, "bridge_deposits.json")
    deposits = load_json(deposits_file, {})

    # Create tracking key
    tracking_key = f"{thr_address}:{network}"

    if tracking_key not in deposits:
        deposits[tracking_key] = {
            "thr_address": thr_address,
            "network": network,
            "deposit_address": deposit_address,
            "wrapped_token": wrapped_token,
            "created_at": time.strftime("%Y-%m-%d %H:%M:%S UTC", time.gmtime()),
            "total_deposited": 0.0,
            "deposits": []
        }
        save_json(deposits_file, deposits)

    deposit_info = deposits[tracking_key]

    app.logger.info(f"🌉 Bridge Deposit Address Generated: {thr_address} ({network}) → {deposit_address}")

    # Return response
    response = {
        "ok": True,
        "thr_address": thr_address,
        "network": network,
        "deposit_address": deposit_address,
        "wrapped_token": wrapped_token,
        "qr_data": deposit_address,
        "instructions": f"Send {network.upper()} to this address. You will receive {wrapped_token} after {confirmations} confirmations.",
        "min_deposit": min_deposit,
        "exchange_rate": f"1 {network.upper()} = 1 {wrapped_token}",
        "confirmations_required": confirmations,
        "total_deposited": deposit_info.get("total_deposited", 0.0),
        "rpc_status": {
            "bitcoin": bool(os.getenv("BTC_RPC_URL")),
            "ethereum": bool(os.getenv("ETH_RPC_URL")),
            "bnb": bool(os.getenv("BSC_RPC_URL")),
            "xrp": bool(os.getenv("XRP_RPC_URL"))
        }
    }

    # Legacy response format for BTC (backwards compatibility)
    if network == "bitcoin" and request.args.get("wallet"):
        response["btc_address"] = deposit_address
        response["wallet"] = thr_address

    return jsonify(response), 200

@app.route("/api/bridge/withdraw", methods=["POST"])
def api_bridge_withdraw():
    """
    Multi-chain bridge: Withdraw (burn wrapped tokens, send to external chain).

    Supports: BTC, ETH, BNB, XRP
    Request body:
    {
        "wallet": "THR...",           # THR address (sender)
        "network": "bitcoin|ethereum|bnb|xrp",
        "destination": "0x...",       # External address on target network
        "amount": 0.01                # Amount to withdraw
    }

    Flow:
    1. Validate wrapped token balance (WBTC, WETH, WBNB, WXRP)
    2. Burn wrapped tokens from wallet
    3. Create withdrawal request transaction
    4. Log to watcher ledger (operator will process)
    """
    data = request.get_json() or {}
    wallet = (data.get("wallet") or "").strip()
    network = (data.get("network") or "").strip().lower()
    destination = (data.get("destination") or data.get("destination_address") or "").strip()
    amount = float(data.get("amount", 0))

    # Validate inputs
    if not wallet or not network or not destination:
        return jsonify({"ok": False, "error": "Missing required parameters"}), 400

    if amount <= 0:
        return jsonify({"ok": False, "error": "Invalid amount"}), 400

    # Check pledge access (whitelist or BTC pledge)
    if not has_pledge_access(wallet):
        return jsonify({"ok": False, "error": "No pledge access"}), 403

    # Validate network and get wrapped token details
    supported_networks = ["bitcoin", "ethereum", "bnb", "xrp"]
    if network not in supported_networks:
        return jsonify({
            "ok": False,
            "error": f"Unsupported network. Supported: {', '.join(supported_networks)}"
        }), 400

    # Map network to wrapped token
    network_config = {
        "bitcoin": {
            "wrapped_token": "WBTC",
            "ledger_file": WBTC_LEDGER_FILE,
            "address_prefixes": ['1', '3', 'bc1'],
            "min_length": 26,
            "native_symbol": "BTC"
        },
        "ethereum": {
            "wrapped_token": "WETH",
            "ledger_file": os.path.join(DATA_DIR, "weth_ledger.json"),
            "address_prefixes": ['0x'],
            "min_length": 42,
            "native_symbol": "ETH"
        },
        "bnb": {
            "wrapped_token": "WBNB",
            "ledger_file": os.path.join(DATA_DIR, "wbnb_ledger.json"),
            "address_prefixes": ['0x'],
            "min_length": 42,
            "native_symbol": "BNB"
        },
        "xrp": {
            "wrapped_token": "WXRP",
            "ledger_file": os.path.join(DATA_DIR, "wxrp_ledger.json"),
            "address_prefixes": ['r'],
            "min_length": 25,
            "native_symbol": "XRP"
        }
    }

    config = network_config[network]
    wrapped_token = config["wrapped_token"]
    ledger_file = config["ledger_file"]

    # Validate destination address format
    valid_prefix = any(destination.startswith(p) for p in config["address_prefixes"])
    if not valid_prefix or len(destination) < config["min_length"]:
        return jsonify({
            "ok": False,
            "error": f"Invalid {network.upper()} address format"
        }), 400

    # Load wrapped token ledger
    wrapped_ledger = load_json(ledger_file, {})
    current_balance = float(wrapped_ledger.get(wallet, 0))

    if current_balance < amount:
        return jsonify({
            "ok": False,
            "error": f"Insufficient {wrapped_token} balance. You have {current_balance}, need {amount}"
        }), 400

    # Generate withdrawal request ID
    request_id = f"bridge_withdraw_{network}_{int(time.time())}_{secrets.token_hex(4)}"

    # Burn wrapped tokens
    wrapped_ledger[wallet] = round(current_balance - amount, 8)
    save_json(ledger_file, wrapped_ledger)

    # Create canonical bridge TX (appears in wallet history + viewer)
    tx = persist_bridge_tx(
        kind="bridge_withdraw",
        network=network,
        wrapped_token=wrapped_token,
        amount=amount,
        thr_address=wallet,
        external_address=destination,
        external_txid=None,  # Will be filled when operator processes
        fee_burned=0.0,      # No fee for bridge withdrawals
        status="pending"     # Operator will process within 24h
    )

    # Log to watcher ledger for bridge operator tracking
    watcher_txs = load_json(WATCHER_LEDGER_FILE, [])
    watcher_txs.append({
        "request_id": request_id,
        "tx_id": tx["tx_id"],
        "from_address": wallet,
        "to_address": destination,
        "network": network,
        "wrapped_token": wrapped_token,
        "wrapped_amount": amount,
        "native_amount": amount,
        "native_symbol": config["native_symbol"],
        "status": "pending_operator",
        "timestamp": tx["timestamp"],
        "direction": "withdraw"
    })
    save_json(WATCHER_LEDGER_FILE, watcher_txs)

    return jsonify({
        "ok": True,
        "status": "success",
        "request_id": request_id,
        "tx_id": tx["tx_id"],  # Canonical TX ID
        "message": f"Withdrawal request created. {amount} {wrapped_token} will be sent to {destination}. Operator will process within 24h.",
        "wrapped_burned": amount,
        "wrapped_token": wrapped_token,
        "network": network,
        "destination": destination,
        "new_balance": wrapped_ledger[wallet]
    }), 200



def _normalize_iot_ts(raw_ts) -> int:
    try:
        if raw_ts is None:
            return int(time.time())
        return int(float(raw_ts))
    except Exception:
        return int(time.time())


def _register_iot_device_row(device_id: str, label: str, owner_wallet: str, sensor_type: str, location: str, api_key: str | None = None) -> dict:
    now_ts = int(time.time())
    normalized = {
        "device_id": (device_id or "").strip(),
        "label": (label or "").strip(),
        "owner_wallet": (owner_wallet or "").strip(),
        "sensor_type": (sensor_type or "").strip(),
        "location": location if isinstance(location, str) else json.dumps(location or {}, ensure_ascii=False),
    }
    with _get_ledger_db_connection() as conn:
        existing = conn.execute("SELECT api_key, created_at FROM iot_devices WHERE device_id = ?", (normalized["device_id"],)).fetchone()
        keep_api = (existing["api_key"] if existing and existing["api_key"] else None) or api_key or secrets.token_hex(16)
        created_at = int(existing["created_at"]) if existing and existing["created_at"] else now_ts
        conn.execute(
            """
            INSERT INTO iot_devices (device_id, label, owner_wallet, sensor_type, location, api_key, created_at, updated_at)
            VALUES (?, ?, ?, ?, ?, ?, ?, ?)
            ON CONFLICT(device_id)
            DO UPDATE SET label=excluded.label, owner_wallet=excluded.owner_wallet, sensor_type=excluded.sensor_type,
                          location=excluded.location, api_key=COALESCE(iot_devices.api_key, excluded.api_key), updated_at=excluded.updated_at
            """,
            (normalized["device_id"], normalized["label"], normalized["owner_wallet"], normalized["sensor_type"], normalized["location"], keep_api, created_at, now_ts),
        )
    normalized["created_at"] = created_at
    normalized["updated_at"] = now_ts
    normalized["api_key"] = keep_api
    return normalized


def _get_iot_device(device_id: str):
    with _get_ledger_db_connection() as conn:
        return conn.execute("SELECT * FROM iot_devices WHERE device_id = ?", (device_id,)).fetchone()


def _verify_iot_api_key(device_row, supplied_key: str | None) -> bool:
    expected = (device_row["api_key"] or "") if device_row else ""
    if not expected:
        return True
    return bool(supplied_key and secrets.compare_digest(str(expected), str(supplied_key)))


def summarize_recent_iot_to_corpus() -> None:
    if not USE_SQLITE_LEDGER:
        return
    cutoff = int(time.time()) - (IOT_SUMMARY_WINDOW_MINUTES * 60)
    with _get_ledger_db_connection() as conn:
        devices = conn.execute("SELECT device_id, sensor_type FROM iot_devices ORDER BY updated_at DESC LIMIT 200").fetchall()
        for dev in devices:
            rows = conn.execute(
                """
                SELECT value_num, value_text, unit, ts FROM iot_readings
                WHERE device_id = ? AND ts >= ?
                ORDER BY ts DESC LIMIT ?
                """,
                (dev["device_id"], cutoff, IOT_SUMMARY_LIMIT_PER_DEVICE),
            ).fetchall()
            if not rows:
                continue
            numeric = [float(r["value_num"]) for r in rows if r["value_num"] is not None]
            if numeric:
                avg_val = round(sum(numeric) / len(numeric), 4)
                trend = "rising" if len(numeric) > 1 and numeric[0] > numeric[-1] else "steady_or_falling"
                summary = f"IoT summary device={dev['device_id']} sensor={dev['sensor_type']} count={len(rows)} avg={avg_val} trend={trend}"
            else:
                summary = f"IoT summary device={dev['device_id']} sensor={dev['sensor_type']} count={len(rows)} latest={rows[0]['value_text']}"
            enqueue_offline_corpus(
                wallet=f"IOT:{dev['device_id']}",
                prompt=f"[IOT_SUMMARY] {dev['device_id']}",
                response=summary,
                files=[],
                session_id=f"iot-{dev['device_id']}",
            )


@app.route("/api/iot/register_device", methods=["POST"])
def api_iot_register_device():
    if not USE_SQLITE_LEDGER:
        return jsonify({"ok": False, "error": "sqlite_iot_storage_disabled"}), 503

    data = request.get_json(silent=True) or {}
    device_id = (data.get("device_id") or "").strip()
    if not device_id:
        return jsonify({"ok": False, "error": "device_id required"}), 400

    normalized = _register_iot_device_row(
        device_id=device_id,
        label=data.get("label") or device_id,
        owner_wallet=data.get("owner_wallet") or "",
        sensor_type=data.get("sensor_type") or "unknown",
        location=data.get("location") or "",
        api_key=data.get("api_key"),
    )
    return jsonify({"ok": True, "status": "registered", "device": normalized}), 200


@app.route("/api/iot/push_reading", methods=["POST"])
def api_iot_push_reading():
    if not USE_SQLITE_LEDGER:
        return jsonify({"ok": False, "error": "sqlite_iot_storage_disabled"}), 503

    data = request.get_json(silent=True) or {}
    device_id = (data.get("device_id") or "").strip()
    sensor_type = (data.get("sensor_type") or "").strip()
    if not device_id or not sensor_type:
        return jsonify({"ok": False, "error": "device_id and sensor_type required"}), 400

    device = _get_iot_device(device_id)
    if not device and IOT_API_REQUIRE_REGISTER:
        return jsonify({"ok": False, "error": "device_not_registered"}), 404

    if not device and not IOT_API_REQUIRE_REGISTER:
        auto_key = request.headers.get("X-IOT-API-KEY") or secrets.token_hex(16)
        _register_iot_device_row(device_id, device_id, "", sensor_type, "", api_key=auto_key)
        device = _get_iot_device(device_id)

    supplied_key = request.headers.get("X-IOT-API-KEY") or data.get("api_key")
    if not _verify_iot_api_key(device, supplied_key):
        return jsonify({"ok": False, "error": "invalid_iot_api_key"}), 401

    raw_value = data.get("value")
    value_num = None
    try:
        value_num = float(raw_value)
    except Exception:
        pass

    ts_val = _normalize_iot_ts(data.get("ts"))
    metadata_json = json.dumps(data.get("meta") or {}, ensure_ascii=False)
    with _get_ledger_db_connection() as conn:
        conn.execute(
            """
            INSERT INTO iot_readings (device_id, sensor_type, value_text, value_num, unit, ts, metadata_json, created_at)
            VALUES (?, ?, ?, ?, ?, ?, ?, ?)
            """,
            (device_id, sensor_type, str(raw_value), value_num, (data.get("unit") or "").strip(), ts_val, metadata_json, int(time.time())),
        )

    logger.info("[IOT] device=%s sensor=%s value=%s %s", device_id, sensor_type, raw_value, (data.get("unit") or "").strip())
    return jsonify({"ok": True, "status": "stored", "device_id": device_id, "sensor_type": sensor_type, "ts": ts_val}), 200


@app.route("/api/iot/readings", methods=["GET"])
def api_iot_readings():
    if not USE_SQLITE_LEDGER:
        return jsonify({"ok": False, "error": "sqlite_iot_storage_disabled", "readings": []}), 503

    device_id = (request.args.get("device_id") or "").strip()
    limit = int(request.args.get("limit") or 20)
    limit = max(1, min(limit, 200))

    if not device_id:
        return jsonify({"ok": False, "error": "device_id required", "readings": []}), 400

    with _get_ledger_db_connection() as conn:
        rows = conn.execute(
            """
            SELECT id, device_id, sensor_type, value_text, value_num, unit, ts, metadata_json
            FROM iot_readings
            WHERE device_id = ?
            ORDER BY ts DESC, id DESC
            LIMIT ?
            """,
            (device_id, limit),
        ).fetchall()

    readings = []
    for r in rows:
        value = r["value_num"] if r["value_num"] is not None else r["value_text"]
        try:
            meta_obj = json.loads(r["metadata_json"] or "{}")
        except Exception:
            meta_obj = {}
        readings.append({
            "id": r["id"],
            "device_id": r["device_id"],
            "sensor_type": r["sensor_type"],
            "value": value,
            "unit": r["unit"],
            "ts": r["ts"],
            "meta": meta_obj,
        })

    return jsonify({"ok": True, "device_id": device_id, "readings": readings}), 200


