def call_offline_corpus(corpus_path, messages, wallet, session_id, chain_context) -> str:
    """Simple local retrieval over ai_offline_corpus.json / knowledge blocks."""
    try:
        raw_corpus = load_json(corpus_path, []) or []
        if isinstance(raw_corpus, dict):
            corpus = raw_corpus.get("conversations") or []
        elif isinstance(raw_corpus, list):
            corpus = raw_corpus
        else:
            corpus = []
    except Exception:
        corpus = []

    last_user = ""
    for m in reversed(messages or []):
        if isinstance(m, dict) and (m.get("role") or "").lower() == "user":
            last_user = str(m.get("content") or "").strip()
            if last_user:
                break

    if not last_user:
        return "Offline corpus is ready, but no user prompt was provided."

    query_tokens = [w.lower() for w in last_user.split() if len(w) > 2]
    scored = []
    for entry in corpus[-2000:]:
        if not isinstance(entry, dict):
            continue
        blob = f"{entry.get('prompt','')}\n{entry.get('response','')}".lower()
        score = sum(1 for t in query_tokens if t in blob)
        if score:
            scored.append((score, entry))
    scored.sort(key=lambda x: x[0], reverse=True)

    context_blocks = []
    for _, item in scored[:4]:
        context_blocks.append(
            f"- [{item.get('timestamp','unknown')}] Q: {str(item.get('prompt',''))[:180]}\n  A: {str(item.get('response',''))[:260]}"
        )

    chain_summary = []
    if isinstance(chain_context, dict):
        chain_summary.append(f"blocks={len(chain_context.get('blocks') or [])}")
        chain_summary.append(f"tokens={len(chain_context.get('tokens') or [])}")
        chain_summary.append(f"blueprints={len(chain_context.get('blueprints') or [])}")

    if context_blocks:
        return (
            "Offline corpus answer (local knowledge):\n\n"
            + "\n".join(context_blocks)
            + f"\n\nPrompt: {last_user}\nContext: {' | '.join(chain_summary)}"
        )

    return (
        "Offline corpus has no directly matching archived blocks yet. "
        f"Prompt received: {last_user}. Context: {' | '.join(chain_summary)}"
    )


def call_thrai_router(router_url: str, payload: dict) -> dict:
    response = requests.post(router_url, json=payload, timeout=45)
    response.raise_for_status()
    try:
        return response.json()
    except Exception:
        return {"response": response.text, "status": "secure", "provider": "thronos", "model": "thrai"}

# ─── D3LFOI ADMIN HELPERS ───────────────────────────────────────────────────
_ADMIN_TOKENS: dict[str, float] = {}
_ADMIN_TOKEN_TTL_SECONDS = 3600


def _generate_admin_token() -> str:
    return secrets.token_urlsafe(32)


def _cache_admin_token(token: str) -> None:
    if not token:
        return
    _ADMIN_TOKENS[token] = time.time() + _ADMIN_TOKEN_TTL_SECONDS


def _is_admin_authenticated() -> bool:
    token = (request.cookies.get("d3lfoi_admin") or "").strip()
    if not token:
        return False
    exp = _ADMIN_TOKENS.get(token)
    if not exp:
        return False
    if exp < time.time():
        _ADMIN_TOKENS.pop(token, None)
        return False
    return True


def _admin_token_from_request(payload: dict | None = None) -> str:
    payload = payload if isinstance(payload, dict) else {}
    return (
        (request.headers.get("X-Admin-Secret") or "").strip()
        or (request.args.get("secret") or "").strip()
        or str(payload.get("secret") or "").strip()
    )


def require_admin(payload: dict | None = None):
    admin_secret = (os.getenv("ADMIN_SECRET") or ADMIN_SECRET or "").strip()
    if not admin_secret:
        return jsonify({"error": "admin_not_configured", "ok": False}), 503
    if _is_admin_authenticated():
        return None
    # Fallback for non-browser operators / curl
    token = _admin_token_from_request(payload)
    if token == admin_secret:
        return None
    return jsonify({"error": "admin_auth_required", "ok": False}), 401


def _ensure_admin_session(session_id: str | None = None, title: str | None = None) -> dict:
    sid = (session_id or "").strip() or uuid.uuid4().hex
    session = ensure_session_exists(sid, wallet=None, session_type="admin")
    if not session:
        session = _create_session_record(session_type="admin", wallet="", title=title or "D3lfoi Operator", session_id=sid)
    sessions = load_ai_sessions()
    updated = False
    for s in sessions:
        if s.get("id") != sid:
            continue
        s["session_type"] = "admin"
        s["billing_mode_locked"] = "free"
        meta = s.get("meta") if isinstance(s.get("meta"), dict) else {}
        meta["session_type"] = "admin"
        meta["billing_mode_locked"] = "free"
        meta["origin"] = "d3lfoi_admin"
        s["meta"] = meta
        s["updated_at"] = datetime.utcnow().isoformat(timespec="seconds") + "Z"
        updated = True
        session = s
        break
    if updated:
        save_ai_sessions(sessions)
    return session


# ─── PYTHEIA CONTROL PLANE (ADMIN) ─────────────────────────────────────────
def _pytheia_state_file() -> str:
    return os.getenv("PYTHEIA_STATE_FILE", os.path.join(DATA_DIR, "pytheia_state.json"))


def _default_pytheia_admin_control() -> dict:
    return {
        "codex_mode": "monitor",
        "governance_approved": False,
        "repo_write_enabled": False,
        "directive": "",
        "attachment_refs": [],
        "page_paths": [],
        "updated_at": None,
    }


def _coerce_bool_payload(value) -> bool:
    if isinstance(value, bool):
        return value
    if isinstance(value, (int, float)):
        return bool(value)
    return str(value or "").strip().lower() in {"1", "true", "yes", "on"}


def _normalize_string_list(values, *, limit: int = 20, normalize_paths: bool = False) -> list[str]:
    if isinstance(values, str):
        values = [x.strip() for x in values.split(",") if x.strip()]
    if not isinstance(values, list):
        return []

    out: list[str] = []
    for entry in values:
        val = str(entry).strip()
        if not val:
            continue
        if normalize_paths:
            val = "/" + val.lstrip("/")
            if val == "/":
                continue
        if val in out:
            continue
        out.append(val)
        if len(out) >= limit:
            break
    return out

def _load_pytheia_control_state() -> dict:
    state = load_json(_pytheia_state_file(), {})
    if not isinstance(state, dict):
        state = {}
    control = _default_pytheia_admin_control()
    if isinstance(state.get("admin_control"), dict):
        for key in ("codex_mode", "directive", "updated_at"):
            if state["admin_control"].get(key) is not None:
                control[key] = str(state["admin_control"].get(key) or "").strip()
        for key in ("governance_approved", "repo_write_enabled"):
            control[key] = _coerce_bool_payload(state["admin_control"].get(key))
        if control["codex_mode"] not in {"monitor", "assist", "active"}:
            control["codex_mode"] = "monitor"
        for key in ("attachment_refs", "page_paths"):
            vals = state["admin_control"].get(key)
            control[key] = _normalize_string_list(vals, normalize_paths=(key == "page_paths"))
    if control["repo_write_enabled"] and not control["governance_approved"]:
        control["repo_write_enabled"] = False

    history = state.get("admin_instruction_history")
    if not isinstance(history, list):
        history = []
    compact_history = []
    for item in history[-20:]:
        if not isinstance(item, dict):
            continue
        compact_history.append({
            "instruction": str(item.get("instruction") or "").strip(),
            "attachment_refs": item.get("attachment_refs") if isinstance(item.get("attachment_refs"), list) else [],
            "page_paths": item.get("page_paths") if isinstance(item.get("page_paths"), list) else [],
            "submitted_by": str(item.get("submitted_by") or "admin").strip() or "admin",
            "submitted_at": str(item.get("submitted_at") or "").strip(),
        })

    state["admin_control"] = control
    state["admin_instruction_history"] = compact_history
    return state


def _save_pytheia_control_state(state: dict) -> None:
    if not isinstance(state, dict):
        return
    state["last_update"] = datetime.utcnow().isoformat(timespec="seconds") + "Z"
    save_json(_pytheia_state_file(), state)


def _build_pytheia_runtime_report(state: dict) -> dict:
    if not isinstance(state, dict):
        state = {}
    last_advice = state.get("last_advice") if isinstance(state.get("last_advice"), dict) else {}
    return {
        "last_status": state.get("last_status") or {},
        "provider_refresh": {
            "last_provider_scan_ts": state.get("last_provider_scan_ts"),
            "next_provider_scan_ts": state.get("next_provider_scan_ts"),
        },
        "last_health_report": state.get("last_health_report") or {},
        "last_provider_snapshot": state.get("last_provider_snapshot") or {},
        "last_advice": last_advice,
        "apk_builder_simulation": last_advice.get("apk_builder_simulation") or {},
    }


@app.route("/api/admin/login", methods=["GET", "POST"])
def api_admin_login():
    if request.method == "GET":
        expected = (os.getenv("ADMIN_SECRET") or ADMIN_SECRET or "").strip()
        return jsonify({"ok": True, "configured": bool(expected), "hint": "Use POST with JSON {secret}", "method": "POST"}), 200

    data = request.get_json(silent=True) or {}
    secret = (data.get("secret") or "").strip()
    expected = (os.getenv("ADMIN_SECRET") or ADMIN_SECRET or "").strip()

    if not expected:
        return jsonify({"ok": False, "error": "admin_not_configured"}), 503

    if not secret or secret != expected:
        return jsonify({"ok": False, "error": "invalid_admin_secret"}), 401

    token = _generate_admin_token()
    _cache_admin_token(token)
    resp = make_response(jsonify({"ok": True}))
    resp.set_cookie(
        "d3lfoi_admin",
        token,
        max_age=_ADMIN_TOKEN_TTL_SECONDS,
        httponly=True,
        secure=True,
        samesite="Strict",
    )
    return resp


@app.route("/api/admin/ai/health", methods=["GET"])
def api_admin_ai_health():
    if NODE_ROLE != "ai_core":
        return jsonify({"error": "admin_only_on_ai_core"}), 404
    denied = require_admin()
    if denied:
        return denied

    catalog = _build_ai_model_catalog()
    offline_ok, offline_reason = _offline_corpus_health()
