@app.route("/api/ai_credits", methods=["GET"])
def api_ai_credits():
    """
    Επιστρέφει τα διαθέσιμα AI credits για ένα wallet.
    Αν δεν δοθεί wallet, θεωρούμε demo / infinite.
    """
    wallet = (request.args.get("wallet") or "").strip()

    # Keep master as source-of-truth for credits in multi-node topology.
    if NODE_ROLE == "ai_core" and LEADER_URL:
        try:
            upstream = requests.get(f"{LEADER_URL.rstrip('/')}/api/ai_credits", params={"wallet": wallet}, timeout=8)
            return jsonify(upstream.json()), upstream.status_code
        except Exception as exc:
            logger.warning("[AI_CREDITS] leader proxy failed for api_ai_credits: %s", exc)

    if not wallet:
        gid = get_or_set_guest_id()
        remaining = guest_remaining_free_messages(gid)
        resp = jsonify({"mode": "guest", "credits": remaining, "ai_credits": remaining, "max_free_messages": GUEST_MAX_FREE_MESSAGES})
        resp.set_cookie(GUEST_COOKIE_NAME, gid, max_age=GUEST_TTL_SECONDS, httponly=True, samesite="Lax")
        return resp, 200

    value = get_ai_credits(wallet)
    return jsonify({"wallet": wallet, "credits": value, "ai_credits": value}), 200


@app.route("/api/ai_credits/ledger", methods=["GET"])
def api_ai_credits_ledger():
    wallet = (request.args.get("wallet") or "").strip()
    if not wallet:
        return jsonify({"error": "missing_wallet"}), 400

    try:
        limit = max(1, min(int(request.args.get("limit") or 200), 1000))
    except Exception:
        limit = 200

    all_entries = load_ai_credits_ledger()
    if not isinstance(all_entries, list):
        all_entries = []

    filtered = [e for e in all_entries if isinstance(e, dict) and (e.get("wallet") or "") == wallet]
    filtered.sort(key=lambda e: str(e.get("timestamp") or ""), reverse=True)

    items = []
    for e in filtered[:limit]:
        ts = e.get("ts") or e.get("timestamp") or datetime.utcnow().isoformat(timespec="seconds") + "Z"
        meta_val = e.get("meta") if isinstance(e.get("meta"), dict) else e.get("metadata")
        if not isinstance(meta_val, dict):
            meta_val = {}
        items.append({
            "id": e.get("id"),
            "wallet": wallet,
            "delta": int(e.get("delta") or 0),
            "balance_after": int(e.get("balance_after") or 0),
            "reason": str(e.get("reason") or "adjust").lower(),
            "meta": meta_val,
            "ts": ts,
        })

    logger.info("[AI_CREDITS_LEDGER] wallet=%s items=%d", wallet, len(items))
    return jsonify({
        "wallet": wallet,
        "items": items,
        "balance": get_ai_credits(wallet),
        "credits": get_ai_credits(wallet),
        "ai_credits": get_ai_credits(wallet),
        "unit": "credits",
        # Backward compatibility
        "entries": items,
    }), 200


