@app.post("/api/pledge")
async def api_pledge_submit(request: Request, db: Annotated[Session, Depends(get_db)]):
    """JSON API endpoint for pledge submission - allows programmatic pledge creation."""
    try:
        data = await request.json()
    except Exception:
        return jsonify(ok=False, error="Invalid JSON"), 400

    btc_address = (data.get("btc_address") or "").strip()
    pledge_text = (data.get("pledge_text") or "").strip()
    passphrase = (data.get("passphrase") or data.get("user_passphrase") or "").strip()

    if not btc_address:
        return jsonify(ok=False, error="Missing btc_address"), 400

    pledges = load_json(PLEDGE_CHAIN, [])
    exists = next((p for p in pledges if p["btc_address"] == btc_address), None)

    if exists:
        return jsonify(
            ok=True,
            status="already_verified",
            thr_address=exists["thr_address"],
            pledge_hash=exists["pledge_hash"],
            recovery_required=True,
            message="Pledge already exists for this BTC address"
        ), 200

    free_list = load_json(WHITELIST_FILE, [])
    is_whitelisted = btc_address in free_list

    # Verify payment (tries up to 3 times with retries for blockstream.info indexing lag)
    paid, txns = (True, []) if is_whitelisted else verify_btc_payment(btc_address, require_confirmation=False)

    # Track if payment is pending confirmation (found but unconfirmed)
    pending_confirmation = False
    if not paid and not is_whitelisted and txns:
        # We found transactions but they might not be confirmed yet
        pending_confirmation = True
        paid = True  # Allow pledge creation
        logger.info(f"Found unconfirmed BTC transaction(s) for {btc_address}, creating pledge with pending confirmation flag")

    if not paid:
        return jsonify(
            ok=False,
            status="pending",
            error="Waiting for BTC payment",
            transactions=[{"txid": t.get("txid"), "amount_btc": t.get("amount_btc")} for t in txns]
        ), 202

    try:
        # Generate proper THR address (THR + 40 hex chars)
        timestamp = str(int(time.time() * 1000))
        thr_addr = generate_thr_address(btc_address, timestamp)
        phash = hashlib.sha256((btc_address + pledge_text).encode()).hexdigest()
        send_seed = secrets.token_hex(16)
        send_seed_hash = hashlib.sha256(send_seed.encode()).hexdigest()
        auth_string = f"{send_seed}:{passphrase}:auth" if passphrase else f"{send_seed}:auth"
        send_auth_hash = hashlib.sha256(auth_string.encode()).hexdigest()

        pledge_entry = {
            "btc_address": btc_address,
            "pledge_text": pledge_text,
            "timestamp": time.strftime("%Y-%m-%d %H:%M:%S UTC", time.gmtime()),
            "pledge_hash": phash,
            "thr_address": thr_addr,
            "send_seed_hash": send_seed_hash,
            "send_auth_hash": send_auth_hash,
            "has_passphrase": bool(passphrase),
            "pending_confirmation": pending_confirmation
        }

        chain = load_json(CHAIN_FILE, [])
        height = len(chain)

        try:
            pdf_name = create_secure_pdf_contract(
                btc_address, pledge_text, thr_addr, phash, height, send_seed, CONTRACTS_DIR, passphrase
            )
        except Exception as pdf_err:
            logger.error(f"PDF generation failed: {pdf_err}")
            pdf_name = f"pledge_{thr_addr}.pdf"

        pledge_entry["pdf_filename"] = pdf_name
        pledges.append(pledge_entry)
        save_json(PLEDGE_CHAIN, pledges)

        # Register BTC->THR mapping for the BTC pledge watcher
        try:
            reg_file = os.path.join(DATA_DIR, "btc_user_registry.json")
            registry = load_json(reg_file, {})
            registry[btc_address] = {
                "thr_address": thr_addr,
                "kyc_verified": False,
                "whitelisted_admin": is_whitelisted,
                "source": "api_pledge",
            }
            save_json(reg_file, registry)
        except Exception as exc:
            logger.warning(f"Failed to update btc_user_registry: {exc}")

        return jsonify(
            ok=True,
            status="verified" if not pending_confirmation else "pending_confirmation",
            thr_address=thr_addr,
            pledge_hash=phash,
            secret_seed=send_seed,
            pending_confirmation=pending_confirmation,
            message="Pledge created successfully" if not pending_confirmation else "Pledge created, awaiting BTC confirmation"
        ), 201

    except Exception as exc:
        logger.error(f"Pledge creation failed: {exc}")
        return jsonify(ok=False, error=f"Pledge creation failed: {str(exc)}"), 500


