@app.route("/pledge_submit", methods=["POST"])
def pledge_submit():
    data = request.get_json() or {}
    btc_address=(data.get("btc_address") or "").strip()
    pledge_text=(data.get("pledge_text") or "").strip()
    passphrase=(data.get("user_passphrase") or data.get("passphrase") or "").strip()
    if not btc_address:
        return jsonify(error="Missing BTC address"),400
    pledges = load_json(PLEDGE_CHAIN, [])
    exists = next((p for p in pledges if p["btc_address"]==btc_address), None)
    if exists:
        pdf_fn = exists.get("pdf_filename", "")
        pdf_url = None
        if pdf_fn and os.path.isfile(os.path.join(CONTRACTS_DIR, pdf_fn)):
            pdf_url = f"/contracts/{pdf_fn}"
        else:
            # PDF missing (volume reset / first-deploy) → regenerate contract
            try:
                chain = load_json(CHAIN_FILE, [])
                height = len(chain)
                # send_seed not stored; use a placeholder so PDF is a
                # proof-of-pledge document (recovery still needs the original)
                regen_seed = "RECOVERY_REQUIRED"
                pdf_fn = create_secure_pdf_contract(
                    exists["btc_address"],
                    exists.get("pledge_text", pledge_text or ""),
                    exists["thr_address"],
                    exists["pledge_hash"],
                    height,
                    regen_seed,
                    CONTRACTS_DIR,
                    passphrase or None,
                )
                # Update stored filename so next visit is instant
                exists["pdf_filename"] = pdf_fn
                save_json(PLEDGE_CHAIN, pledges)
                pdf_url = f"/contracts/{pdf_fn}"
                app.logger.info(f"Regenerated pledge PDF for {exists['thr_address']}")
            except Exception as regen_err:
                app.logger.warning(f"PDF regen failed for {exists['thr_address']}: {regen_err}")
        return jsonify(
            status="already_verified",
            thr_address=exists["thr_address"],
            pledge_hash=exists["pledge_hash"],
            pdf_url=pdf_url,
            recovery_required=True,
            recovery_url="/recovery",
        ),200
    free_list=load_json(WHITELIST_FILE,[])
    is_whitelisted = btc_address in free_list

    # Verify payment (tries up to 3 times with retries for blockstream.info indexing lag)
    paid, txns = (True,[]) if is_whitelisted else verify_btc_payment(btc_address, require_confirmation=False)

    # Track if payment is pending confirmation (found but unconfirmed)
    pending_confirmation = False
    if not paid and not is_whitelisted and txns:
        # We found transactions but they might not be confirmed yet
        pending_confirmation = True
        paid = True  # Allow pledge creation
        app.logger.info(f"Found unconfirmed BTC transaction(s) for {btc_address}, creating pledge with pending confirmation flag")

    if not paid:
        return jsonify(status="pending",message="Waiting for BTC payment",txns=txns),200

    try:
        # Generate proper THR address (THR + 40 hex chars)
        timestamp = str(int(time.time() * 1000))
        thr_addr = generate_thr_address(btc_address, timestamp)
        phash = hashlib.sha256((btc_address+pledge_text).encode()).hexdigest()
        send_seed=secrets.token_hex(16)
        send_seed_hash=hashlib.sha256(send_seed.encode()).hexdigest()
        auth_string=f"{send_seed}:{passphrase}:auth" if passphrase else f"{send_seed}:auth"
        send_auth_hash=hashlib.sha256(auth_string.encode()).hexdigest()
        pledge_entry={
            "btc_address":btc_address,
            "pledge_text":pledge_text,
            "timestamp":time.strftime("%Y-%m-%d %H:%M:%S UTC", time.gmtime()),
            "pledge_hash":phash,
            "thr_address":thr_addr,
            "send_seed_hash":send_seed_hash,
            "send_auth_hash":send_auth_hash,
            "has_passphrase":bool(passphrase),
            "pending_confirmation":pending_confirmation
        }
        chain=load_json(CHAIN_FILE,[])
        height=len(chain)
        try:
            pdf_name=create_secure_pdf_contract(
                btc_address, pledge_text, thr_addr, phash, height, send_seed, CONTRACTS_DIR, passphrase
            )
        except Exception as pdf_err:
            app.logger.error(f"PDF generation failed: {pdf_err}")
            pdf_name=f"pledge_{thr_addr}.pdf"
        pledge_entry["pdf_filename"]=pdf_name
        pledges.append(pledge_entry)
        save_json(PLEDGE_CHAIN, pledges)

        # Register BTC->THR mapping for the BTC pledge watcher
        try:
            reg_file = os.path.join(DATA_DIR, "btc_user_registry.json")
            registry = load_json(reg_file, {})
            registry[btc_address] = {
                "thr_address": thr_addr,
                "kyc_verified": False,
                "whitelisted_admin": btc_address in (free_list or []),
                "source": "pledge_submit",
            }
            save_json(reg_file, registry)
        except Exception as exc:
            app.logger.warning(f"Failed to update btc_user_registry: {exc}")

        # Build pdf_url – regenerate if the file is unexpectedly absent
        pdf_path = os.path.join(CONTRACTS_DIR, pdf_name)
        if not os.path.isfile(pdf_path):
            try:
                pdf_name = create_secure_pdf_contract(
                    btc_address, pledge_text, thr_addr, phash, height, send_seed, CONTRACTS_DIR, passphrase
                )
                pdf_path = os.path.join(CONTRACTS_DIR, pdf_name)
                pledge_entry["pdf_filename"] = pdf_name
                pledges[-1] = pledge_entry
                save_json(PLEDGE_CHAIN, pledges)
            except Exception:
                pass
        pdf_url = f"/contracts/{pdf_name}" if os.path.isfile(pdf_path) else None

        return jsonify(
            status="verified",
            thr_address=thr_addr,
            pledge_hash=phash,
            pdf_url=pdf_url,
            send_secret=send_seed
        ),200
    except Exception as exc:
        app.logger.error(f"Pledge creation failed: {exc}")
        return jsonify(error=f"Pledge creation failed: {str(exc)}"),500


# ─── PLEDGE STATUS & QUOTE APIs ────────────────────
@app.route("/api/pledge/status")
def api_pledge_status():
    """Check pledge status for a BTC address: pending / verified / unknown."""
    btc_address = (request.args.get("btc") or request.args.get("btc_address") or "").strip()
    if not btc_address:
        return jsonify(ok=False, error="Missing ?btc= parameter"), 400

    pledges = load_json(PLEDGE_CHAIN, [])
    exists = next((p for p in pledges if p["btc_address"] == btc_address), None)

    if exists:
        status = "verified"
        if exists.get("pending_confirmation"):
            status = "pending_confirmation"
        return jsonify(
            ok=True,
            status=status,
            thr_address=exists["thr_address"],
            pledge_hash=exists["pledge_hash"],
            timestamp=exists.get("timestamp"),
            has_passphrase=exists.get("has_passphrase", False),
            pending_confirmation=exists.get("pending_confirmation", False),
        ), 200

    # Not pledged yet – check if there's a payment pending
    free_list = load_json(WHITELIST_FILE, [])
    if btc_address in free_list:
        return jsonify(ok=True, status="whitelisted", message="Whitelisted – submit pledge to activate"), 200

    try:
        txns = get_btc_txns(btc_address, BTC_RECEIVER)
    except Exception:
        txns = []

    paid_sats = 0
    confirmations = 0
    seen_txids = set()
    for tx in txns:
        txid = tx.get("txid", "")
        if txid in seen_txids:
            continue
        seen_txids.add(txid)
        if tx.get("to") == BTC_RECEIVER:
            amt = float(tx.get("amount_btc", 0))
            paid_sats += int(amt * 1e8)
            confirmations = max(confirmations, int(tx.get("confirmations", 0)))

    required_sats = int(MIN_AMOUNT * 1e8)
    meets_min_fee = paid_sats >= required_sats

    if paid_sats > 0:
        return jsonify(
            ok=True,
            status="pending" if not meets_min_fee else "paid_not_pledged",
            paid_sats=paid_sats,
            required_sats=required_sats,
            confirmations=confirmations,
            meets_min_fee=meets_min_fee,
            message="Payment detected – submit pledge form to activate" if meets_min_fee else "Partial payment",
        ), 200

    return jsonify(ok=True, status="unknown", message="No pledge or payment found for this BTC address"), 200


