@app.route("/admin/migrate_seeds", methods=["POST","GET"])
def admin_migrate_seeds():
    payload=request.get_json() or {}
    secret=request.args.get("secret","") or payload.get("secret","")
    if secret!=ADMIN_SECRET:
        return jsonify(error="forbidden"),403
    pledges=load_json(PLEDGE_CHAIN,[])
    changed=[]
    for p in pledges:
        if p.get("send_seed_hash") and p.get("send_auth_hash"):
            continue
        thr_addr=p["thr_address"]
        btc_address=p["btc_address"]
        pledge_text=p["pledge_text"]
        pledge_hash=p["pledge_hash"]
        send_seed=secrets.token_hex(16)
        send_seed_hash=hashlib.sha256(send_seed.encode()).hexdigest()
        send_auth_hash=hashlib.sha256(f"{send_seed}:auth".encode()).hexdigest()
        p["send_seed_hash"]=send_seed_hash
        p["send_auth_hash"]=send_auth_hash
        p["has_passphrase"]=False
        chain=load_json(CHAIN_FILE,[])
        height=len(chain)
        pdf_name=create_secure_pdf_contract(
            btc_address, pledge_text, thr_addr, pledge_hash, height, send_seed, CONTRACTS_DIR
        )
        p["pdf_filename"]=pdf_name
        changed.append({
            "thr_address":thr_addr,
            "btc_address":btc_address,
            "send_seed":send_seed,
            "pdf_filename":pdf_name
        })
    save_json(PLEDGE_CHAIN, pledges)
    return jsonify(migrated=changed),200


# ─── QUORUM LAYER – aggregation API surface (BLS placeholder) ───────────────
def _tx_message_bytes(tx: dict) -> bytes:
    material = f"{tx.get('from','')}|{tx.get('to','')}|{tx.get('amount',0)}|{tx.get('tx_id','')}"
    return hashlib.sha256(material.encode()).digest()

@app.route("/api/attest", methods=["POST"])
def api_attest():
    data=request.get_json() or {}
    tx_id=(data.get("tx_id") or "").strip()
    signer=(data.get("signer") or "").strip()
    partial_sig=(data.get("partial_sig") or "").strip()
    pubkey=(data.get("pubkey") or "").strip()
    scheme=(data.get("scheme") or "BLS").upper()
    if not (tx_id and signer and partial_sig and pubkey):
        return jsonify(error="missing_fields"),400
    pool=load_mempool()
    tx=next((t for t in pool if t.get("tx_id")==tx_id),None)
    if not tx:
        chain=load_json(CHAIN_FILE,[])
        tx=next((t for t in chain if t.get("tx_id")==tx_id and t.get("status")!="confirmed"),None)
    if not tx:
        return jsonify(error="unknown_tx"),404
    store=load_attest_store()
    bucket=store.get(tx_id, {"scheme":scheme, "items":[]})
    already={ (i.get("pubkey"), i.get("signer")) for i in bucket["items"] }
    if (pubkey, signer) not in already:
        bucket["items"].append({"signer":signer,"sig":partial_sig,"pubkey":pubkey,"ts":int(time.time())})
        store[tx_id]=bucket
        save_attest_store(store)
    if "signers" not in tx:
        tx["signers"]=[]
    if tx.get("status") not in ("pending","confirmed"):
        tx["status"]="quoruming"
    save_mempool([t if t.get("tx_id")!=tx_id else tx for t in pool])
    return jsonify(status="accepted", collected=len(bucket["items"]), scheme=bucket["scheme"]),200

@app.route("/api/mail/attest", methods=["POST"])
def api_mail_attest():
    data = request.get_json() or {}

    sender = (data.get("from") or "").strip()
    recipients = data.get("to")
    subject = (data.get("subject") or "").strip()
    timestamp = (data.get("timestamp") or "").strip()
    canonical_hash = (data.get("canonicalHash") or data.get("hash") or "").strip()
    tenant_id = (data.get("tenantId") or "").strip()

    if not sender or not subject or not timestamp or not canonical_hash or not tenant_id:
        return jsonify(
            error="missing_fields",
            required=["from", "to", "subject", "timestamp", "canonicalHash", "tenantId"],
        ), 400

    if not isinstance(recipients, list) or not recipients:
        return jsonify(error="invalid_to", details="'to' must be a non-empty list"), 400

    if not _require_commerce_api_key(str(data.get("apiKey") or "")):
        return jsonify(error="unauthorized"), 401

    canonical_payload = {
        "from": sender,
        "to": recipients,
        "subject": subject,
        "messageId": data.get("messageId"),
        "timestamp": timestamp,
        "canonicalHash": canonical_hash,
        "orderId": data.get("orderId"),
        "tenantId": tenant_id,
        "meta": data.get("meta") if isinstance(data.get("meta"), dict) else {},
    }
    canonical_json = json.dumps(
        canonical_payload,
        ensure_ascii=False,
        sort_keys=True,
        separators=(",", ":"),
    )
    final_hash = hashlib.sha256(canonical_json.encode("utf-8")).hexdigest()

    attestation_id = f"mailatt-{uuid.uuid4().hex[:16]}"
    mail_attestation = {
        "attestationId": attestation_id,
        "from": sender,
        "to": recipients,
        "subject": subject,
        "messageId": data.get("messageId"),
        "orderId": data.get("orderId"),
        "tenantId": tenant_id,
        "timestamp": timestamp,
        "canonicalHash": canonical_hash,
        "finalHash": final_hash,
        "meta": canonical_payload["meta"],
        "createdAt": time.strftime("%Y-%m-%dT%H:%M:%SZ", time.gmtime()),
    }

    attestations = load_mail_attestations()
    if not isinstance(attestations, list):
        attestations = []
    attestations.append(mail_attestation)
    save_mail_attestations(attestations)

    pool = load_mempool()
    pool.append({
        "type": "mail_attestation",
        "height": None,
        "timestamp": mail_attestation["createdAt"],
        "from": sender,
        "to": AI_WALLET_ADDRESS,
        "amount": 0.0,
        "fee_burned": 0.0,
        "tx_id": f"MAIL-{attestation_id}",
        "mail_attestation_id": attestation_id,
        "mail_attestation_hash": final_hash,
        "mail_attestation_payload": canonical_json,
        "details": {
            "kind": "mail_attestation",
            "tenantId": tenant_id,
            "orderId": data.get("orderId"),
            "subject": subject,
        },
        "note": f"Mail attestation for {tenant_id}",
        "status": "pending",
        "confirmation_policy": "QUORUM",
        "min_signers": max(1, MAIL_ATTEST_MIN_SIGNERS),
    })
    save_mempool(pool)

    logger.info(
        f"[MAIL_ATTEST] tenant={tenant_id} order={data.get('orderId') or '-'} hash={final_hash}"
    )

    return jsonify(ok=True, attestationId=attestation_id, hash=final_hash), 200


@app.route("/api/mail/attestations", methods=["GET"])
def api_mail_attestations():
    if not _require_commerce_api_key(str(request.args.get("apiKey") or "")):
        return jsonify(error="unauthorized"), 401

    tenant_id = (request.args.get("tenant") or "").strip()
    if not tenant_id:
        return jsonify(error="missing_tenant"), 400

    try:
        limit = int(request.args.get("limit", 50))
    except Exception:
        limit = 50
    limit = max(1, min(limit, 200))

    tenant_rows = [
        row
        for row in load_mail_attestations()
        if isinstance(row, dict) and (row.get("tenantId") or "").strip() == tenant_id
    ]
    tenant_rows.sort(key=lambda x: x.get("timestamp", ""), reverse=True)

    return jsonify(
        ok=True,
        tenant=tenant_id,
        count=min(len(tenant_rows), limit),
        items=tenant_rows[:limit],
    ), 200


