def submit_block():
    data = request.get_json() or {}
    return _process_mining_submission(data, require_job_id=False)


@app.route("/api/mining/work")
def api_mining_work():
    address = (request.args.get("address") or request.args.get("thr_address") or "").strip() or None
    job = _create_mining_job(address)
    return jsonify({"ok": True, **job}), 200


@app.route("/api/mining/submit", methods=["POST"])
def api_mining_submit():
    data = request.get_json() or {}
    return _process_mining_submission(data, require_job_id=True)


@app.route("/api/miner/work")
def api_miner_work():
    """Simple HTTP miner contract (CPU/GPU)."""
    address = (request.args.get("address") or request.args.get("thr_address") or "").strip() or None
    job = _create_mining_job(address)
    return jsonify({
        "ok": True,
        **job,
        "last_hash": job.get("prev_hash"),
        "header": job.get("prev_hash"),
    }), 200


@app.route("/api/miner/submit", methods=["POST"])
def api_miner_submit():
    """Simple HTTP miner submit (CPU/GPU) - processes asynchronously to avoid timeouts."""
    # Reject mining on read-only replica nodes
    if READ_ONLY or NODE_ROLE == "replica":
        return jsonify(
            error="Mining disabled on read-only nodes",
            node_role=NODE_ROLE,
            message="Submit blocks to the master node"
        ), 403

    data = request.get_json() or {}

    # Quick validation
    thr_address = data.get("thr_address") or data.get("address")
    nonce = data.get("nonce")
    if not thr_address or nonce is None:
        return jsonify(error="Missing mining data"), 400

    # Queue for background processing
    try:
        _BLOCK_PROCESS_QUEUE.put((data, time.time()), block=False)
        return jsonify(
            status="accepted",
            message="Block queued for processing",
            height=data.get("height"),
            thr_address=thr_address
        ), 202
    except queue.Full:
        # Queue is full - return 503 instead of blocking (prevents timeouts)
        logger.warning(f"Block processing queue is full - rejecting block from {thr_address}")
        return jsonify(
            error="Node processing limit reached",
            reason="queue_full",
            message="Please retry after a moment"
        ), 503


# ─── BACKGROUND MINTER / WATCHDOG ──────────────────
def submit_mining_block_for_pledge(thr_addr):
    chain = load_json(CHAIN_FILE, [])

    pow_blocks = [
        b for b in chain
        if isinstance(b, dict) and b.get("reward") is not None
    ]

    if pow_blocks:
        prev_hash = pow_blocks[-1].get("block_hash", "0"*64)
        local_height = len(pow_blocks)
    else:
        prev_hash = "0"*64
        local_height = 0

    height       = HEIGHT_OFFSET + local_height
    total_reward = calculate_reward(height)

    # ─── REWARD SPLIT: 80% Miner / 10% AI / 5% Full Nodes / 5% Ecosystem ───
    miner_share = round(total_reward * 0.80, 6)
    ai_share    = round(total_reward * 0.10, 6)      # AI Pool (continues)
    nodes_share = round(total_reward * 0.05, 6)      # Full node runners
    ecosystem_share = round(total_reward * 0.05, 6)  # Digital Legacy pool

    target = get_mining_target()

    nonce = random.randrange(0, 2**32)
    while True:
        h = hashlib.sha256((prev_hash + thr_addr).encode() + str(nonce).encode()).hexdigest()
        if int(h, 16) <= target:
            pow_hash = h
            break
        nonce = (nonce + 1) % (2**32)

    ts = time.strftime("%Y-%m-%d %H:%M:%S UTC", time.gmtime())

    new_block = {
        "thr_address": thr_addr,
        "timestamp": ts,
        "block_hash": pow_hash,
        "prev_hash": prev_hash,
        "nonce": nonce,
        "reward": total_reward,
        "reward_split": {"miner": miner_share, "ai": ai_share, "nodes": nodes_share, "ecosystem": ecosystem_share},
        "pool_fee": ecosystem_share,
        "reward_to_miner": miner_share,
        "height": height,
        "type": "block",
        "target": target,
        "is_stratum": False,
    }
    chain.append(new_block)

    pool = load_mempool()
    included = []
    if pool:
        for tx in list(pool):
            tx["height"] = height
            tx["status"] = "confirmed"
            tx["timestamp"] = ts
            chain.append(tx)
            included.append(tx)
        save_mempool([])

        ledger = load_json(LEDGER_FILE, {})
        for tx in included:
            if tx.get("type") == "transfer":
                ledger[tx["to"]] = round(ledger.get(tx["to"], 0.0) + float(tx["amount"]), 6)
                ledger[BURN_ADDRESS] = round(ledger.get(BURN_ADDRESS, 0.0) + float(tx.get("fee_burned", 0.0)), 6)
        save_json(LEDGER_FILE, ledger)

    ledger = load_json(LEDGER_FILE, {})
    ledger[thr_addr] = round(ledger.get(thr_addr, 0.0) + miner_share, 6)
    ledger[AI_WALLET_ADDRESS] = round(ledger.get(AI_WALLET_ADDRESS, 0.0) + ai_share, 6)
    # Full nodes and ecosystem pool are accumulated separately (handled by their respective managers)
    save_json(LEDGER_FILE, ledger)

    save_json(CHAIN_FILE, chain)
    update_last_block(new_block, is_block=True)
    print(f"⛏️ [Pledge PoW] block #{height} for {thr_addr} | TXs: {len(included)} | hash={pow_hash[:16]}…")

def seconds_since_last_block()->float:
    chain=load_json(CHAIN_FILE,[])
    blocks=[b for b in chain if isinstance(b,dict) and b.get("reward") is not None]
    if not blocks:
        return 10**9
    try:
        t_fmt="%Y-%m-%d %H:%M:%S UTC"
        last_ts=datetime.strptime(blocks[-1]["timestamp"],t_fmt).timestamp()
        return time.time()-last_ts
    except Exception:
        return 10**9

def confirm_mempool_if_stuck(max_wait_sec:int=180):
    pool=load_mempool()
    if not pool:
        return
    if seconds_since_last_block()<max_wait_sec:
        return
    print("⚠️ Watchdog: Mempool stuck > 3 mins. Auto-mining block to clear TXs.")
    submit_mining_block_for_pledge(AI_WALLET_ADDRESS)

def mint_first_blocks():
    pledges=load_json(PLEDGE_CHAIN,[])
    chain=load_json(CHAIN_FILE,[])
    seen={ b.get("thr_address") for b in chain if isinstance(b,dict) and b.get("thr_address") }
    for p in pledges:
        thr=p["thr_address"]
        if thr in seen:
            continue
        submit_mining_block_for_pledge(thr)


# ─── TELEMETRY CACHE UPDATER (NEW - Dashboard Performance) ──────────────────
def update_telemetry_cache_job():
    """
    Updates telemetry cache with network stats. Prevents expensive recalculations.
    Runs every 30 seconds.

    Cached metrics:
    - network_hashrate: Estimated network hashrate
    - difficulty: Current mining difficulty
    - tx_count: Total transaction count
    - block_count: Total block count
    - tps: Transactions per second (last minute)
    """
    if not USE_SQLITE_LEDGER:
        return

    try:
        # Get last block for difficulty/hashrate
        last_block = get_last_block_snapshot()

        # Calculate hashrate (blocks/day * difficulty)
        chain = load_json(CHAIN_FILE, [])
        blocks = [b for b in chain if isinstance(b, dict) and b.get("reward") is not None]
        block_count = len(blocks)

        # Get recent blocks for TPS calculation
        recent_blocks = blocks[-60:] if len(blocks) >= 60 else blocks  # Last 60 blocks
        if len(recent_blocks) >= 2:
            time_span = 0
            first_ts = recent_blocks[0].get("timestamp", "")
            last_ts = recent_blocks[-1].get("timestamp", "")

            try:
                from datetime import datetime
                if first_ts and last_ts:
                    dt1 = datetime.fromisoformat(first_ts.replace("Z", "+00:00"))
                    dt2 = datetime.fromisoformat(last_ts.replace("Z", "+00:00"))
                    time_span = (dt2 - dt1).total_seconds()
            except:
                time_span = len(recent_blocks) * 60  # Fallback: assume 60s per block

            if time_span > 0:
                tps = len(recent_blocks) / time_span
            else:
                tps = 0
        else:
            tps = 0

        # Count transactions
        tx_count = sum(1 for item in chain
                      if isinstance(item, dict) and item.get("type") in
                      ["transfer", "token_transfer", "swap", "bridge", "service_payment"])

        # Get difficulty
        difficulty = last_block.get("difficulty", 0)

        # Estimate hashrate (very rough: blocks_per_day * difficulty)
        if len(blocks) >= 144:  # At least 1 day of blocks
            blocks_per_day = 1440  # 1 block/min = 1440/day
            hashrate = blocks_per_day * difficulty
        else:
            hashrate = 0

        # Update cache
        _update_telemetry_cache("network_hashrate", hashrate)
        _update_telemetry_cache("difficulty", difficulty)
        _update_telemetry_cache("tx_count", tx_count)
        _update_telemetry_cache("block_count", block_count)
        _update_telemetry_cache("tps", round(tps, 4))

        logger.debug(f"[TELEMETRY] Updated cache: blocks={block_count}, txs={tx_count}, tps={tps:.4f}, hashrate={hashrate}")

    except Exception as e:
        logger.error(f"[TELEMETRY] Failed to update cache: {e}")


# ─── AI KNOWLEDGE WATCHER – log -> mempool -> block ─────────────────────────
def ai_knowledge_watcher():
    """
    Διαβάζει το AI_BLOCK_LOG_FILE (ai_block_log.json) και για κάθε νέα
    εγγραφή δημιουργεί mempool TX τύπου 'ai_knowledge'.
    Τα TXs αυτά θα μπουν στο επόμενο block που θα γίνει mined.
    """
    try:
        log_entries = load_json(AI_BLOCK_LOG_FILE, [])
        if not log_entries:
            return

        pool = load_mempool()
        chain = load_json(CHAIN_FILE, [])

        seen_ids = set(
            tx.get("ai_log_id") for tx in pool
            if isinstance(tx, dict) and tx.get("type") == "ai_knowledge"
        )
        for tx in chain:
            if isinstance(tx, dict) and tx.get("type") == "ai_knowledge":
                if tx.get("ai_log_id"):
                    seen_ids.add(tx["ai_log_id"])

        changed = False

        for entry in log_entries:
            eid = entry.get("id")
            if not eid or eid in seen_ids:
                continue

            if str(entry.get("status","")).lower() == "error":
                continue

            prompt = entry.get("prompt", "")
            response = entry.get("response", "")
            provider = entry.get("provider", "")
            model = entry.get("model", "")
            wallet = entry.get("wallet") or AI_WALLET_ADDRESS
            ts = entry.get("timestamp") or time.strftime(
                "%Y-%m-%d %H:%M:%S UTC", time.gmtime()
            )

            payload_obj = {
                "prompt_tail": prompt[-512:],
                "response_tail": response[-2048:],
                "provider": provider,
                "model": model,
            }
            payload_json = json.dumps(payload_obj, ensure_ascii=False)
            ai_hash = hashlib.sha256(payload_json.encode("utf-8")).hexdigest()

            tx = {
                "type": "ai_knowledge",
                "height": None,
                "timestamp": ts,
                "from": wallet,
                "to": AI_WALLET_ADDRESS,
                "amount": 0.0,
                "fee_burned": 0.0,
                "tx_id": f"AI-{eid}",
                "ai_log_id": eid,
                "ai_hash": ai_hash,
                "ai_payload": payload_json,
                "status": "pending",
                "confirmation_policy": "FAST",
                "min_signers": 0,
            }

            pool.append(tx)
            seen_ids.add(eid)
            changed = True

        if changed:
            save_mempool(pool)
            print("🤖 [AI-KNOWLEDGE] updated mempool with new AI entries.")

    except Exception as e:
        print("[AI-KNOWLEDGE WATCHER] error:", e)


# ─── Phase 4: AI REWARDS DISTRIBUTION ─────────────────────────────────────────
def distribute_ai_rewards_step():
    """
    Periodically distribute AI pool funds to miners and IoT contributors.

    Economics:
    - Miners get Y% of pool (pro-rata by blocks mined in last N blocks)
    - IoT miners get (100-Y)% (pro-rata by telemetry samples in last M minutes)

    For now, use simple defaults:
    - MINER_SHARE = 60% (configurable via env)
    - IOT_SHARE = 40%
    - LOOKBACK_BLOCKS = 100 (last 100 blocks for miner rewards)
    - LOOKBACK_MINUTES = 60 (last 60 minutes for IoT rewards)
    - MIN_POOL_BALANCE = 10 THR (only distribute if pool >= 10 THR)
    """
    if READ_ONLY or NODE_ROLE != "master":
        return  # Only master distributes

    try:
        # Configuration
        MINER_SHARE = float(_strip_env_quotes(os.getenv("AI_POOL_MINER_SHARE", "0.60")))  # 60%
        IOT_SHARE = 1.0 - MINER_SHARE
        LOOKBACK_BLOCKS = int(_strip_env_quotes(os.getenv("AI_POOL_LOOKBACK_BLOCKS", "100")))
        LOOKBACK_MINUTES = int(_strip_env_quotes(os.getenv("AI_POOL_LOOKBACK_MINUTES", "60")))
        MIN_POOL_BALANCE = float(_strip_env_quotes(os.getenv("AI_POOL_MIN_BALANCE", "10.0")))
        DISTRIBUTION_PERCENTAGE = float(_strip_env_quotes(os.getenv("AI_POOL_DISTRIBUTION_PCT", "0.10")))  # Distribute 10% of pool each time

        pool = get_ai_pool_state()
        balance = float(pool.get("ai_pool_balance", 0))

        if balance < MIN_POOL_BALANCE:
            logger.debug(f"[AI_POOL] Balance {balance} below minimum {MIN_POOL_BALANCE}, skipping distribution")
            return

        # Calculate distribution amount
        distribution_amount = round(balance * DISTRIBUTION_PERCENTAGE, 6)
        miner_pool = round(distribution_amount * MINER_SHARE, 6)
        iot_pool = round(distribution_amount * IOT_SHARE, 6)

        logger.info(f"[AI_POOL] Distributing {distribution_amount} THR (miners: {miner_pool}, IoT: {iot_pool})")

        # === MINER REWARDS ===
        # Get recent blocks and count per miner
        blocks = get_blocks_for_viewer()
        recent_blocks = blocks[-LOOKBACK_BLOCKS:] if len(blocks) > LOOKBACK_BLOCKS else blocks

        miner_blocks = {}
        for block in recent_blocks:
            miner = block.get("miner") or block.get("miner_address")
            if miner:
                miner_blocks[miner] = miner_blocks.get(miner, 0) + 1

        total_blocks_counted = sum(miner_blocks.values())

        if miner_blocks and total_blocks_counted > 0 and miner_pool > 0:
            for miner_address, block_count in miner_blocks.items():
                reward = round((block_count / total_blocks_counted) * miner_pool, 6)
                if reward > 0:
                    _distribute_ai_pool_to_address(
                        address=miner_address,
                        amount=reward,
                        category="mining",
                        details={"blocks_mined": block_count, "lookback_blocks": LOOKBACK_BLOCKS}
                    )
            logger.info(f"[AI_POOL] Distributed {miner_pool} THR to {len(miner_blocks)} miners")
        else:
            logger.info(f"[AI_POOL] No miners found in last {LOOKBACK_BLOCKS} blocks")

        # === IOT REWARDS ===
        # Get recent IoT telemetry transactions
        chain = load_json(CHAIN_FILE, [])
        now = time.time()
        cutoff_time = now - (LOOKBACK_MINUTES * 60)

        iot_samples = {}
        for tx in chain:
            if tx.get("type") == "iot_telemetry":
                tx_time = _parse_timestamp(tx.get("timestamp"))
                if tx_time >= cutoff_time:
                    address = tx.get("address")
                    samples = int(tx.get("samples", 0))
                    if address and samples > 0:
                        iot_samples[address] = iot_samples.get(address, 0) + samples

        total_samples = sum(iot_samples.values())

        if iot_samples and total_samples > 0 and iot_pool > 0:
            for iot_address, sample_count in iot_samples.items():
                reward = round((sample_count / total_samples) * iot_pool, 6)
                if reward > 0:
                    _distribute_ai_pool_to_address(
                        address=iot_address,
                        amount=reward,
                        category="iot_telemetry",
                        details={"samples_contributed": sample_count, "lookback_minutes": LOOKBACK_MINUTES}
                    )
            logger.info(f"[AI_POOL] Distributed {iot_pool} THR to {len(iot_samples)} IoT miners")
        else:
            logger.info(f"[AI_POOL] No IoT telemetry found in last {LOOKBACK_MINUTES} minutes")

        logger.info(f"[AI_POOL] Distribution complete. Remaining balance: {get_ai_pool_state().get('ai_pool_balance', 0)} THR")

    except Exception as e:
        logger.error(f"[AI_POOL] Distribution error: {e}", exc_info=True)


