@app.route("/api/v1/balance/<thr_addr>", methods=["GET"])
def api_v1_balance(thr_addr: str):
    """Return the current THR balance and all token balances for the given address."""
    ledger = load_json(LEDGER_FILE, {})
    wbtc_ledger = load_json(WBTC_LEDGER_FILE, {})
    token_balances = load_token_balances()

    try:
        thr_bal = round(float(ledger.get(thr_addr, 0.0)), 6)
    except Exception:
        thr_bal = 0.0

    try:
        wbtc_bal = round(float(wbtc_ledger.get(thr_addr, 0.0)), 6)
    except Exception:
        wbtc_bal = 0.0

    # Get all custom token balances for this address
    tokens = {}
    for token_symbol, holders in token_balances.items():
        if thr_addr in holders:
            try:
                tokens[token_symbol] = round(float(holders[thr_addr]), 6)
            except Exception:
                tokens[token_symbol] = 0.0

    return jsonify(
        address=thr_addr,
        balance=thr_bal,  # Keep for backward compatibility
        balances={
            "THR": thr_bal,
            "WBTC": wbtc_bal,
            **tokens
        }
    ), 200


@app.route("/api/v1/address/<thr_addr>/history", methods=["GET"])
def api_v1_address_history(thr_addr: str):
    """Return the on‑chain transaction history for the specified address.

    Merges CHAIN_FILE and TX_LOG (persistent ledger) so that all transaction
    types are included: transfers, fiat gateway, pledges, swaps, IoT purchases,
    mining rewards, etc.  Raw block entries (entries with 'reward' but no tx_id)
    are excluded — callers should use /api/v1/block/<height> for those.
    """
    chain = load_json(CHAIN_FILE, [])
    tx_log = load_tx_log()

    addr_lower = thr_addr.lower()

    def _matches(tx: dict) -> bool:
        if not isinstance(tx, dict):
            return False
        # Skip raw block entries (they have reward but no tx_id)
        if tx.get("reward") is not None and not tx.get("tx_id"):
            return False
        if tx.get("kind") == "block":
            return False
        tx_meta = tx.get("meta") if isinstance(tx.get("meta"), dict) else {}
        parties = {
            tx.get("from"), tx.get("to"),
            tx.get("thr_address"), tx.get("wallet"),
            tx.get("wallet_address"), tx.get("address"),
            tx_meta.get("wallet"), tx_meta.get("thr_address"),
        }
        return addr_lower in {str(p).lower() for p in parties if p}

    seen: set = set()
    deduped = []

    for tx in list(chain) + list(tx_log):
        if not _matches(tx):
            continue
        tx_id = tx.get("tx_id") or tx.get("id")
        if tx_id:
            if tx_id in seen:
                continue
            seen.add(tx_id)
        else:
            key = (
                tx.get("kind") or tx.get("type"),
                tx.get("timestamp"),
                tx.get("from"),
                tx.get("to"),
                tx.get("amount"),
            )
            if key in seen:
                continue
            seen.add(key)
        deduped.append(tx)

    # Sort newest first
    deduped.sort(key=lambda t: _parse_timestamp(t.get("timestamp", "")), reverse=True)

    return jsonify(address=thr_addr, transactions=deduped), 200


@app.route("/api/v1/block/<int:height>", methods=["GET"])
def api_v1_block_by_height(height: int):
    """Fetch a block by its height (1‑based, includes HEIGHT_OFFSET).  If
    ``height`` is outside the current chain range, respond with a 404."""
    chain = load_json(CHAIN_FILE, [])
    blocks = [b for b in chain if isinstance(b, dict) and b.get("reward") is not None]
    idx = height - HEIGHT_OFFSET
    if idx < 0 or idx >= len(blocks):
        return jsonify(error="block_not_found", height=height), 404
    block = blocks[idx].copy()

    # Recalculate reward with current 80/10/5/5 split (same logic as viewer)
    try:
        scheduled_reward = calculate_reward(int(height))
    except Exception:
        scheduled_reward = 8.0

    stored_reward = float(block.get("reward", 0.0) or 0.0)
    rsplit = block.get("reward_split") or {}
    stored_split_total = (
        float(rsplit.get("miner", 0.0))
        + float(rsplit.get("ai", 0.0))
        + float(rsplit.get("burn", 0.0))
        + float(rsplit.get("full_nodes", 0.0))
        + float(rsplit.get("ecosystem", 0.0))
    ) if rsplit else 0.0

    # Trust stored values only if they match current schedule; otherwise regenerate
    if rsplit and abs(stored_split_total - scheduled_reward) < 0.001:
        total_reward = stored_split_total
        block["reward"] = total_reward
    elif stored_reward > 0 and abs(stored_reward - scheduled_reward) < 0.001:
        total_reward = stored_reward
        block["reward"] = total_reward
    else:
        # Pre-upgrade or corrupt block — render with current schedule
        block["reward"] = scheduled_reward
        rsplit = {}

    # Ensure correct 80/10/5/5 split for display
    if not rsplit or abs(stored_split_total - scheduled_reward) >= 0.001:
        block["reward_split"] = {
            "miner": scheduled_reward * 0.80,
            "ai": scheduled_reward * 0.10,
            "full_nodes": scheduled_reward * 0.05,
            "ecosystem": scheduled_reward * 0.05,
        }

    return jsonify(block=block, height=height), 200


@app.route("/api/v1/blockhash/<string:block_hash>", methods=["GET"])
def api_v1_block_by_hash(block_hash: str):
    """Fetch a block by its hash.  Returns 404 if no matching block is
    found."""
    chain = load_json(CHAIN_FILE, [])
