def _get_fallback_models():
    """Return minimal curated model list for degraded mode."""
    try:
        from ai_models_config import CURATED_MODELS
        fallback = []
        for provider, data in CURATED_MODELS.items():
            for model in data.get("models", []):
                fallback.append({
                    "id": model["id"],
                    "provider": provider,
                    "label": model.get("label", model["id"]),
                    "display_name": model.get("label", model["id"]),
                    "enabled": False,  # Mark as disabled in degraded mode
                    "degraded": True,
                    "tier": "fallback",
                    "default": model.get("default", False),
                    "stats": {"total_calls": 0, "avg_latency_ms": 0.0}
                })
        return fallback
    except Exception as e:
        app.logger.error(f"Failed to load fallback models: {e}")
        return [{
            "id": "auto",
            "provider": "thronos",
            "label": "AUTO (Emergency Fallback)",
            "display_name": "AUTO (Emergency Fallback)",
            "enabled": True,
            "degraded": True,
            "tier": "emergency",
            "default": True,
            "stats": {"total_calls": 0, "avg_latency_ms": 0.0}
        }]


@app.route("/api/ai_models", methods=["GET"])
def api_ai_models():

    """
    Επιστρέφει ενοποιημένη λίστα μοντέλων για το Thronos Quantum UI.
    Χρησιμοποιεί το AI_MODEL_REGISTRY και τα stats από το AI Interaction Ledger.
    Δεν σκάει αν κάποιος provider δεν έχει API key – απλά τον μαρκάρει ως disabled.
    NEVER returns 500 - always returns 200 with degraded mode fallback if needed.
    """
    # ─── Proxy mode: ai-core forwards model catalog to leader/master ───
    if _is_proxy_mode_enabled():
        base_url = _ai_proxy_base_url()
        if base_url:
            target = base_url.rstrip("/") + "/api/ai_models"
            try:
                resp = requests.get(target, params={k: v for k, v in request.args.items()}, timeout=30)
                logger.info("[AI_PROXY] Forwarding %s to %s (mode=%s)", "/api/ai_models", base_url, THRONOS_AI_MODE)
                return Response(resp.content, status=resp.status_code, mimetype="application/json")
            except Exception as exc:
                logger.error("[AI_PROXY] upstream %s unreachable: %s", target, exc)
                return jsonify({
                    "models": [{"id": "auto", "label": "Auto (Thronos chooses)", "provider": "system", "enabled": True, "degraded": True}],
                    "default_model_id": "auto",
                    "error": "upstream_unreachable",
                    "message": "Quantum core cannot reach leader node right now.",
                }), 502

    # ─── Local AI handling (fallback or when is_ai_core) ───
    try:
        _apply_env_flags(get_provider_status())
        models = _build_ai_model_catalog()
        for m in models:
            m.setdefault("label", m.get("display_name") or m.get("id"))

        payload = {
            "models": models,
            "default_model_id": _default_model_id() or "auto",
            "engine": "d3lfoi",
            "mode": "core",
            "node_role": NODE_ROLE,
        }
        return jsonify(payload), 200

    except Exception as exc:
        app.logger.exception("api_ai_models catastrophic error")
        fallback_models = [
            {"id": m.get("id"), "label": m.get("label"), "provider": m.get("provider"), "enabled": True}
            for m in _get_fallback_models()
        ]
        return (
            jsonify(
                {
                    "models": fallback_models or [{"id": "auto", "label": "Auto (Thronos chooses)", "provider": "system", "enabled": True}],
                    "default_model_id": fallback_models[0]["id"] if fallback_models else "auto",
                    "error_code": "CATASTROPHIC_FAILURE",
                    "error_message": str(exc),
                }
            ),
            200,
        )


