@app.route("/api/t2e/submit", methods=["POST"])
def api_t2e_submit():
    data = request.get_json(silent=True) or {}
    wallet = (data.get("wallet") or "").strip()
    session_id = (data.get("session_id") or "").strip()
    if not wallet:
        return jsonify({"ok": False, "error": "wallet required"}), 400
    if not session_id and not data.get("diff") and not data.get("metadata"):
        return jsonify({"ok": False, "error": "training contribution required"}), 400

    event_id = (data.get("event_id") or data.get("request_id") or f"t2e-{int(time.time()*1000)}-{secrets.token_hex(4)}").strip()
    events = load_json(AI_T2E_EVENTS_FILE, {})
    if not isinstance(events, dict):
        events = {}

    if event_id in events:
        ev = events[event_id]
        return jsonify({"ok": True, "idempotent": True, "event_id": event_id, "session_id": ev.get("session_id"), "session_type": "train", "credits_delta": ev.get("credits_delta", 0)}), 200

    session = _session_by_id(session_id) if session_id else None
    if not session:
        session = _create_session_record(session_type="train", wallet=wallet, session_id=session_id or None)
        session_id = session.get("id")

    if (session.get("session_type") or "train") != "train":
        return jsonify({"ok": False, "error": "session_type_mismatch", "expected": "train", "found": session.get("session_type")}), 409

    before = get_ai_credits(wallet)
    delta = int(data.get("credits_delta") or 5)
    after = add_ai_credits(wallet, delta, reason="t2e_reward", metadata={"event_id": event_id, "session_id": session_id})

    event = {
        "event_id": event_id,
        "wallet": wallet,
        "session_id": session_id,
        "session_type": "train",
        "product": "train",
        "direction": "credit",
        "reference_id": event_id,
        "credits_delta": delta,
        "created_at": datetime.utcnow().isoformat(timespec="seconds") + "Z",
        "status": "credited",
    }
    events[event_id] = event
    save_json(AI_T2E_EVENTS_FILE, events)

    try:
        record_ai_interaction(
            session_id=session_id or None,
            user_wallet=wallet,
            provider="thronos",
            model="t2e-attestor",
            prompt="t2e_submit",
            output="accepted",
            tokens_input=0,
            tokens_output=0,
            cost_usd=0.0,
            latency_ms=0,
            ai_credits_spent=0.0,
            metadata=event,
            success=True,
        )
    except Exception:
        app.logger.exception("t2e_submit_record_failed")

    return jsonify({"ok": True, "event_id": event_id, "session_id": session_id, "session_type": "train", "credits_before": before, "credits_delta": delta, "credits_after": after}), 200


@app.route("/api/ai/health", methods=["GET"])
def api_ai_health():
    if _is_proxy_mode_enabled():
        global AI_PROXY_HEALTH_LAST_LOG_TS
        now_ts = time.time()
        cached = AI_PROXY_HEALTH_CACHE.get("payload")
        cache_age = now_ts - float(AI_PROXY_HEALTH_CACHE.get("ts", 0) or 0)
        if cached and cache_age < AI_PROXY_HEALTH_CACHE_TTL:
            return jsonify(cached), 200

        base_url = _ai_proxy_base_url()
        if base_url:
            target = base_url.rstrip("/") + "/api/ai/health"
            logger.info("[AI_PROXY] Forwarding %s to %s (mode=%s)", "/api/ai/health", base_url, THRONOS_AI_MODE)
            try:
                resp = requests.get(target, timeout=5)
                data = resp.json() if resp.headers.get("content-type", "").startswith("application/json") else {}
                data = data if isinstance(data, dict) else {}
                data.setdefault("ok", True)
                data["node_role"] = "ai_core"
                data["thronos_ai_mode"] = "proxy"
                data.setdefault("offline_corpus", {
                    "enabled": False,
                    "degraded": True,
                    "path": AI_CORPUS_FILE,
                    "reason": "proxy_node",
                })
                data.setdefault("thrai", {
                    "enabled": False,
                    "degraded": True,
                    "router_url": (DIKO_MAS_MODEL_URL or "").strip(),
                    "reason": "proxy_node",
                })
                AI_PROXY_HEALTH_CACHE["ts"] = now_ts
                AI_PROXY_HEALTH_CACHE["payload"] = data
                return jsonify(data), resp.status_code
            except Exception as exc:
                if (now_ts - AI_PROXY_HEALTH_LAST_LOG_TS) >= AI_PROXY_HEALTH_LOG_COOLDOWN:
                    logger.error("[AI_PROXY] upstream %s unreachable: %s", target, exc)
                    AI_PROXY_HEALTH_LAST_LOG_TS = now_ts

        payload = {
            "ok": True,
            "node_role": "ai_core",
            "thronos_ai_mode": "proxy",
            "enabled_model_ids": [],
            "provider_status": {},
            "offline_corpus": {
                "enabled": False,
                "degraded": True,
                "path": AI_CORPUS_FILE,
                "reason": "proxy_node",
            },
            "thrai": {
                "enabled": False,
                "degraded": True,
                "router_url": (DIKO_MAS_MODEL_URL or "").strip(),
                "reason": "proxy_node",
            }
        }
        AI_PROXY_HEALTH_CACHE["ts"] = now_ts
        AI_PROXY_HEALTH_CACHE["payload"] = payload
        return jsonify(payload), 200

    try:
        catalog = _build_ai_model_catalog()
        enabled_ids = [m.get("id") for m in catalog if m.get("enabled")]
    except Exception:
        catalog = []
        enabled_ids = []

    offline_ok, offline_reason = _offline_corpus_health()
    thrai_ok, thrai_reason = _thrai_router_health()
    provider_status = get_provider_status()
    providers_block = {}
    for pname in ("openai", "anthropic", "gemini"):
        info = provider_status.get(pname, {}) if isinstance(provider_status, dict) else {}
        providers_block[pname] = {
            "enabled": bool(info.get("configured") and info.get("library_loaded", True) is not False),
            "degraded": bool(not info.get("configured") or info.get("library_loaded", True) is False),
            "reason": info.get("last_error") or (None if info.get("configured") else "missing_api_key"),
        }

    payload = {
        "ok": True,
        "node_role": NODE_ROLE,
        "thronos_ai_mode": os.getenv("THRONOS_AI_MODE", "all"),
        "mode": "core",
        "engine": "d3lfoi",
        "enabled_model_ids": enabled_ids,
        "models": catalog,
        "providers": providers_block,
        "offline_corpus": {
            "enabled": bool(THR_OFFLINE_CORPUS_ENABLED and offline_ok),
            "degraded": False if not THR_OFFLINE_CORPUS_ENABLED else (not offline_ok),
            "health_ok": bool(offline_ok),
            "path": AI_CORPUS_FILE,
            "reason": offline_reason,
        },
        "thrai": {
            "enabled": bool(THR_THAI_ENABLED and thrai_ok),
            "degraded": bool(THR_THAI_ENABLED and not thrai_ok),
            "health_ok": bool(thrai_ok),
            "router_url": (DIKO_MAS_MODEL_URL or "").strip(),
            "reason": thrai_reason,
        },
        "provider_status": provider_status,
        "model_snapshot": _load_model_catalog_snapshot(),
        "pytheia": (lambda: (lambda st: {"status": "ok" if st else "unknown", "last_run": st.get("last_update") if isinstance(st, dict) else None, "last_error": None})(load_json(os.getenv("PYTHEIA_STATE_FILE", os.path.join(DATA_DIR, "pytheia_state.json")), {})))(),
    }
    return jsonify(payload), 200


