NFT_REGISTRY_FILE = os.path.join(DATA_DIR, "nft_registry.json")

def load_nft_registry():
    return load_json(NFT_REGISTRY_FILE, {"nfts": [], "collections": {}})

def save_nft_registry(registry):
    save_json(NFT_REGISTRY_FILE, registry)


@app.route("/api/v1/nfts", methods=["GET"])
def api_v1_nfts():
    """Get all NFTs"""
    if READ_ONLY and not MASTER_INTERNAL_URL.startswith("http://localhost"):
        try:
            response = requests.get(f"{MASTER_INTERNAL_URL}/api/v1/nfts", timeout=2)
            if response.ok:
                data = response.json()
                nfts = data.get("nfts", [])
                for nft in nfts:
                    nft["image_url"] = normalize_media_url(nft.get("image_url") or nft.get("image"))
                return jsonify({"status": "success", "nfts": nfts}), 200
        except Exception as exc:
            logger.warning("[NFT] Failed to fetch from master: %s", exc)

    registry = load_nft_registry()
    nfts = registry.get("nfts", [])
    for nft in nfts:
        nft["image_url"] = normalize_media_url(nft.get("image_url") or nft.get("image"))
    return jsonify({"status": "success", "nfts": nfts}), 200


NFT_MINT_FEE = float(_strip_env_quotes(os.getenv("NFT_MINT_FEE", "1.0")))  # 1 THR mint fee


@app.route("/api/v1/nfts/mint", methods=["POST"])
def api_v1_nfts_mint():
    """Mint a new NFT with network fee, auth validation, and chain recording."""
    name = request.form.get("name", "").strip()
    description = request.form.get("description", "").strip()
    category = request.form.get("category", "art")
    price = float(request.form.get("price", 0))
    royalties = int(request.form.get("royalties", 10))
    creator = request.form.get("creator", "").strip()
    auth_secret = request.form.get("auth_secret", "").strip()
    passphrase = request.form.get("passphrase", "").strip()

    if not name or not creator:
        return jsonify({"status": "error", "message": "Name and creator required"}), 400

    # --- Auth validation ---
    ok, _, error_key = validate_effective_auth(creator, auth_secret, passphrase)
    if not ok:
        error_msgs = {
            "no_effective_pledge": "No effective pledge access",
            "missing_auth_secret": "Auth secret required",
            "missing_pledge": "Wallet has not pledged",
            "send_not_enabled": "Send not enabled for this wallet",
            "passphrase_required": "Passphrase required",
            "invalid_auth": "Invalid auth",
        }
        return jsonify({"status": "error", "message": error_msgs.get(error_key, "Auth failed")}), 403

    # --- Check THR balance for mint fee ---
    mint_fee = NFT_MINT_FEE
    ledger = load_json(LEDGER_FILE, {})
    user_balance = float(ledger.get(creator, 0.0))
    if user_balance < mint_fee:
        return jsonify({
            "status": "error",
            "message": f"Insufficient THR. Mint fee: {mint_fee} THR, Balance: {user_balance:.6f} THR"
        }), 402

    # Handle image upload
    image_url = None
    nft_id = f"NFT{int(time.time() * 1000)}"
    if "image" in request.files:
        file = request.files["image"]
        if file and file.filename:
            ext = file.filename.rsplit(".", 1)[-1].lower()
            if ext in ("png", "jpg", "jpeg", "gif", "webp"):
                filename = f"{nft_id}.{ext}"
                upload_dir = NFT_IMAGES_DIR
                os.makedirs(upload_dir, exist_ok=True)
                file.save(os.path.join(upload_dir, filename))
                image_url = f"/media/nft_images/{filename}"

    # --- Deduct mint fee from creator ---
    ledger[creator] = round(user_balance - mint_fee, 6)
    # Fee is burned (sent to network)
    network_wallet = os.getenv("NETWORK_FEE_WALLET", "THR_NETWORK_FEES_00001")
    network_balance = float(ledger.get(network_wallet, 0.0))
    ledger[network_wallet] = round(network_balance + mint_fee, 6)
    save_json(LEDGER_FILE, ledger)

    # Create NFT
    timestamp = time.strftime("%Y-%m-%d %H:%M:%S UTC", time.gmtime())
    nft = {
        "id": nft_id,
        "name": name,
        "description": description,
        "category": category,
        "price": price,
        "royalties": royalties,
        "creator": creator,
        "owner": creator,
        "image_url": image_url,
        "created_at": timestamp,
        "for_sale": True,
        "mint_fee": mint_fee,
    }

    registry = load_nft_registry()
    registry["nfts"].append(nft)
    save_nft_registry(registry)

    # --- Record on chain ---
    chain = load_json(CHAIN_FILE, [])
    tx = {
        "type": "nft_mint",
        "category": "nft_mint",
        "from": creator,
        "to": network_wallet,
        "amount": mint_fee,
        "fee": mint_fee,
        "fee_burned": mint_fee,
        "symbol": "THR",
        "token_symbol": "THR",
        "asset_symbol": "THR",
        "nft_id": nft_id,
        "nft_name": name,
        "timestamp": timestamp,
        "status": "confirmed",
    }
    chain.append(tx)
    save_json(CHAIN_FILE, chain)
    update_last_block(tx, is_block=False)

    logger.info(f"NFT Mint: {creator} → {nft_id} '{name}' | Fee: {mint_fee} THR")

    nft["image_url"] = normalize_media_url(nft.get("image_url") or nft.get("image"))
    return jsonify({
        "status": "success",
        "nft": nft,
        "mint_fee": mint_fee,
        "new_balance": ledger.get(creator, 0.0),
    }), 201


@app.route("/api/nfts/buy", methods=["POST"])
@app.route("/api/v1/nfts/buy", methods=["POST"])
def api_v1_nfts_buy():
    """Buy an NFT with THR payment, chain recording, and royalties."""
    data = request.get_json() or {}
    nft_id = data.get("nft_id", "").strip()
    buyer = (data.get("buyer_thr") or data.get("buyer") or "").strip()
    credential_lookup_address = (data.get("credential_lookup_address") or buyer).strip()
    auth_secret = data.get("auth_secret", "").strip()
    passphrase = data.get("passphrase", "").strip()
    signed_tx = data.get("signed_tx") if isinstance(data.get("signed_tx"), dict) else None

    if not nft_id or not buyer:
        return jsonify({"status": "error", "message": "Missing required fields"}), 400

    if signed_tx:
        signed_tx = dict(signed_tx)
        if data.get("public_key") and not signed_tx.get("publicKey"):
            signed_tx["publicKey"] = data.get("public_key")
        if data.get("signature") and not signed_tx.get("signature"):
            signed_tx["signature"] = data.get("signature")
        try:
            import wallet_v1_production_final as wallet_v1_prod
            valid_sig, sig_error = wallet_v1_prod.verify_signed_transaction_core(signed_tx)
        except Exception as exc:
            valid_sig, sig_error = False, str(exc)
        if not valid_sig:
            return jsonify({"status": "error", "message": "Invalid signature", "error": sig_error}), 400

    # --- Auth validation ---
    ok, _, error_key = validate_effective_auth(credential_lookup_address, auth_secret, passphrase)
    if not ok:
        return jsonify({"status": "error", "message": "Invalid auth", "error": error_key}), 403

    registry = load_nft_registry()
    nft = next((n for n in registry["nfts"] if n["id"] == nft_id), None)

    if not nft:
        return jsonify({"status": "error", "message": "NFT not found"}), 404

    if not nft.get("for_sale"):
        return jsonify({"status": "error", "message": "NFT not for sale"}), 400

    if nft["owner"] == buyer:
        return jsonify({"status": "error", "message": "You already own this NFT"}), 400

    price = float(nft.get("price", 0))
    if price <= 0:
        return jsonify({"status": "error", "message": "NFT has no price set"}), 400

    # --- Check buyer balance ---
    ledger = load_json(LEDGER_FILE, {})
    buyer_balance = float(ledger.get(buyer, 0.0))
    if buyer_balance < price:
        return jsonify({
            "status": "error",
            "message": f"Insufficient THR. Price: {price} THR, Balance: {buyer_balance:.6f} THR"
        }), 402

    # --- Calculate royalties ---
    royalty_pct = min(50, max(0, int(nft.get("royalties", 10)))) / 100.0
    royalty_amount = round(price * royalty_pct, 6)
    seller_amount = round(price - royalty_amount, 6)
    old_owner = nft["owner"]
    creator_addr = nft.get("creator", old_owner)

    # --- Transfer THR ---
    ledger[buyer] = round(buyer_balance - price, 6)
    # Seller gets price minus royalties
    seller_balance = float(ledger.get(old_owner, 0.0))
    ledger[old_owner] = round(seller_balance + seller_amount, 6)
    # Creator gets royalties (if different from seller)
    if creator_addr != old_owner and royalty_amount > 0:
        creator_balance = float(ledger.get(creator_addr, 0.0))
        ledger[creator_addr] = round(creator_balance + royalty_amount, 6)
    elif royalty_amount > 0:
        # Creator is seller, they get the full amount
        ledger[old_owner] = round(float(ledger.get(old_owner, 0.0)) + royalty_amount, 6)
    save_json(LEDGER_FILE, ledger)

    # --- Transfer ownership ---
    nft["owner"] = buyer
    nft["for_sale"] = False
    save_nft_registry(registry)

    # --- Record on chain ---
    timestamp = time.strftime("%Y-%m-%d %H:%M:%S UTC", time.gmtime())
    chain = load_json(CHAIN_FILE, [])
    tx = {
        "type": "nft_buy",
        "category": "nft_buy",
        "from": buyer,
        "to": old_owner,
        "amount": price,
        "fee": 0.0,
        "symbol": "THR",
        "token_symbol": "THR",
        "asset_symbol": "THR",
        "nft_id": nft_id,
        "nft_name": nft.get("name", ""),
        "royalty_amount": royalty_amount,
        "royalty_to": creator_addr,
        "timestamp": timestamp,
        "status": "confirmed",
    }
    chain.append(tx)
    save_json(CHAIN_FILE, chain)
    update_last_block(tx, is_block=False)

    logger.info(f"NFT Buy: {buyer} → {old_owner} | {price} THR for '{nft.get('name')}' | Royalty: {royalty_amount} THR → {creator_addr}")

    return jsonify({
        "status": "success",
        "message": f"NFT purchased for {price} THR",
        "nft": nft,
        "price": price,
        "royalty": royalty_amount,
        "new_balance": ledger.get(buyer, 0.0),
    }), 200


@app.route("/api/nft/burn", methods=["POST"])
@app.route("/api/v1/nft/burn", methods=["POST"])
def api_nft_burn():
    """
    Burn an NFT (mark as burned and remove from marketplace).

    Request body:
    {
        "nft_id": "NFT...",
        "owner": "THR...",
        "auth_secret": "..."
    }

    Effect:
    - Mark burned=true
    - Remove from marketplace (for_sale=false)
    - Write event kind=nft_burn to history
    """
    data = request.get_json() or {}
    nft_id = data.get("nft_id", "").strip()
    owner = data.get("owner", "").strip()
    auth_secret = data.get("auth_secret", "").strip()

    if not nft_id or not owner:
        return jsonify({"ok": False, "error": "Missing nft_id or owner"}), 400

    # Validate owner address
    if not validate_thr_address(owner):
        return jsonify({"ok": False, "error": "Invalid owner address"}), 400

    # Authenticate owner (basic check with auth_secret)
    if not auth_secret:
        return jsonify({"ok": False, "error": "auth_secret required"}), 400

    # Load NFT registry
    registry = load_nft_registry()
    nft = next((n for n in registry["nfts"] if n["id"] == nft_id), None)

    if not nft:
        return jsonify({"ok": False, "error": "NFT not found"}), 404

    # Verify ownership
    if nft.get("owner") != owner:
        return jsonify({"ok": False, "error": "You do not own this NFT"}), 403

    # Check if already burned
    if nft.get("burned"):
        return jsonify({"ok": False, "error": "NFT already burned"}), 400

    # Mark NFT as burned and remove from marketplace
    nft["burned"] = True
    nft["for_sale"] = False
    nft["burned_at"] = time.strftime("%Y-%m-%d %H:%M:%S UTC", time.gmtime())
    nft["burned_by"] = owner

    # Save updated registry
    save_nft_registry(registry)

    # Write burn event to history (for tx feed)
    try:
        burn_event = {
            "tx_id": f"NFTBURN{int(time.time() * 1000)}",
            "type": "nft_burn",
            "kind": "nft_burn",
            "from": owner,
            "to": BURN_ADDRESS,
            "nft_id": nft_id,
            "nft_name": nft.get("name", ""),
            "timestamp": time.time(),
            "note": f"NFT burned: {nft.get('name', nft_id)}"
        }

        # Index the event if DB is available
        if USE_SQLITE_LEDGER:
            _index_block_event(
                event_type="nft_burn",
                event_id=burn_event["tx_id"],
                height=0,  # Not blockchain-verified
                timestamp=burn_event["timestamp"],
                from_address=owner,
                to_address=BURN_ADDRESS,
                amount=0,
                asset_symbol="NFT",
                metadata={"nft_id": nft_id, "nft_name": nft.get("name", "")}
            )
    except Exception as e:
        logger.warning(f"Failed to index NFT burn event: {e}")

    return jsonify({
        "ok": True,
        "message": f"NFT {nft.get('name', nft_id)} has been burned",
        "nft": {
            "id": nft["id"],
            "name": nft.get("name"),
            "burned": True,
            "burned_at": nft.get("burned_at"),
            "burned_by": owner
        }
    }), 200


