@app.route("/schemas/pytheia-advice.schema.json")
def serve_pytheia_schema():
    """Serve PYTHEIA Advice JSON Schema"""
    schema_path = os.path.join(os.path.dirname(__file__), "schemas", "pytheia-advice.schema.json")
    if not os.path.exists(schema_path):
        return jsonify({"status": "error", "message": "Schema file not found"}), 404
    return send_file(schema_path, mimetype="application/schema+json")


@app.route("/api/governance/pytheia/advice", methods=["POST"])
def api_pytheia_advice():
    """
    Ingest PYTHEIA AI Node audit advice.
    Validates against pytheia-advice.schema.json and stores as special governance post.
    Returns: {"status": "success", "post_id": "...", "url": "..."}
    """
    data = request.get_json() or {}

    # Basic validation - check required fields per schema
    required = ["schema_version", "timestamp", "auditor", "repo", "commit",
                "title", "severity", "priorities", "options", "patch_plan"]
    missing = [f for f in required if f not in data]
    if missing:
        return jsonify({
            "status": "error",
            "message": f"Missing required fields: {', '.join(missing)}"
        }), 400

    # Validate schema_version
    if data.get("schema_version") != "PYTHEIA Advice v1.0.0":
        return jsonify({
            "status": "error",
            "message": "Invalid schema_version. Expected 'PYTHEIA Advice v1.0.0'"
        }), 400

    # Validate severity
    valid_severities = ["BLOCKER", "MAJOR", "MINOR", "INFO"]
    if data.get("severity") not in valid_severities:
        return jsonify({
            "status": "error",
            "message": f"Invalid severity. Must be one of: {', '.join(valid_severities)}"
        }), 400

    # Validate priorities array
    priorities = data.get("priorities", [])
    if not isinstance(priorities, list) or len(priorities) < 1 or len(priorities) > 20:
        return jsonify({
            "status": "error",
            "message": "priorities must be an array with 1-20 items"
        }), 400

    # Validate options array
    options = data.get("options", [])
    if not isinstance(options, list) or len(options) < 1 or len(options) > 5:
        return jsonify({
            "status": "error",
            "message": "options must be an array with 1-5 items"
        }), 400

    # Create governance post
    post_id = f"PYTHEIA{int(time.time() * 1000)}"

    # Build governance proposal from PYTHEIA advice
    proposal = {
        "id": post_id,
        "type": "PYTHEIA_ADVICE",  # Special type for rendering
        "title": data.get("title"),
        "description": f"Audit by {data.get('auditor')} - Severity: {data.get('severity')}",
        "category": "protocol",  # PYTHEIA advice is always protocol-related
        "status": "active" if data.get("requires_approval", True) else "info",
        "votes_for": 0,
        "votes_against": 0,
        "creator": data.get("auditor", "PYTHEIA AI Node"),
        "created_at": time.strftime("%Y-%m-%d", time.gmtime()),
        "ends_at": time.strftime("%Y-%m-%d", time.gmtime(time.time() + 7 * 86400)),  # 7 days
        # Store full PYTHEIA data
        "pytheia_data": data
    }

    # Save to governance
    gov = load_governance()
    gov["proposals"].append(proposal)
    save_governance(gov)

    # Generate URL
    governance_url = data.get("governance_url") or "https://thrchain.up.railway.app/governance"

    return jsonify({
        "status": "success",
        "post_id": post_id,
        "url": governance_url,
        "message": "PYTHEIA advice posted to governance successfully"
    }), 201


# ─── Phase 4: IoT, AI Pool & Governance APIs ────────────────────────────────────

@app.route("/api/iot/telemetry", methods=["POST"])
def api_iot_telemetry():
    """
    Submit IoT telemetry data for GPS mining rewards.

    Users earn THR for contributing route data that trains the autopilot.
    Reward formula: 0.001 THR per 10 GPS samples (route points).

    Expected JSON:
    {
      "address": "THR...",
      "device_id": "optional_device_identifier",
      "route_hash": "hash_of_gps_path",
      "samples": <int>,        # Number of GPS data points
      "music_session": "...",  # Optional: linked music session for trip
      "auth_secret": "..."     # Optional: for authentication
    }
    """
    data = request.get_json() or {}
    address = (data.get("address") or "").strip()
    device_id = (data.get("device_id") or "").strip()
    route_hash = (data.get("route_hash") or "").strip()
    samples = int(data.get("samples", 0))
    music_session = (data.get("music_session") or "").strip()

    if not address or not route_hash or samples <= 0:
        return jsonify({"ok": False, "error": "Missing required fields: address, route_hash, samples"}), 400

    # Verify address exists in ledger or pledges
    ledger = load_json(LEDGER_FILE, {})
    pledges = load_json(PLEDGE_CHAIN, [])

    address_exists = address in ledger or any(p.get("thr_address") == address for p in pledges)
    if not address_exists:
        return jsonify({"ok": False, "error": "Address not found in system"}), 404

    # Calculate GPS mining reward: 0.001 THR per 10 samples (min 10 samples)
    # This incentivizes users to contribute route data for autopilot training
    GPS_REWARD_PER_10_SAMPLES = 0.001
    reward_thr = round((samples // 10) * GPS_REWARD_PER_10_SAMPLES, 6) if samples >= 10 else 0.0

    # Create IoT telemetry transaction
    chain = load_json(CHAIN_FILE, [])
    ts = time.strftime("%Y-%m-%d %H:%M:%S UTC", time.gmtime())
    tx_id = f"IOT-TELEM-{int(time.time())}-{secrets.token_hex(4)}"

    tx = {
        "type": "iot_telemetry",
        "address": address,
        "device_id": device_id,
        "route_hash": route_hash,
        "samples": samples,
        "music_session": music_session if music_session else None,
        "timestamp": ts,
        "tx_id": tx_id,
        "status": "confirmed"
    }
    chain.append(tx)

    # If reward earned, credit THR and log mining transaction
    if reward_thr > 0:
        # Credit THR to user (from AI pool)
        ai_balance = float(ledger.get(AI_WALLET_ADDRESS, 0.0))
        if ai_balance >= reward_thr:
            ledger[AI_WALLET_ADDRESS] = round(ai_balance - reward_thr, 6)
            ledger[address] = round(float(ledger.get(address, 0.0)) + reward_thr, 6)

            # Log GPS mining reward transaction
            reward_tx = {
                "type": "gps_mining",
                "from": AI_WALLET_ADDRESS,
                "to": address,
                "amount": reward_thr,
                "samples": samples,
                "route_hash": route_hash,
                "music_session": music_session if music_session else None,
                "timestamp": ts,
                "tx_id": f"GPS-MINE-{int(time.time())}-{secrets.token_hex(4)}",
                "note": f"GPS route contribution: {samples} samples → autopilot training"
            }
            chain.append(reward_tx)
            tx["reward_thr"] = reward_thr
            tx["reward_tx_id"] = reward_tx["tx_id"]

    save_json(CHAIN_FILE, chain)
    save_json(LEDGER_FILE, ledger)

    logger.info(f"📍 GPS Mining: {address} - {samples} samples → {reward_thr} THR (route: {route_hash[:16]}...)")

    return jsonify({
        "ok": True,
        "tx_id": tx_id,
        "samples": samples,
        "reward_thr": reward_thr,
        "message": f"Telemetry recorded: {samples} samples" + (f", earned {reward_thr} THR" if reward_thr > 0 else "")
    }), 201


